import React from 'react'
import { IconButton } from '@fs/zion-ui'
import { PersonAdd } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { useHistory } from '@fs/zion-router'
import useChatLog from '../hooks/useChatLog'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'

export default function AddPersonButton({ channel }) {
  const { t } = useTranslation()
  const title = t('chat.add-people.label', 'Add Person to Chat')
  const history = useHistory()
  const { cid } = channel || {}
  const { track } = useChatLog({ component: '[AddPersonButton]' })

  return (
    <IconButton
      title={title}
      data-testid="add-person"
      Icon={PersonAdd}
      onClick={() => {
        track({ link_name: `Chat:Add Person:${channel?.type}` }, { chatChannelId: cid })
        history.push(buildChatRoute(CHAT_ROUTE_KEY.CHAT_DETAILS, { cid }))
      }}
    />
  )
}
