import React, { useMemo } from 'react'
import { Paragraph, Ellipsis, Separator } from '@fs/zion-ui'
import useMemoryCard from '../useMemoryCard'

export default function Description({ memory, dense }) {
  const { isPhotoStoryMemory, isTextStoryMemory } = useMemoryCard(memory)
  const { title, description } = memory

  const lineClamp = useMemo(() => {
    if (!isPhotoStoryMemory && dense) return 7
    if (isTextStoryMemory) return 10
    return 2
  }, [dense, isPhotoStoryMemory, isTextStoryMemory])

  return (
    // This needs to be a div, not a fragment, for growY on Description in MemoryCard.js to work
    <div>
      {(title || isPhotoStoryMemory) && <Separator size="nano" />}
      {description && (
        <Paragraph size={dense ? 'xs' : 'sm'}>
          <Ellipsis lineClamp={lineClamp} noTooltip>
            {description}
          </Ellipsis>
        </Paragraph>
      )}
    </div>
  )
}
