import debounce from 'lodash.debounce'
import chatLog, { LOG_LEVEL } from '../../global/chatLog'
import { MESSAGE_HISTORY_ACTIONS } from '../../hooks/useMessageHistoryReducer'
import { CHAT_ACTIONS } from '../../hooks/useChatReducer'
import { FS_THREAD_MESSAGE_PREFIX } from '../fsChat/fsChannelEnums'

const MESSAGE_PAGE_SIZE = 150

const hasMoreMessages = (lastNumberOfMessagesRead) => lastNumberOfMessagesRead >= MESSAGE_PAGE_SIZE

export const channelReadAfterMessage = ({ channel, message }) => {
  const channelLastRead = new Date(channel?.lastRead()).getTime()
  const messageLastRead = new Date(message?.updated_at).getTime()
  return messageLastRead && channelLastRead > messageLastRead
}

async function getStreamMessages({ channel, options }) {
  if (!channel) {
    throw new Error('getStreamMessages must have a channel!')
  }

  const result = await channel.query({ messages: options })

  return { channel, messages: result.messages }
}

export async function getMessages({ channel, oldestMessageId, newestMessageId, topVisibleMessageId }) {
  const limit = MESSAGE_PAGE_SIZE
  const options = { limit }
  if (
    (oldestMessageId && (topVisibleMessageId || newestMessageId)) ||
    (topVisibleMessageId && (oldestMessageId || newestMessageId)) ||
    (newestMessageId && (topVisibleMessageId || oldestMessageId))
  ) {
    throw new Error('Only one of oldestMessageId, newestMessageId or topVisibleMessageId messageIds can be provided!')
  }
  if (oldestMessageId) options.id_lt = oldestMessageId
  if (newestMessageId) options.id_gt = newestMessageId
  if (topVisibleMessageId) options.id_around = topVisibleMessageId

  const result = await getStreamMessages({ channel, options })
  const more = hasMoreMessages(result?.messages?.length)
  const moreUp = (!oldestMessageId && !(!oldestMessageId && !newestMessageId && !topVisibleMessageId)) || more
  const moreDown = (!topVisibleMessageId && !newestMessageId) || more
  // fixes a bug where we don't scroll down to the most recent message
  const isFreshQuery = !oldestMessageId && !newestMessageId && !topVisibleMessageId

  return { newMessages: result?.messages || [], moreUp, moreDown, isFreshQuery }
}

export async function getMessageHistoryMessages({
  channel,
  messageHistoryDispatch,
  oldestMessageId,
  newestMessageId,
  topVisibleMessageId,
  isRetry = false,
  getIsMounted = () => true,
}) {
  try {
    messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.SET_LOADING, loading: true })
    return await getMessages({
      channel,
      oldestMessageId,
      newestMessageId,
      topVisibleMessageId,
    })
  } catch (e) {
    // If we tried querying with topVisibleMessageId, this implies there were messages that a user previously saw.
    // Stream error code 4 (bad request) means that messageId might not exist anymore (deleted, re-imported, etc.), so re-query without the invalid ID.
    if (topVisibleMessageId && e.code === 4) {
      return getMessageHistoryMessages({
        channel,
        messageHistoryDispatch,
        oldestMessageId,
        newestMessageId,
        getIsMounted,
      })
    }

    if (e.code !== 4 && e.code !== 9) {
      chatLog({
        msg: `Error reading messages in useMessageHistory: event: ${e}`,
        level: LOG_LEVEL.ERROR,
        component: '[messageHistoryService]',
      })

      // Retry once before showing error
      if (!isRetry) {
        chatLog({
          msg: 'Retrying message fetch',
          level: LOG_LEVEL.INFO,
          component: '[messageHistoryService]',
        })
        // Brief delay to allow Stream to recover from transient issues
        await new Promise((resolve) => {
          setTimeout(resolve, 500)
        })
        // Bail out if the component unmounted during the delay
        if (!getIsMounted()) return { newMessages: [], moreUp: false, moreDown: false }
        return getMessageHistoryMessages({
          channel,
          messageHistoryDispatch,
          oldestMessageId,
          newestMessageId,
          topVisibleMessageId,
          isRetry: true,
          getIsMounted,
        })
      }

      if (getIsMounted()) messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.SET_ERROR })
      throw e
    }
  } finally {
    if (getIsMounted()) messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.SET_LOADING, loading: false })
  }
  return { newMessages: [], moreUp: false, moreDown: false }
}

function logStreamChannelEventHandler({ event, channel, pid, log }) {
  const { message, cid: eventCid = '', type } = event
  const eventString = `Channel Event "${type}" cid:${eventCid} pid:${pid || ''}`
  const { cid: channelId = '' } = channel || {}
  const channelString = channel ? `\n  channel <-- cid:${channelId} -->` : ''
  const { id: messageId = '', text = '', reply_count = 0 } = message || {}
  const messageString = message ? `\n  message <- id:${messageId} "${text}" reply_count=${reply_count} -->` : ''

  log({ msg: `${eventString}${channelString}${messageString}`, level: LOG_LEVEL.LOG })
}

const MAX_WAIT_TIME = 1000
const config = { maxWait: MAX_WAIT_TIME }
const debouncedMarkChannelRead = debounce(
  async (channel, handleBasicError) => {
    try {
      await channel.markRead()
    } catch (err) {
      handleBasicError(err, { moreInfo: `Error marking channel read. ChannelId: ${channel?.cid}` })
    }
  },
  MAX_WAIT_TIME,
  config
)

async function markChannelIfUnreadAndFocused({ channel, chatWindowIsFocused, handleBasicError, chatDispatch, track }) {
  if (channel?.countUnread?.() && chatWindowIsFocused) {
    track({ link_name: 'Chat:Mark Chat as Read' }, { chatChannelId: channel?.cid })
    chatDispatch({ type: CHAT_ACTIONS.MARK_READ })
    debouncedMarkChannelRead(channel, handleBasicError)
  }
}

export async function handleMessageEvent({
  event,
  channel,
  messageHistoryDispatch,
  chatDispatch,
  pid,
  chatWindowIsFocused,
  handleBasicError,
  log,
  track,
}) {
  logStreamChannelEventHandler({ event, channel, pid, log })

  switch (event.type) {
    case 'message.new':
      // will be marked read from Virtuoso rangeChanged
      if ((event?.message?.id || '').indexOf(FS_THREAD_MESSAGE_PREFIX) === -1) {
        messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.NEW_MESSAGE, event, chatWindowIsFocused })
      }
      break
    case 'message.updated':
      messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.MESSAGE_UPDATED, event })
      chatDispatch({ type: CHAT_ACTIONS.MESSAGE_UPDATED, event })
      await markChannelIfUnreadAndFocused({
        channel,
        chatWindowIsFocused,
        handleBasicError,
        chatDispatch,
        track,
        cisId: event?.user?.id,
      })
      break
    case 'message.deleted':
      // will be marked read from Virtuoso rangeChanged
      messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.MESSAGE_DELETED, event })
      chatDispatch({ type: CHAT_ACTIONS.MESSAGE_DELETED, event })
      break
    case 'reaction.new':
    case 'reaction.updated':
    case 'reaction.deleted':
      messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.MESSAGE_UPDATED, event })
      break
    default:
      log({ msg: `unhandled useMessageHistory: event: ${event}`, level: LOG_LEVEL.ERROR })
      break
  }
}

export async function markChannelRead({
  chatWindowIsFocused,
  channel,
  handleBasicError,
  messageHistoryDispatch,
  chatDispatch,
  track,
}) {
  await markChannelIfUnreadAndFocused({ channel, chatWindowIsFocused, handleBasicError, chatDispatch, track })
  if (chatWindowIsFocused) {
    messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.CLEAR_UNREAD_MESSAGES })
  }
}
