import { useTranslation } from 'react-i18next'
import { IconButton } from '@fs/zion-ui'
import { SocialSend, NoticeLoading } from '@fs/zion-icon'
import React from 'react'

export default function ChatActionsSendButton({ disabled, showSpinner }) {
  const [t] = useTranslation()
  return (
    <IconButton
      data-testid="send-message"
      type="submit"
      title={t('chat.send-message.action', 'Send Message')}
      Icon={showSpinner ? NoticeLoading : SocialSend}
      emphasis="low"
      disabled={disabled}
      size="md"
    />
  )
}
