import React, { useCallback, useMemo } from 'react'
import {
  Bleed,
  Button,
  DialogOverlayActions,
  DialogOverlayFooter,
  MarginBox,
  Paragraph,
  Row,
  useContainerWidth,
} from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { miscUtils } from './utils'
import { usePickerDialog } from './hooks'

const PickerDialogFooter = ({
  actionText,
  confirmationCallback,
  secondaryActionText,
  secondaryActionCallback,
  idSelectionStates,
  maxSelectable,
  cancelOnClick,
  overlay,
  noOverlay,
}) => {
  const [t] = useTranslation()
  const atWidth = useContainerWidth()
  const { disableImportButton, selectedIds, selectedLength } = usePickerDialog({ idSelectionStates, maxSelectable })
  const { close } = overlay

  const showSecondaryAction = useMemo(
    () => Boolean(secondaryActionText && secondaryActionCallback),
    [secondaryActionCallback, secondaryActionText]
  )

  const itemsSelectedMessage = useMemo(
    () =>
      miscUtils.isNumber(maxSelectable) && maxSelectable >= 0
        ? t('picker-dialog.count.of.total.label', '{number} of {total} Selected', {
            number: selectedLength,
            total: maxSelectable,
          })
        : t('picker-dialog.count-selected.label', '{number} Selected', { number: selectedLength }),
    [maxSelectable, selectedLength, t]
  )

  const handleImportClick = useCallback(() => {
    confirmationCallback?.(selectedIds)
    !noOverlay && close()
  }, [close, confirmationCallback, noOverlay, selectedIds])

  const handleCancelClick = useCallback(() => {
    if (cancelOnClick) {
      cancelOnClick()
    } else {
      close()
    }
  }, [cancelOnClick, close])

  const handleSecondaryActionClick = useCallback(() => {
    secondaryActionCallback?.(selectedIds)
    !noOverlay && close()
  }, [close, secondaryActionCallback, noOverlay, selectedIds])

  const importButtonText = useMemo(() => actionText || t('picker-dialog.import.action', 'Import'), [actionText, t])

  const WrapperComponent = useCallback(
    ({ children }) =>
      noOverlay ? (
        <Bleed all>
          <MarginBox marginX="sm" marginY="xs">
            {children}
          </MarginBox>
        </Bleed>
      ) : (
        <DialogOverlayFooter>{children}</DialogOverlayFooter>
      ),
    [noOverlay]
  )

  return (
    <WrapperComponent>
      <Row alignX="end" alignY="middle">
        <Paragraph size={atWidth({ default: 'xs', sm: 'sm' })}>{itemsSelectedMessage}</Paragraph>
        <DialogOverlayActions>
          {showSecondaryAction ? (
            <Button emphasis="medium" onClick={handleSecondaryActionClick}>
              {secondaryActionText}
            </Button>
          ) : (
            <Button onClick={handleCancelClick}>{t('common-ui:cancel.action', 'Cancel')}</Button>
          )}
          <Button onClick={handleImportClick} emphasis="high" disabled={disableImportButton} noShrinkX>
            {importButtonText}
          </Button>
        </DialogOverlayActions>
      </Row>
    </WrapperComponent>
  )
}

export default PickerDialogFooter
