import React from 'react'
import { css } from '@linaria/core'
import { useStatusOverlay } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { uploadFilesFromFileSelectorInput } from '../helpers/chatAttachmentHelper'
import { useChatAttachmentsDispatch, useChatAttachmentsState } from '../providers/ChatAttachmentsProvider'

const className = css`
  // we need this here, becuase the div wrapper in Chat.js caused css issues
  // ** watch out for any incompatible brower issues **
  display: contents;
`

export const ChatAttachmentDropContainer = ({ children, isReply = false }) => {
  const showStatusOverlay = useStatusOverlay()
  const { pendingArtifactAttachments } = useChatAttachmentsState()
  const chatAttachmentsDispatch = useChatAttachmentsDispatch()
  const [t] = useTranslation()
  const dropAttachmentHandler = async (event) => {
    event.preventDefault()
    let files = event?.dataTransfer?.files
    // Only allow up to 3 files in the pendingAttachments queues
    if (files.length + pendingArtifactAttachments.length > 3) {
      const remainingUploads = 3 - pendingArtifactAttachments.length
      files = Array.from(files).slice(0, remainingUploads)
      showStatusOverlay({ message: t('chat.share-memory.limit', 'Max Uploads Reached'), type: 'warning' })
    }
    if (files?.length > 0) {
      await uploadFilesFromFileSelectorInput({
        fileInputRef: { current: { files } },
        showStatusOverlay,
        pendingArtifactAttachments,
        chatAttachmentsDispatch,
        isReply,
      })
    }
  }
  return (
    <div
      className={className}
      onDrop={dropAttachmentHandler}
      onDragOver={(e) => e.preventDefault()}
      data-testid="chat-file-drop-zone"
    >
      {children}
    </div>
  )
}
