import React, { memo, useCallback } from 'react'
import { css } from '@linaria/core'
import { colors } from '@fs/zion-ui'
import { boolAttr } from '@fs/zion-frontend-friends'
import { ContentCheck } from '@fs/zion-icon'
import PropTypes from 'prop-types'

const selectableContainerCss = css`
  position: relative;
  list-style: none;
  padding: 0;
  margin: 0 auto;
  max-width: 100%;
  height: 250px;
  display: flex;
  position: relative;
  background-color: ${colors.gray00};
  user-select: none;
  outline: none;
  cursor: pointer;

  &::before {
    transition: background 0.25s;
  }
  &::after {
    transition: border-color 0.25s;
    outline: none;
  }

  &[aria-checked='true']::before,
  &:hover::before,
  &:focus::before {
    background-color: rgba(32, 171, 215, 0.2); //${colors.blue30};
    content: '';
    position: absolute;
    bottom: 0;
    inset-inline-start: 0;
    height: 100%;
    width: 100%;
  }

  &:hover::after,
  &:focus::after {
    content: '';
    position: absolute;
    height: 100%;
    width: 100%;
    border: 2px solid ${colors.blue30};
  }

  &:hover > div,
  &:focus > div {
    border: 1.5px solid ${colors.blue30};
    opacity: 1;
  }
`
const checkContainerCss = css`
  position: absolute;
  display: flex;
  justify-content: center;
  align-items: center;
  inset-inline-start: 12px;
  inset-inline-end: 12px;
  height: 24px;
  width: 24px;
  border-radius: 24px;
  background-color: ${colors.gray00};
  border: 1px solid ${colors.gray40};

  &[is-checked] {
    background-color: ${colors.blue50};
    border: 1px solid ${colors.gray00};
    opacity: 1;
  }
`
const imageContainerCss = css`
  object-fit: cover;
  object-position: center;
  height: inherit;
  width: 100%;
  background-color: ${colors.gray05};
  min-height: 250px;
  &:hover {
    border: 2px solid ${colors.blue30};
  }
`

const PickerDialogImage = memo(({ id, alt = '', src, selected, onSelect }) => {
  const handleSelectableClick = useCallback(
    (e) => {
      e.stopPropagation()
      onSelect(id, e.shiftKey)
    },
    [id, onSelect]
  )

  const handleSelectableKeyDown = useCallback(
    (e) => {
      if (e.key === 'Enter') {
        onSelect(id)
      }
    },
    [id, onSelect]
  )

  return (
    <div
      role="checkbox"
      aria-checked={selected?.toString() || 'false'}
      tabIndex="0"
      onClick={handleSelectableClick}
      onKeyDown={handleSelectableKeyDown}
      id={id}
      className={selectableContainerCss}
    >
      <img src={src} alt={alt} className={imageContainerCss} />
      <div className={checkContainerCss} is-checked={boolAttr(selected)}>
        <ContentCheck size="xs" color={selected ? colors.gray00 : colors.gray40} />
      </div>
    </div>
  )
})

export default PickerDialogImage

PickerDialogImage.propTypes = {
  /** Unique id for the image. */
  id: PropTypes.oneOfType([PropTypes.number, PropTypes.string]).isRequired,
  /** Alt text for the image */
  alt: PropTypes.string,
  /** The image url`. */
  src: PropTypes.string.isRequired,
  /** If the image is selected. Derived from the idSelectionStates. */
  selected: PropTypes.bool.isRequired,
  /** Callback when the image is clicked. Pass `selectItem` from useSelection hook. */
  onSelect: PropTypes.func.isRequired,
}
