import { BillboardButton, Row } from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'

export default function ChatEmojiPicker({ onEmojiClick }) {
  const [t] = useTranslation()
  const curatedEmojiRows = [
    {
      '👍': t('chat.emoji-like.label', 'Like'),
      '👎': t('chat.emoji-dislike.label', 'Dislike'),
      '😀': t('chat.emoji-smile.label', 'Smile'),
      '😂': t('chat.emoji-laugh.label', 'Laugh'),
      '😉': t('chat.emoji-wink.label', 'Wink'),
      '🙁': t('chat.emoji-frown.label', 'Frown'),
      '😇': t('chat.emoji-smile-halo.label', 'Smile with halo'),
      '👏': t('chat.emoji-clap.label', 'Clap'),
    },
    {
      '🎉': t('chat.emoji-celebrate.label', 'Celebrate'),
      '❤️': t('chat.emoji-love.label', 'Love'),
      '💯': t('chat.emoji-100.label', '100'),
      '️❗️': t('chat.emoji-exclamation-mark.label', 'Exclamation mark'),
      '🙏': t('chat.emoji-thank-you.label', 'Thank you'),
      '🔍': t('chat.emoji-magnifying-glass.label', 'Magnifying glass'),
      '🤷‍♂️': t('chat.emoji-man-shrugging.label', 'Man shrugging'),
      '🤷‍♀️': t('chat.emoji-woman-shrugging.label', 'Woman shrugging'),
    },
  ]

  return curatedEmojiRows.map((emojiRow, i) => (
    // eslint-disable-next-line react/no-array-index-key -- these items are static array chunks with no unique ID
    <Row gutters="nano" key={i}>
      {Object.entries(emojiRow).map(([emoji, label]) => (
        <BillboardButton key={emoji} emphasis="low" onClick={() => onEmojiClick(emoji)} description={label}>
          <span role="img" aria-label={label}>
            {emoji}
          </span>
        </BillboardButton>
      ))}
    </Row>
  ))
}
