import React from 'react'
import GallerySelectorProvider from './GallerySelectorContext'
import GallerySelectorCore from './GallerySelectorCore'

const noOp = () => {}

export default function GallerySelector({
  maxSelectable,
  confirmationCallback,
  secondaryActionCallback,
  onClose = noOp,
  emptyState,
  openerRef = null,
  acceptedTypes = [],
  excludedMemIds = [],
  noOverlay = false,
  ...props
}) {
  return (
    <GallerySelectorProvider>
      <GallerySelectorCore
        maxSelectable={maxSelectable}
        confirmationCallback={confirmationCallback}
        secondaryActionCallback={secondaryActionCallback}
        onClose={onClose}
        emptyState={emptyState}
        openerRef={openerRef}
        acceptedTypes={acceptedTypes}
        excludedMemIds={excludedMemIds}
        noOverlay={noOverlay}
        {...props}
      />
    </GallerySelectorProvider>
  )
}
