import { useCallback, useMemo } from 'react'
import { miscUtils } from '../utils'

const usePickerDialog = ({ idSelectionStates, maxSelectable }) => {
  const selectedIds = useMemo(
    () => Object.keys(idSelectionStates).filter((id) => idSelectionStates[id]),
    [idSelectionStates]
  )

  const selectedLength = useMemo(() => selectedIds.length, [selectedIds])

  const isImportingDisabled = useCallback(
    () => miscUtils.isNumber(maxSelectable) && maxSelectable === 0,
    [maxSelectable]
  )

  const isSelectionLimitReached = useCallback(
    () => !!maxSelectable && selectedLength >= maxSelectable,
    [maxSelectable, selectedLength]
  )

  const selectionLimitReached = useMemo(
    () => isSelectionLimitReached(idSelectionStates, maxSelectable),
    [idSelectionStates, isSelectionLimitReached, maxSelectable]
  )

  const importingDisabled = useMemo(() => isImportingDisabled(maxSelectable), [isImportingDisabled, maxSelectable])

  const disableImportButton = useMemo(() => {
    return !selectedLength || importingDisabled
  }, [importingDisabled, selectedLength])

  const isSelected = useCallback((id) => idSelectionStates[id], [idSelectionStates])

  const isSelectingEnabled = useCallback(
    (id) => !importingDisabled && (!selectionLimitReached || (selectionLimitReached && isSelected(id))),
    [importingDisabled, isSelected, selectionLimitReached]
  )
  return useMemo(
    () => ({
      disableImportButton,
      isSelected,
      isSelectingEnabled,
      selectedIds,
      selectedLength,
    }),
    [disableImportButton, isSelected, isSelectingEnabled, selectedIds, selectedLength]
  )
}

export default usePickerDialog
