import { useReducer } from 'react'
import chatLog, { LOG_LEVEL } from '../global/chatLog'
import { MESSAGE_HISTORY_START_INDEX } from '../services/fsChat/fsChannelEnums'

const DEFAULT_STATE = {
  loading: true,
  unreadMessages: [],
  error: false,
  messages: [],
  hasMoreUp: false,
  hasMoreDown: false,
  firstItemIndex: MESSAGE_HISTORY_START_INDEX,
  topVisibleMessageId: '',
}

export const MESSAGE_HISTORY_ACTIONS = {
  NEW_MESSAGE: 'NEW_MESSAGE',
  MESSAGE_UPDATED: 'MESSAGE_UPDATED',
  MESSAGE_DELETED: 'MESSAGE_DELETED',
  NEW_CHANNEL: 'NEW_CHANNEL',
  SET_UNREAD_MESSAGES: 'SET_UNREAD_MESSAGES',
  CLEAR_UNREAD_MESSAGES: 'CLEAR_UNREAD_MESSAGES',
  SET_ERROR: 'SET_ERROR',
  SET_MESSAGES: 'SET_MESSAGES',
  SET_TOP_VISIBLE_MESSAGE_ID: 'SET_TOP_VISIBLE_MESSAGE_ID',
  BEFORE_APPEND: 'BEFORE_APPEND',
  AFTER_APPEND: 'AFTER_APPEND',
  BEFORE_PREPEND: 'BEFORE_PREPEND',
  AFTER_PREPEND: 'AFTER_PREPEND',
  INITIAL_LOAD: 'INITIAL_LOAD',
  SET_LOADING: 'SET_LOADING',
}

const removeDuplicateMessagesReducer = (acc, cur) => (acc.some((it) => it.id === cur.id) ? acc : [...acc, cur])

function reducer(state, action) {
  const change = { ...state }

  switch (action.type) {
    case MESSAGE_HISTORY_ACTIONS.NEW_MESSAGE:
      {
        const { event, chatWindowIsFocused } = action
        change.messages = [...change.messages, event.message].reduce(removeDuplicateMessagesReducer, [])
        if (!chatWindowIsFocused) {
          change.unreadMessages = [...change.unreadMessages, event?.message?.id]
        }
      }
      break

    case MESSAGE_HISTORY_ACTIONS.MESSAGE_UPDATED:
      {
        const newMessage = action?.event?.message
        const oldMessages = change.messages
        const oldMessage = oldMessages.find((m) => m.id === newMessage.id)
        if (newMessage && oldMessage) {
          oldMessages[oldMessages.indexOf(oldMessage)] = newMessage
        }
        change.messages = [...oldMessages]
      }
      break

    case MESSAGE_HISTORY_ACTIONS.MESSAGE_DELETED:
      {
        const deletedMessage = action?.event?.message
        const hardDelete = Boolean(action?.event?.hard_delete)
        const oldMessages = change.messages
        const oldMessage = oldMessages.find((m) => m.id === deletedMessage.id)
        if (deletedMessage && oldMessage) {
          if (hardDelete) {
            oldMessages.splice(oldMessages.indexOf(oldMessage), 1)
          } else {
            oldMessages.splice(oldMessages.indexOf(oldMessage), 1, deletedMessage)
          }
        }
        change.messages = [...oldMessages]
      }
      break

    case MESSAGE_HISTORY_ACTIONS.CLEAR_UNREAD_MESSAGES:
      if (change.unreadMessages.length > 0) {
        change.unreadMessages = []
      }
      break

    case MESSAGE_HISTORY_ACTIONS.NEW_CHANNEL:
      change.loading = true
      change.messages = []
      change.hasMoreUp = false
      change.hasMoreDown = false
      change.error = false
      change.unreadMessages = []
      change.firstItemIndex = MESSAGE_HISTORY_START_INDEX
      change.topVisibleMessageId = ''
      break

    case MESSAGE_HISTORY_ACTIONS.SET_TOP_VISIBLE_MESSAGE_ID:
      change.topVisibleMessageId = action.topVisibleMessageId || ''
      break

    case MESSAGE_HISTORY_ACTIONS.BEFORE_APPEND:
    case MESSAGE_HISTORY_ACTIONS.BEFORE_PREPEND:
      change.loading = true
      change.error = false
      break

    case MESSAGE_HISTORY_ACTIONS.AFTER_APPEND:
      // Multiple events can sometimes happen on the first reply within a thread channel
      // change.messages = [...change.messages, ...action.newMessages]
      change.messages = [...change.messages, ...action.newMessages].reduce(removeDuplicateMessagesReducer, [])
      change.hasMoreDown = action.hasMoreDown
      change.error = false
      change.loading = false
      break

    case MESSAGE_HISTORY_ACTIONS.AFTER_PREPEND:
      // Multiple events can sometimes happen on the first reply within a thread channel
      // change.messages = [...action.newMessages, ...change.messages]
      change.messages = [...action.newMessages, ...change.messages].reduce(removeDuplicateMessagesReducer, [])
      change.firstItemIndex -= action?.newMessages?.length ?? 0
      change.hasMoreUp = action.hasMoreUp
      change.error = false
      change.loading = false
      break

    case MESSAGE_HISTORY_ACTIONS.INITIAL_LOAD:
      change.messages = [...action.newMessages]
      change.firstItemIndex = MESSAGE_HISTORY_START_INDEX
      change.hasMoreUp = action.hasMoreUp
      change.hasMoreDown = action.hasMoreDown
      change.error = false
      change.loading = false
      break

    case MESSAGE_HISTORY_ACTIONS.SET_ERROR:
      change.error = true
      change.loading = false
      break

    case MESSAGE_HISTORY_ACTIONS.SET_LOADING:
      change.loading = action.loading
      break

    default:
      chatLog({
        msg: `ERROR: Unhandled action type: ${action.type}`,
        level: LOG_LEVEL.ERROR,
        component: '[useMessageHistoryReducer]',
      })
      break
  }
  return { ...change }
}

export default function useMessageHistoryReducer() {
  return useReducer(reducer, {
    ...DEFAULT_STATE,
  })
}
