/**
 * Some on these functions are copied from memoryUtils in zion-memories.
 * Consider moving our memoryUtils functions (and others in zion-memories) to a separate
 * shared internal/util package so we don't have to duplicate code from zion memories.
 */
import { baseUrl } from '@fs/zion-config'
import { getSessionId } from '@fs/zion-session'
import { i18n } from '@fs/zion-locale'

/** ******************************
 *  == START DUPLICATED UTILS ==
 ********************************* */

const memoriesBaseUrl = `${baseUrl}/memories`

export const restorationToolUrl = `${memoriesBaseUrl}/restore`

const isAudio = (memory) => memory?.category === 'AUDIO'
const isImage = (memory) => memory?.category === 'IMAGE'
const isPdf = (memory) => memory?.category === 'PDF'
const isText = (memory) => memory?.category === 'TEXT'
const isPrivate = (memory) => memory?.visibility === 'PRIVATE'
const isError = (memory) => memory?.artifactDisplayState === 'ERROR'
const isRestricted = (memory) => memory?.artifactDisplayState === 'RESTRICTED'
const isPhaudio = (memory) => isImage(memory) && memory.associatedArtifacts?.artifact.some(isAudio)
const isPhotoStory = (memory) => isText(memory) && memory.associatedArtifacts?.artifact.some(isImage)
const isTextStory = (memory) => isText(memory) && !isPhotoStory(memory)

const getStoryImageMemories = (memory) => {
  if (!isPhotoStory(memory)) return []
  return memory.associatedArtifacts?.artifact.filter((a) => {
    return isImage(a)
  })
}

const arrangeFromFeaturedImage = (associatedArtifacts = [], memory) => {
  const featuredImageIndex = associatedArtifacts.findIndex(({ apid }) => apid === memory.iconApid)
  const reorderedImages = featuredImageIndex >= 0 ? [associatedArtifacts[featuredImageIndex]] : []
  for (let i = 0; i < associatedArtifacts.length; i++) {
    if (i !== featuredImageIndex) {
      reorderedImages.push(associatedArtifacts[i])
    }
  }
  return reorderedImages
}

const getStoryImageUrls = (memory) => {
  const associatedArtifacts = getStoryImageMemories(memory).filter((image) => image.thumbMobileUrl) // Filter out null urls
  if (!associatedArtifacts.length) return []
  const reorderedAssociatedUrls = arrangeFromFeaturedImage(associatedArtifacts, memory)
  // Filter out memories with [ undefined ] as their associatedArtifacts
  return reorderedAssociatedUrls.length
    ? reorderedAssociatedUrls.map((image) => `${image.thumbMobileUrl}&session=${getSessionId()}`)
    : []
}

// Formats audio durations from a the width (timestamp) to xx:xx
// You can pass in an audio memory directly, or a memory with an associated audio (phaudio)
const formatAudioDuration = (memory) => {
  const [associatedAudio] = memory.associatedArtifacts?.artifact.filter(isAudio) ?? []

  const time = isAudio(memory) ? memory.width : associatedAudio.width
  const minutes = time / 60
  const seconds = String(Math.floor((minutes % 1) * 60))

  return `${Math.floor(minutes)}:${seconds.padStart(2, '0')}`
}

const getDateString = (memory) => {
  const datePlaceObject = memory?.datesPlaces?.[0] || {}
  const { dateLocalizedText, dateNormalizedText, dateNonStandardizedText } = datePlaceObject
  return dateLocalizedText || dateNormalizedText || dateNonStandardizedText || ''
}

const getPlaceString = (memory) => {
  const datePlaceObject = memory?.datesPlaces?.[0] || {}
  const { placeLocalizedText, placeNormalizedText, placeNonStandardizedText } = datePlaceObject
  return placeLocalizedText || placeNormalizedText || placeNonStandardizedText || ''
}

/**
 * Checks if the host is localhost.
 */
export const isLocalHost = (host = window.location.origin) => host.includes('localhost')

/** ****************************
 *  == END DUPLICATED UTILS ==
 ******************************* */

/**
 * Get status text for memories with a Status overlay (restricted, error, missing, etc.)
 */
const getStatusText = (memory, missing) => {
  let statusHeading = ''
  let statusBody = ''

  if (isRestricted(memory)) {
    statusHeading = i18n.t('memory-card.restricted.label', 'Restricted')
    statusBody = i18n.t(
      'memory-card.restricted.tooltip',
      'An initial review shows that this memory may conflict with one or more site guidelines. To find out more, check your email or contact FamilySearch Support.'
    )
  } else if (isError(memory)) {
    statusHeading = i18n.t('memory-card.error.label', "Something didn't work")
    statusBody = i18n.t(
      'memory-card.error.tooltip',
      'Sorry. Due to a system error we couldn’t process this memory. Try re-uploading it. If you have more trouble, check with support.'
    )
  }

  // This is purposely not in an else-if because it needs to override every other status
  if (missing) {
    statusHeading = i18n.t('memory-card.missing.label', 'Missing Memory')
    statusBody = i18n.t(
      'memory-card.missing.tooltip',
      'The file for this Memory is missing. Click (or tap) to see your restoration options in the Memories Restoration Tool.'
    )
  }

  return { statusHeading, statusBody }
}

/**
 * Creates aria-labels for MemoryCards based on memory type and status
 */
const getAriaLabel = (memory, missing) => {
  let ariaLabel = ''
  const { title } = memory
  const numAssociatedPhotos = getStoryImageMemories(memory).length

  const ariaLabels = {
    noTitle: {
      photo: i18n.t('memory-card.aria-label.no-title.photo', 'Photo memory with no title'),
      textStory: i18n.t('memory-card.aria-label.no-title.text-story', 'Story memory with no title'),
      photoStory: i18n.t(
        'memory-card.aria-label.no-title.photo-story',
        '{numAssociatedPhotos, plural, one {Story memory with no title and # attached photo} other {Story memory with no title and # attached photos}}',
        { numAssociatedPhotos }
      ),
      audio: i18n.t('memory-card.aria-label.no-title.audio', 'Audio file memory with no title'),
      phaudio: i18n.t(
        'memory-card.aria-label.no-title.phaudio',
        'Photo memory with no title and one attached audio file'
      ),
      pdf: i18n.t('memory-card.aria-label.no-title.pdf', 'Document memory with no title'),
    },
    withTitle: {
      photo: i18n.t('memory-card.aria-label.with-title.photo', 'Photo memory titled {title}', { title }),
      textStory: i18n.t('memory-card.aria-label.with-title.text-story', 'Story memory titled {title}', { title }),
      photoStory: i18n.t(
        'memory-card.aria-label.with-title.photo-story',
        '{numAssociatedPhotos, plural, one {Story memory titled {title} with # attached photo} other {Story memory titled {title} with # attached photos}}',
        { numAssociatedPhotos, title }
      ),
      audio: i18n.t('memory-card.aria-label.with-title.audio', 'Audio file memory titled {title}', { title }),
      phaudio: i18n.t(
        'memory-card.aria-label.with-title.phaudio',
        'Photo memory titled {title} with one attached audio file',
        { title }
      ),
      pdf: i18n.t('memory-card.aria-label.with-title.pdf', 'Document memory titled {title}', { title }),
    },
  }

  const labelType = title ? 'withTitle' : 'noTitle'

  if (isImage(memory) && !isPhaudio(memory)) {
    ariaLabel = ariaLabels[labelType].photo
  } else if (isTextStory(memory)) {
    ariaLabel = ariaLabels[labelType].textStory
  } else if (isPhotoStory(memory)) {
    ariaLabel = ariaLabels[labelType].photoStory
  } else if (isAudio(memory)) {
    ariaLabel = ariaLabels[labelType].audio
  } else if (isPhaudio(memory)) {
    ariaLabel = ariaLabels[labelType].phaudio
  } else if (isPdf(memory)) {
    ariaLabel = ariaLabels[labelType].pdf
  }

  const { statusHeading, statusBody } = getStatusText(memory, missing)

  return `${ariaLabel} ${statusHeading} ${statusBody}`.trim()
}

export const memoryUtils = {
  formatAudioDuration,
  getAriaLabel,
  getDateString,
  getPlaceString,
  getStatusText,
  getStoryImageUrls,
  isAudio,
  isError,
  isImage,
  isPdf,
  isPhaudio,
  isPhotoStory,
  isPrivate,
  isRestricted,
  isTextStory,
}
