import React, { useEffect, useMemo } from 'react'
import PropTypes from 'prop-types'
import { DialogOverlay, usePageWidth } from '@fs/zion-ui'
import PickerDialogFooter from './PickerDialogFooter'
import OverlayContext from './OverlayContext'

const emptyObj = {}

const PickerDialog = ({ headingText, overlay, clearSelected, footerProps = emptyObj, noOverlay, children }) => {
  const atWidth = usePageWidth()
  const { isOpen, transitioning } = overlay

  useEffect(() => {
    if (!isOpen && !transitioning) {
      clearSelected?.()
    }
  }, [clearSelected, isOpen, transitioning])

  const size = atWidth({
    default: 'xs',
    sm: 'sm',
    md: 'md',
    lg: 'lg',
    xl: 'xl',
    xxl: 'xxl',
  })

  const value = useMemo(() => ({ closeOverlay: overlay.close }), [overlay.close])

  return noOverlay ? (
    <>
      {children}
      <PickerDialogFooter {...footerProps} overlay={overlay} noOverlay={noOverlay} />
    </>
  ) : (
    <DialogOverlay title={headingText} size={size} {...overlay}>
      <OverlayContext.Provider value={value}>
        {children}
        <PickerDialogFooter {...footerProps} overlay={overlay} />
      </OverlayContext.Provider>
    </DialogOverlay>
  )
}

export default PickerDialog

PickerDialog.propTypes = {
  /** Heading text of the dialog. */
  headingText: PropTypes.string,
  /** The overlay returned from `useOverlay()`. */
  overlay: PropTypes.oneOfType([PropTypes.node, PropTypes.func, PropTypes.object]).isRequired,
  /** The 'clearSelected' function returned from the `useSelection` hook. */
  clearSelected: PropTypes.func.isRequired,
  /** The props used by the footer. The maximum number of items the user can select, the callback used when Import is clicked, and  `idSelectionStates` returned from the `useSelection` hook. */
  footerProps: PropTypes.shape({
    /** The maximum number of items the user can select. If provided, the count will be shown as: `# of [maxSelectable #] Selected`. */
    maxSelectable: PropTypes.number,
    /** Invoked callback when the Import button is clicked. */
    confirmationCallback: PropTypes.oneOfType([PropTypes.func, PropTypes.object]).isRequired,
    /** The `idSelectionStates` returned from the `useSelection` hook. This is returned to your `confirmationCallback`. */
    idSelectionStates: PropTypes.shape({
      selected: PropTypes.bool,
    }).isRequired,
  }),
}
