import { i18n } from '@fs/zion-locale'
import zionDebug from '@fs/zion-debug'
import axios from '@fs/zion-axios'

export const CHAT_PROCESSING_STATE = {
  PROCESSED: 'PROCESSED',
}
export const CHAT_SCREENING_STATE = {
  RESTRICTED: 'RESTRICTED',
  APPROVED: 'APPROVED',
}

export const MESSAGING_SERVICE_BASE = `/service/msg-artifact`

const MAX_FILE_SIZE = 15 * 1024 * 1024 // 15MB
const acceptList = 'image/jpeg,image/gif,image/png'

const debug = zionDebug('zion:chat:artifact-store')

const getFileValidationString = (file) => {
  if (file.size > MAX_FILE_SIZE) {
    return i18n.t('chat.file-too-large.error', `We're sorry, {filename} is too large to be uploaded.`, {
      filename: file.name,
    })
  }
  if (!file.type) {
    return i18n.t('chat.unknown-file-type.error', `Files of this type are not supported.`)
  }
  const fileType = file.type.split('/')[1]
  // Check file type
  if (!acceptList.includes(file.type)) {
    return i18n.t('chat.file-type.error', `Files of type: {fileType} are not supported.`, { fileType })
  }
  return ''
}

const validateFiles = (files) => {
  return files.reduce(
    (acc, file) => {
      const errorString = getFileValidationString(file)
      if (errorString) {
        acc.validationErrorString = acc.validationErrorString
          ? `${acc.validationErrorString}\n${errorString}`
          : errorString
      } else {
        acc.validFiles.push(file)
      }
      return acc
    },
    { validFiles: [], validationErrorString: '' }
  )
}

export async function uploadFileToArtifactStore(file) {
  const formData = new FormData()
  formData.append('file', file)
  formData.append('mediaType', file.type)
  try {
    const uploadedFileResp = await axios.post(`${MESSAGING_SERVICE_BASE}/msg-attach`, formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
        Accept: 'text/plain',
      },
    })
    return { id: uploadedFileResp.data, filename: file.name, mediaType: file.type }
  } catch (err) {
    if (err.status === 409) {
      debug('File already exists in artifact store')
      return {
        success: true,
        message: i18n.t('chat.error-file-already-exists', 'File already exists'),
        file: err.data,
      }
    }
    debug('Error uploading file to artifact store', err)
    return {
      success: false,
      message: i18n.t('chat.error-uploading-file.message', 'Error uploading file'),
    }
  }
}

export async function uploadFiles({ files }) {
  const { validFiles, validationErrorString } = validateFiles(files)
  const uploadedFileResults = await Promise.allSettled(
    validFiles.map((file) => {
      return uploadFileToArtifactStore(file)
    })
  )

  const uploadedFiles = uploadedFileResults.map((result) => {
    if (result.status === 'fulfilled') {
      return result.value
    }
    return {
      success: false,
      message: result.reason.message,
    }
  })
  return { uploadedFiles, validationErrorString }
}

function getFallbackData({ filename, errStatus }) {
  const fallbackData = {
    thumb64Uri: `${MESSAGING_SERVICE_BASE}/msg-attach/${filename}-thumb64`,
    thumbmobileUri: `${MESSAGING_SERVICE_BASE}/msg-attach/${filename}-thumbmobile`,
    originalUri: `${MESSAGING_SERVICE_BASE}/msg-attach/${filename}`,
    filename,
    thumb200sUri: `${MESSAGING_SERVICE_BASE}/msg-attach/${filename}-thumb200s`,
    thumb200Uri: `${MESSAGING_SERVICE_BASE}/msg-attach/${filename}-thumb200`,
  }
  if (errStatus === 404) {
    fallbackData.screeningState = CHAT_SCREENING_STATE.RESTRICTED
  }
  return fallbackData
}

export async function getArtifactFromStore(filename) {
  if (!filename) {
    return null
  }
  const url = `${MESSAGING_SERVICE_BASE}/msg-attach/info/${filename}`
  const params = {
    _: new Date().getTime(),
  }
  try {
    const { data } = await axios.get(url, { params })
    return data || getFallbackData({ filename })
  } catch (err) {
    const errStatus = err?.response?.status
    return getFallbackData({ filename, errStatus })
  }
}
