import React, { useRef, useEffect } from 'react'
import { useQueryParams } from '@fs/zion-router'
import { useEvent } from '@fs/zion-frontend-friends'
import { useChatDispatch } from '../providers/ChatStateProvider'
import ChatContentMuted from './ChatContentMuted'
import ChatContentMessages from '../chat-messages/ChatContentMessages'
import useMessageHistory from '../hooks/useMessageHistory'
import ChatHelperMessages from '../chat-helper/ChatHelperMessages'
import { isChannelMuted } from '../helpers/stream/streamChatHelper'
import useChatLog from '../hooks/useChatLog'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import { markChannelRead, getMessageHistoryMessages } from '../services/messageHistory/messageHistoryService'
import ChatReconnectPage from '../chat-reconnect/ChatReconnectPage'
import { MESSAGE_HISTORY_ACTIONS } from '../hooks/useMessageHistoryReducer'

export default function ChatContent({ isTyping, channel, isCreate, focusWrapperRef }) {
  const chatDispatch = useChatDispatch()
  const virtuosoRef = useRef(null)
  const scrollTimeoutRef = useRef(null)
  const { query } = useQueryParams()
  const {
    loading,
    messages,
    error,
    unreadMessages,
    firstItemIndex,
    prependItems,
    appendItems,
    markChannelReadOnRangeChange,
    setTopVisibleMessageId,
    topVisibleMessageId,
    messageHistoryDispatch,
  } = useMessageHistory({
    channel,
    virtuosoRef,
    chatDispatch,
    initialMessageId: query.messageId,
  })

  const hasMessages = messages?.length > 0
  const showHelperMessages = !isCreate && !loading && !error

  const { log, track } = useChatLog({ component: '[ChatContent]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  const onFocusMarkRead = useEvent(() => {
    markChannelRead({
      chatWindowIsFocused: true,
      channel,
      handleBasicError,
      messageHistoryDispatch,
      chatDispatch,
      track,
    })
  })

  const retryFetchMessages = useEvent(async () => {
    track({ link_name: 'Chat:Message List Error:click retry' })
    // Reset error state and start loading
    messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.NEW_CHANNEL })

    if (channel) {
      try {
        const { newMessages, moreUp, moreDown } = await getMessageHistoryMessages({
          channel,
          messageHistoryDispatch,
          chatDispatch,
        })

        messageHistoryDispatch({
          type: MESSAGE_HISTORY_ACTIONS.INITIAL_LOAD,
          newMessages,
          hasMoreUp: moreUp,
          hasMoreDown: moreDown,
        })

        // Scroll to end of messages
        if (scrollTimeoutRef.current) {
          clearTimeout(scrollTimeoutRef.current)
        }
        scrollTimeoutRef.current = setTimeout(() => {
          if (newMessages.length > 0) {
            virtuosoRef.current?.scrollToIndex({ index: newMessages.length - 1, align: 'end', behavior: 'instant' })
          }
          scrollTimeoutRef.current = null
        }, 10)
      } catch {
        // Error already handled by getMessageHistoryMessages (SET_ERROR dispatched)
      }
    }
  })

  useEffect(() => {
    const focusWrapper = focusWrapperRef?.current
    // manually adding focusin event because adding an onFocus prop to Chat.js caused state issues
    // using focusin instead of focus, becuase focusin bubbles up the DOM tree
    if (focusWrapper) {
      focusWrapper.addEventListener('focusin', onFocusMarkRead)
    }
    return () => {
      if (focusWrapper) {
        focusWrapper.removeEventListener('focusin', onFocusMarkRead)
      }
    }
  }, [focusWrapperRef, onFocusMarkRead])

  // Cleanup scroll timeout on unmount
  useEffect(() => {
    return () => {
      if (scrollTimeoutRef.current) {
        clearTimeout(scrollTimeoutRef.current)
      }
    }
  }, [])

  return (
    <>
      {(hasMessages || loading) && !error && (
        <ChatContentMessages
          channel={channel}
          loading={loading}
          messages={messages}
          unreadMessages={unreadMessages}
          firstItemIndex={firstItemIndex}
          prependItems={prependItems}
          appendItems={appendItems}
          virtuosoRef={virtuosoRef}
          markChannelReadOnRangeChange={markChannelReadOnRangeChange}
          setTopVisibleMessageId={setTopVisibleMessageId}
          topVisibleMessageId={topVisibleMessageId}
        />
      )}

      {error && <ChatReconnectPage onClick={retryFetchMessages} hideImage />}

      {showHelperMessages && <ChatHelperMessages isTyping={isTyping} messages={messages} />}

      {isChannelMuted(channel) && <ChatContentMuted channel={channel} />}
    </>
  )
}
