import axios from '@fs/zion-axios'
import { serviceUtils } from '../utils'

// -------------------------------
// ---- MMS PATRONS API CALLS ----
// -------------------------------
const baseUrl = `/service/memories/manager/patrons`

/** */
const getAlbumsForUser = ({ cisId }) => axios.get(`${baseUrl}/${cisId}/albums`)

/** */
const getFavoriteMemoriesForUser = ({ cisId, queryParams }) =>
  axios.get(`${baseUrl}/${cisId}/favorites/artifacts${serviceUtils.getQueryString(queryParams)}`)

/** */
const getFavoriteAlbums = ({ cisId }) => axios.get(`${baseUrl}/${cisId}/favoriteAlbums/albums`)

export { getAlbumsForUser, getFavoriteAlbums, getFavoriteMemoriesForUser }
