import { ContentRemove } from '@fs/zion-icon'
import { IconButton, MarginBox, Row, Separator, Paragraph, Ellipsis } from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'
import ChatAttachment, { ChatAboutAttachment } from './ChatAttachment'

const RemoveButton = ({ removeHandler }) => {
  const [t] = useTranslation()
  return (
    <div style={{ position: 'absolute', top: '-8px', right: '-8px' }}>
      <IconButton
        Icon={ContentRemove}
        title={t('common-ui:remove.action', 'Remove')}
        onClick={removeHandler}
        color="blue"
        emphasis="lightHigh"
        size="xs"
      />
    </div>
  )
}

export default function ChatPendingAttachments({
  pendingArtifactAttachments,
  artifactRemoveHandler,
  pendingAboutAttachment,
  aboutRemoveHandler,
  isReply,
}) {
  const showArtifacts = pendingArtifactAttachments?.length > 0
  const showAbout = pendingAboutAttachment?.text || pendingAboutAttachment?.link
  if (showArtifacts || showAbout) {
    return (
      <MarginBox marginX="xxs" marginY="nano" data-testid="chat-pending-attachments">
        <Separator size="nano" />
        <Row gutters="nano" wrap>
          {showArtifacts &&
            pendingArtifactAttachments?.map((a) => {
              if (isReply !== a.isReply) {
                return null
              }
              return (
                <div key={a.id} gutters="nano" style={{ position: 'relative', maxWidth: '66px' }}>
                  <ChatAttachment pending id={a.id} serviceType={a.serviceType} fromUser />
                  <RemoveButton alignY="middle" removeHandler={() => artifactRemoveHandler(a.id)} noShrinkX />
                  <Paragraph size="xs">
                    <Ellipsis>{a.title}</Ellipsis>
                  </Paragraph>
                </div>
              )
            })}
          {showAbout && (
            <div style={{ position: 'relative' }}>
              <ChatAboutAttachment data={pendingAboutAttachment.text} filename={pendingAboutAttachment.link} />
              <RemoveButton removeHandler={aboutRemoveHandler} noShrinkX />
            </div>
          )}
        </Row>
      </MarginBox>
    )
  }

  return null
}
