import React, { Suspense, useEffect } from 'react'
import { css } from '@linaria/core'
import {
  BillboardText,
  Paragraph,
  Card,
  colors,
  Ellipsis,
  ListItem,
  Row,
  useOverlay,
  H6,
  Subheading,
} from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import MemoryTile from '@fs/zion-memory-tile'
import { NoticeDoNot, NoticeLoading } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { useChatAttachment } from '../hooks/useChatAttachment'
import { MESSAGING_SERVICE_BASE, CHAT_SCREENING_STATE } from '../services/memories/artifactStoreService'
import {
  uploadToTileProps,
  uploadMemoryToTileProps,
  getScreeningStateLabel,
  CHAT_ATTACHMENT_SERVICE_TYPE,
  getCanShowImage,
} from '../helpers/chatAttachmentHelper'

const ChatAttachmentFullPageOverlay = React.lazy(() => import('./ChatAttachmentFullPageOverlay'))
ChatAttachmentFullPageOverlay.displayName = 'ChatAttachmentFullPageOverlay'

const tileHeightCss = css`
  height: 68px;
`

const loadingSquare = css`
  height: 68px;
  width: 68px;
  background-color: ${colors.gray03};
  display: flex;
  align-items: center;
  justify-content: center;
`

const textItemsCss = css`
  max-width: 200px;
  display: flex;
  flex-direction: column;
  justify-content: center;
`

const AttachmentCard = ({ to, ...props }) => (
  <Card
    backgroundColor={colors.gray00}
    edges="border"
    target="_blank"
    external={to ? true : undefined}
    to={to}
    {...props}
  />
)

const LinkOrNot = ({ link, children }) => {
  if (link) {
    return (
      <Link external to={link} wayfinding target="_blank">
        {children}
      </Link>
    )
  }
  return <>{children}</>
}

const generateUrl = ({ serviceType, id }) => {
  if (serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.MEMORY_ARTIFACT) {
    return id && `/photos/artifacts/${id}`
  }
  return id ? `${MESSAGING_SERVICE_BASE}/msg-attach/${id}` : undefined
}

const generateTileProps = ({ serviceType, data, memory }) => {
  if (serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.MEMORY_ARTIFACT) {
    return data || uploadMemoryToTileProps(memory)
  }
  return data || uploadToTileProps(memory)
}

function ChatInternalAttachment({ memory, pending, status, tileProps }) {
  const [t] = useTranslation()
  const screeningState = memory?.screeningState
  const label = getScreeningStateLabel(screeningState)

  switch (status) {
    case 'error':
      return (
        <H6>
          <Ellipsis>{t('chat.error-memory-not-found.heading', 'Memory not found')}</Ellipsis>
          <Subheading>
            <Ellipsis>{t('chat.error-memory-deleted.subheading', 'Memory was possibly deleted')}</Ellipsis>
          </Subheading>
        </H6>
      )
    case 'fetched':
      return memory?.screeningState === CHAT_SCREENING_STATE.RESTRICTED ? (
        <div style={{ color: colors.danger30 }}>{label}</div>
      ) : (
        <H6>
          <Ellipsis>{tileProps?.title}</Ellipsis>
          <Subheading>
            <Ellipsis lineClamp={2}>{tileProps?.description}</Ellipsis>
          </Subheading>
        </H6>
      )

    default:
      return pending ? null : (
        <H6>
          <Ellipsis>{label}</Ellipsis>
        </H6>
      )
  }
}

const AttachmentThumbnail = ({ tileProps, memory }) => {
  return (
    <div className={tileHeightCss}>
      {!tileProps || memory?.screeningState === CHAT_SCREENING_STATE.RESTRICTED ? (
        <div className={loadingSquare}>
          {memory?.screeningState === CHAT_SCREENING_STATE.RESTRICTED && <NoticeDoNot color={colors.danger30} />}
        </div>
      ) : (
        <MemoryTile {...tileProps} />
      )}
    </div>
  )
}

const ChatAttachment = ({ pending, data, id, serviceType, fromUser, setAttachmentWithData }) => {
  const overlay = useOverlay()
  const url = generateUrl({ serviceType, id })
  const { memory, status } = useChatAttachment({ pending, id, serviceType })
  const tileProps = generateTileProps({ serviceType, data, memory })
  const isMemory = serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.MEMORY_ARTIFACT
  const canShowImage = getCanShowImage({ screeningState: memory?.screeningState, fromUser })
  const AttachmentWrapper = pending ? Link : AttachmentCard
  const attachmentWrapperProps = pending ? { external: true } : {}

  useEffect(() => {
    setAttachmentWithData &&
      setAttachmentWithData((prev) => {
        return { ...prev, [id]: memory }
      })
  }, [id, memory, setAttachmentWithData])

  return (
    <AttachmentWrapper
      to={canShowImage && isMemory ? url : undefined}
      onClick={canShowImage && !isMemory ? overlay.handleClick : undefined}
      {...attachmentWrapperProps}
    >
      <Row alignY="middle" data-testid="chat-attachment" gutters="xs">
        <Suspense fallback={<NoticeLoading />}>
          {/* Prevent clicks in the overlay from propagating through and triggering the handleClick, which then closes the overlay (FSCHAT-783) */}
          {(overlay.isOpen || overlay.transitioning) && (
            <ChatAttachmentFullPageOverlay {...overlay} url={url} onClick={(e) => e.stopPropagation()} id={id} />
          )}
        </Suspense>
        <AttachmentThumbnail serviceType={serviceType} tileProps={tileProps} memory={memory} noShrinkX />
        <div className={textItemsCss}>
          <ChatInternalAttachment tileProps={tileProps} memory={memory} pending={pending} status={status} />
        </div>
      </Row>
    </AttachmentWrapper>
  )
}

export default ChatAttachment

export const ChatAboutAttachment = ({ data, filename }) => {
  return (
    <AttachmentCard data-testid="chat-about-attachment">
      <LinkOrNot link={filename}>{data}</LinkOrNot>
    </AttachmentCard>
  )
}

export const ChatEnrichedUrlAttachment = ({ attachment }) => {
  const { author_name, title, title_link, text, image_url } = attachment
  return (
    <AttachmentCard to={title_link}>
      <BillboardText primaryColor={colors.blue60}>
        <ListItem
          data-testid="chat-enriched-url-attachment"
          startElement={<ListItem.Image src={image_url} size="sm" />}
          primaryText={author_name || title}
          secondaryText={author_name ? title : undefined}
          emphasized
        />
      </BillboardText>
      <Paragraph size="xs">{text}</Paragraph>
    </AttachmentCard>
  )
}
