import { MarginBox, Paragraph, Separator } from '@fs/zion-ui'
import React, { useCallback, useEffect, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { lastMessageWithinAUADelay, getHelpeeInfo } from '../helpers/chatAUAHelper'
import { useCurrentChannel } from '../hooks/channelHooks'
import useInterval from '../hooks/utils/useInterval'
import { useChatState } from '../providers/ChatStateProvider'
import NoResultsText from '../chat/NoResultsText'
import { isSupportChannel } from '../services/fsChat/fsChatService'

const ONE_MINUTE = 60 * 1000

export default function ChatHelperMessages({ isTyping, messages }) {
  const [t] = useTranslation()
  const [displayHelperBusy, setDisplayHelperBusy] = useState(false)
  const { client } = useChatState()
  const channel = useCurrentChannel()
  const [helpeeInfo, setHelpeeInfo] = useState({ isHelpee: false, helpeeName: undefined })
  const { isHelpee, helpeeName } = helpeeInfo
  const hasMessages = messages?.length > 0

  const updateDisplayHelperBusy = useCallback(() => {
    setDisplayHelperBusy(lastMessageWithinAUADelay(messages))
  }, [messages, setDisplayHelperBusy])

  useEffect(() => {
    updateDisplayHelperBusy()
  }, [updateDisplayHelperBusy, messages])

  // This was wrapped in a useEffect to delay rendering until after useMessageHistory state updates
  useEffect(() => setHelpeeInfo(getHelpeeInfo({ channel, client })), [channel, client])

  useInterval(() => {
    updateDisplayHelperBusy()
  }, ONE_MINUTE)

  return (
    <>
      {channel && !hasMessages && (
        <MarginBox marginX="sm">
          <Separator size="xs" />
          {isHelpee &&
            t(
              'chat.type-your-ask-us-anything-question.message',
              "Someone will join you shortly. Please type your question below while you're waiting."
            )}
          {isSupportChannel(channel) &&
            !isHelpee &&
            helpeeName &&
            t(
              'chat.helping-an-ask-us-anything.message',
              `{name} hasn't asked a question yet. If it's been a few minutes, please reach out to see if they still need help.`,
              { name: helpeeName }
            )}
          {!isSupportChannel(channel) && <NoResultsText />}
        </MarginBox>
      )}

      {isSupportChannel(channel) && displayHelperBusy && isHelpee && !isTyping && (
        <MarginBox marginX="sm">
          <Separator size="xs" />
          <Paragraph size="sm">
            {t(
              'chat.aua-get-more-help.message',
              "The person helping you may be chatting with another guest. If you don't get a timely response, you may need to start a new Ask Us Anything chat."
            )}
          </Paragraph>
        </MarginBox>
      )}
    </>
  )
}
