import React, { useState } from 'react'
import { IconButton, useStatusOverlay } from '@fs/zion-ui'
import { ControlTranslate, NoticeLoading } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import { useTranslation } from 'react-i18next'
import useChatLog from '../../hooks/useChatLog'
import { LOG_LEVEL } from '../../global/chatLog'
import { useChatState } from '../../providers/ChatStateProvider'
import useSupportedLanguageName from './chatTranslationHelper'

export default function ChatTranslateMessageToggle({
  message,
  channelId,
  isTranslated,
  setIsTranslated,
  isMessageInUsersLanguage,
}) {
  const [t] = useTranslation()
  const { log, track } = useChatLog({ component: '[ChatTranslateMessageToggle]' })
  const showStatusOverlay = useStatusOverlay()
  const { client } = useChatState()
  const { id: messageId } = message
  const languageName = useSupportedLanguageName(i18n.language)

  const [isTranslateLoading, setIsTranslateLoading] = useState(false)

  const onMessageLanguageToggle = async () => {
    try {
      setIsTranslateLoading(true)

      // before translating, if the message's original language was already detected
      // as the current browser language, no need to translate
      if (isMessageInUsersLanguage) {
        setIsTranslateLoading(false)
        return
      }

      if (!isTranslated) {
        track(
          { link_name: `Chat:Translate Message - ${i18n.language}` },
          { chatMessageId: messageId, chatChannelId: channelId }
        )
        // Only call Stream once for each language.
        // If it has been translated, we will set isTranslated to true,
        // and pull in the translated string in ChatMessage.js
        if (!message?.i18n?.[`${i18n.language}_text`]) await client.translateMessage(messageId, i18n.language)

        // after translating, skip setting isTranslated if the message's original language is already in the browser language
        if (isMessageInUsersLanguage) {
          setIsTranslateLoading(false)
          return
        }
      }

      setIsTranslated(!isTranslated)
      setIsTranslateLoading(false)
    } catch (error) {
      log({
        error: `Error translating message with messageId ${messageId} into language ${i18n.language}: ${error}`,
        level: LOG_LEVEL.ERROR,
      })
      setIsTranslateLoading(false)
      showStatusOverlay({
        message: t(
          'chat.translate-message.error',
          'Something went wrong with the translation. Please wait a few minutes, and try again.'
        ),
        type: 'error',
      })
    }
  }

  return (
    <IconButton
      title={
        isTranslated
          ? t('chat.view-original', 'View Original')
          : t('chat.translate-message.label', `Translate Message to ${languageName}`, { language: languageName })
      }
      size="xs"
      Icon={isTranslateLoading ? NoticeLoading : ControlTranslate}
      aria-label={
        isTranslated
          ? t('chat.view-original', 'View Original')
          : t('chat.translate-message.label', `Translate Message to ${languageName}`, { language: languageName })
      }
      data-testid="translate-message-toggle"
      onClick={onMessageLanguageToggle}
    />
  )
}
