import { useCallback, useEffect, useMemo, useRef } from 'react'
import Cache from '@fs/zion-cache'
import { useEvent } from '@fs/zion-frontend-friends'
import { usePageIsFocused } from './usePageVisibility'
import useMessageHistoryReducer, { MESSAGE_HISTORY_ACTIONS } from './useMessageHistoryReducer'
import {
  handleMessageEvent,
  getMessageHistoryMessages,
  markChannelRead,
  channelReadAfterMessage,
} from '../services/messageHistory/messageHistoryService'
import useHandleChatErrors from './useHandleChatErrors'
import { CHAT_MESSAGE_TYPE, getChannelUnreadCount } from '../helpers/stream/streamChatHelper'
import useChatLog from './useChatLog'
import { LOG_LEVEL } from '../global/chatLog'
import useChatFlags from './useChatFlags'

const cache = new Cache({ dbName: 'fsChatMessageSync' })

const channelEvents = [
  'message.new',
  'message.updated',
  'message.deleted',
  'reaction.new',
  'reaction.updated',
  'reaction.deleted',
]

function getTopVisibleMessageIdStorageKey(cid) {
  return cid ? `${cid}-topVisibleMessageId` : null
}

async function cacheTopVisibleMessageId({ messageId, cid, log, messageHistoryDispatch }) {
  try {
    const storageKey = getTopVisibleMessageIdStorageKey(cid)
    if (storageKey && typeof messageId === 'string') {
      await cache.setItem(storageKey, messageId)
    }
    messageHistoryDispatch({
      type: MESSAGE_HISTORY_ACTIONS.SET_TOP_VISIBLE_MESSAGE_ID,
      topVisibleMessageId: messageId,
    })
  } catch (err) {
    log({ msg: `Unable to store topVisibleMessageId ${messageId} due to err ${err}`, level: LOG_LEVEL.ERROR })
  }
}

async function getCachedTopVisibleMessageId(cid) {
  let newTopVisibleMessageId
  try {
    const storageKey = getTopVisibleMessageIdStorageKey(cid)
    newTopVisibleMessageId = await cache.getItem(storageKey)
  } catch (cacheError) {
    // Ignore this, and just load from the bottom
  }
  return newTopVisibleMessageId
}

// eslint-disable-next-line sonarjs/cognitive-complexity -- this is complex, but most of it is nested functions that aren’t easily extracted out
export default function useMessageHistory({ channel, parentMessage, virtuosoRef, chatDispatch, initialMessageId }) {
  const pid = parentMessage?.id
  const [messageHistoryState, messageHistoryDispatch] = useMessageHistoryReducer()
  const { loading, unreadMessages, error, messages, firstItemIndex, hasMoreUp, hasMoreDown, topVisibleMessageId } =
    messageHistoryState

  const chatWindowIsFocused = usePageIsFocused()
  const { log, track } = useChatLog({ component: '[useMessageHistory]' })
  const { handleBasicError } = useHandleChatErrors({ log })
  const oldestMessageId = messages[0]?.id
  const newestMessageId = messages?.length > 0 ? messages[messages.length - 1].id : undefined
  const handleChannelEvent = useEvent((event) => {
    handleMessageEvent({
      event,
      channel,
      messageHistoryDispatch,
      chatDispatch,
      pid,
      chatWindowIsFocused,
      handleBasicError,
      log,
      track,
    })
  })

  const { messagingChatRemoveChannelWatchIsOn } = useChatFlags()
  useEffect(() => {
    !messagingChatRemoveChannelWatchIsOn && channel?.watch()
    channelEvents.forEach((event) => channel?.on(event, handleChannelEvent))
    return () => {
      channelEvents.forEach((event) => {
        channel?.off(event, handleChannelEvent)
      })
    }
  }, [channel, handleChannelEvent, messagingChatRemoveChannelWatchIsOn])

  const prependItems = useCallback(async () => {
    if (!loading && channel && hasMoreUp) {
      messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.BEFORE_PREPEND })
      try {
        const { newMessages, moreUp } = await getMessageHistoryMessages({
          channel,
          messageHistoryDispatch,
          oldestMessageId,
        })
        messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.AFTER_PREPEND, newMessages, hasMoreUp: moreUp })
      } catch {
        // Error already handled by getMessageHistoryMessages (SET_ERROR dispatched)
      }
    }
  }, [channel, messageHistoryDispatch, oldestMessageId, loading, hasMoreUp])

  const appendItems = useCallback(async () => {
    if (!loading && channel && hasMoreDown) {
      messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.BEFORE_APPEND })
      try {
        const { newMessages, moreDown } = await getMessageHistoryMessages({
          channel,
          messageHistoryDispatch,
          newestMessageId,
        })
        messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.AFTER_APPEND, newMessages, hasMoreDown: moreDown })
      } catch {
        // Error already handled by getMessageHistoryMessages (SET_ERROR dispatched)
      }
    }
  }, [channel, messageHistoryDispatch, newestMessageId, loading, hasMoreDown])

  // When the virtuoso range changes, check if the top visible message is such that we should mark the channel as read
  const markingReadRef = useRef(false)
  const markChannelReadOnRangeChange = useCallback(
    async (message) => {
      // Prevent overlapping requests to mark channel read (e.g., when scrolling quickly)
      if (markingReadRef.current) return
      const isThreadParent = message?.id === pid
      if (!message && !isThreadParent) return

      const isFirstMessage = !hasMoreUp
      const isMessageBeforeUnreads = channelReadAfterMessage({ channel, message })
      if (isFirstMessage || isThreadParent || isMessageBeforeUnreads) {
        markingReadRef.current = true
        await markChannelRead({
          chatWindowIsFocused,
          channel,
          handleBasicError,
          messageHistoryDispatch,
          chatDispatch,
          track,
          cisId: message?.user?.id,
        })
        markingReadRef.current = false
      }
    },
    [channel, chatDispatch, chatWindowIsFocused, handleBasicError, hasMoreUp, messageHistoryDispatch, pid, track]
  )

  // Cache the message ID that is currently at the top of the virtuoso scroller.
  // We will use it later to read and display the same messages if the user comes back to this same channel.
  const setTopVisibleMessageId = useCallback(
    async (messageId) => {
      if (messageId === '' && channel?.cid) {
        cacheTopVisibleMessageId({ messageId, cid: channel?.cid, log, messageHistoryDispatch })
      } else {
        const message = messages?.find((m) => m.id === messageId)
        const isThreadParent = messageId === pid
        if (!message && !isThreadParent) return
        if (!isThreadParent) {
          cacheTopVisibleMessageId({ messageId, cid: channel?.cid, log, messageHistoryDispatch })
        }
      }
    },
    [channel, log, messageHistoryDispatch, messages, pid]
  )

  useEffect(() => {
    let isLatestRender = true
    let scrollTimeout = null
    const getInitialMessages = async () => {
      messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.NEW_CHANNEL })

      if (channel) {
        let newTopVisibleMessageId = ''

        // If there are unreads, start at the bottom rather than cached position (unless initialMessageId is provided)
        if (getChannelUnreadCount({ channel }) === 0 || initialMessageId) {
          newTopVisibleMessageId = initialMessageId || (await getCachedTopVisibleMessageId(channel.cid))
          messageHistoryDispatch({
            type: MESSAGE_HISTORY_ACTIONS.SET_TOP_VISIBLE_MESSAGE_ID,
            topVisibleMessageId: newTopVisibleMessageId || '',
          })
        }

        // Start from the specified message and read towards the more recent (newer) messages.
        // If a message ID is not provided, then read the most recent page of messages and scroll to the end.
        try {
          const { newMessages, moreUp, moreDown, isFreshQuery } = await getMessageHistoryMessages({
            channel,
            messageHistoryDispatch,
            chatDispatch,
            topVisibleMessageId: newTopVisibleMessageId,
            getIsMounted: () => isLatestRender,
          })
          if (isLatestRender) {
            messageHistoryDispatch({
              type: MESSAGE_HISTORY_ACTIONS.INITIAL_LOAD,
              newMessages,
              hasMoreUp: moreUp,
              // If we started at the bottom, there will not be newer messages, so optimize for that case to avoid an extra query
              hasMoreDown: newTopVisibleMessageId ? moreDown : false,
            })

            // Scroll to the provided message ID or to the end of the list if not provided.
            if (newTopVisibleMessageId && !isFreshQuery) {
              scrollTimeout = setTimeout(() => {
                const providedMessageIndex = newMessages.findIndex((message) => message.id === newTopVisibleMessageId)
                virtuosoRef.current?.scrollToIndex({ index: providedMessageIndex, align: 'end', behavior: 'instant' })
              }, 10)
            } else if (newMessages.length > 0) {
              scrollTimeout = setTimeout(() => {
                virtuosoRef.current?.scrollToIndex({ index: newMessages.length - 1, align: 'end', behavior: 'instant' })
              }, 10)
            }
          }
        } catch {
          // Error already handled by getMessageHistoryMessages (SET_ERROR dispatched)
        }
      } else if (isLatestRender) {
        messageHistoryDispatch({ type: MESSAGE_HISTORY_ACTIONS.INITIAL_LOAD, newMessages: [], hasMore: false })
      }
    }

    getInitialMessages()
    return () => {
      // Cleaning up to make sure we don't update the state with the result of an old query to getMessageHistoryMessages
      isLatestRender = false
      if (scrollTimeout) {
        clearTimeout(scrollTimeout)
      }
    }
  }, [chatDispatch, messageHistoryDispatch, channel, virtuosoRef, initialMessageId])

  // Exclude soft deletes that have no_replies
  // Hide any messages sent while a user is shadow banned
  // The shadowed flag will only appear true to others
  const filteredMessages = useMemo(
    () =>
      messages.filter((m) => {
        return !(m.type === CHAT_MESSAGE_TYPE.DELETED || (m.fs_message_deleted && m.reply_count === 0) || m.shadowed)
      }),
    [messages]
  )

  return {
    loading,
    error,
    messages: filteredMessages,
    unreadMessages,
    firstItemIndex,
    prependItems,
    markChannelReadOnRangeChange,
    setTopVisibleMessageId,
    appendItems,
    topVisibleMessageId,
    messageHistoryDispatch,
  }
}
