import { useEvent } from '@fs/zion-frontend-friends'
import { useStatusOverlay } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { LOG_LEVEL } from '../global/chatLog'
import { getChannelMembers } from '../helpers/stream/streamChatHelper'
import { useChatState } from '../providers/ChatStateProvider'
import { isDirectChannel } from '../services/fsChat/fsChatService'
import { useChannelActions, useRedirectIfOnChannel } from './channelHooks'
import useChatLog from './useChatLog'
import useHandleChatErrors from './useHandleChatErrors'

export default function useChatBlockUser({ targetUserId, targetUserName }) {
  const [t] = useTranslation()
  const { channels, client } = useChatState()
  const { log, track } = useChatLog({ component: '[useChatBlockUser]' })
  const { handleBasicError } = useHandleChatErrors({ log })
  const showStatusOverlay = useStatusOverlay()

  // Find direct channel with the user being blocked
  const targetUserChannel = channels.find(
    (channel) =>
      isDirectChannel(channel) &&
      getChannelMembers({ channel, excludeUserId: client.userID }).every((member) => member.user_id === targetUserId)
  )
  const { markChannelRead } = useChannelActions({ channel: targetUserChannel })
  const redirectIfOnChannel = useRedirectIfOnChannel(targetUserChannel)

  const blockUser = useEvent(async () => {
    try {
      log({ msg: `Chat:Block User ${targetUserId}`, level: LOG_LEVEL.WARN }, { targetUserId })
      track({ link_name: `Chat:Block User` }, { chatTargetUserIds: [targetUserId] })
      // Do everything possible to hide the blocked user
      if (targetUserChannel) {
        markChannelRead()
        redirectIfOnChannel()
      }
      await client.muteUser(targetUserId)
    } catch (error) {
      handleBasicError(error, { moreInfo: `Error blocking user. TargetUserId: ${targetUserId}` })
    }
  })

  const unblockUser = useEvent(async () => {
    try {
      track({ link_name: `Chat:Unblock User` }, { chatTargetUserIds: [targetUserId] })
      await client.unmuteUser(targetUserId)
      showStatusOverlay({
        message: t('chat.user-unblocked.label', '{name} has been unblocked', { name: targetUserName }),
        type: 'success',
      })
    } catch (error) {
      handleBasicError(error, { moreInfo: `Error unblocking user. TargetUserId: ${targetUserId}` })
    }
  })

  return { blockUser, unblockUser }
}
