import React from 'react'
import { Paragraph, Ellipsis } from '@fs/zion-ui'
import useMemoryCard from '../useMemoryCard'

export default function Details({ memory, showDatePlace, dense }) {
  const { date, place } = useMemoryCard(memory)

  if (!showDatePlace) {
    return null
  }

  return (
    <Paragraph size={dense ? 'xs' : 'sm'} secondary>
      {showDatePlace === 'date' && <Ellipsis>{date}</Ellipsis>}
      {showDatePlace === 'place' && <Ellipsis>{place}</Ellipsis>}
    </Paragraph>
  )
}
