import React from 'react'
import { css } from '@linaria/core'
import { Ellipsis, LayoutBand, Paragraph, Row, Separator, WhiteTheme, colors } from '@fs/zion-ui'
import { DocumentImageBroken, NoticeImportant, NoticeWarning } from '@fs/zion-icon'
import useMemoryCard from '../useMemoryCard'
import { memoryUtils } from '../../utils'

const statusCss = css`
  display: flex;
  align-items: center;
  position: absolute;
  width: 100%;
  height: 100%;
  top: 0;
  border-radius: 8px;
  z-index: 2;
`

function StatusIcon({ memory, missing, ...props }) {
  const { isRestrictedMemory, isErrorMemory } = useMemoryCard(memory)
  let statusIcon = null

  if (isRestrictedMemory) {
    statusIcon = <NoticeWarning background={colors.yellow20} {...props} />
  } else if (isErrorMemory) {
    statusIcon = <NoticeImportant background={colors.danger70} {...props} />
  }

  // This is purposely not in an else-if because it needs to override every other status
  if (missing) {
    statusIcon = <DocumentImageBroken background={colors.yellow50} {...props} />
  }

  return statusIcon
}

export default function Status({ memory, missing, dense }) {
  const { statusHeading, statusBody } = memoryUtils.getStatusText(memory, missing)

  return statusHeading && statusBody ? (
    <LayoutBand marginX="xs" marginY="xs" color="rgba(0, 0, 0, .75)" className={statusCss}>
      <WhiteTheme>
        <Row alignX="center">
          <StatusIcon memory={memory} missing={missing} size={dense ? 'xs' : 'sm'} />
        </Row>
        <Separator size="nano" />
        <Paragraph size={dense ? 'xs' : 'sm'} centered dense={dense}>
          {statusHeading}
        </Paragraph>
        <Paragraph size="xs" centered dense={dense}>
          <Ellipsis lineClamp={dense ? 4 : 10}>{statusBody}</Ellipsis>
        </Paragraph>
      </WhiteTheme>
    </LayoutBand>
  ) : null
}
