import React from 'react'
import { QuickGlanceOverlay, useOverlay, RadioGroup, Radio, Paragraph, Separator, Row, ActionChip } from '@fs/zion-ui'
import { useWatch } from '@fs/zion-form'
import { useTranslation } from 'react-i18next'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import { CHAT_PREF, setChatPreference } from '../services/chatUserPreferenceService/chatUserPreferenceService'
import useChatLog from '../hooks/useChatLog'
import { LOG_LEVEL } from '../global/chatLog'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import { useChatAttachmentsState } from '../providers/ChatAttachmentsProvider'

export default function ChatActionsChangeEnterButton({ isReply = false }) {
  const [t] = useTranslation()
  const overlay = useOverlay()
  const { log, track } = useChatLog({ component: '[ChatActionsChangeEnterButton]' })
  const chatDispatch = useChatDispatch()
  const { enterSendsMessage } = useChatState()
  const { message } = useWatch('message')
  const { pendingArtifactAttachments } = useChatAttachmentsState()
  const displayEnterSettingText =
    message?.length >= 3 || pendingArtifactAttachments.some((attachment) => attachment.isReply === isReply)
  const enterSettingText = enterSendsMessage
    ? t('chat.enter.sends-message', 'Enter Key Sends Message')
    : t('chat.enter.new-line', 'Enter Key Creates New Line')

  const toggleEnterButtonAction = async ({ target }) => {
    try {
      const newEnterBehavior = target.value === 'sendMessage'
      chatDispatch({
        type: CHAT_ACTIONS.ENTER_SENDS_MESSAGE,
        enterSendsMessage: newEnterBehavior,
      })
      await setChatPreference(CHAT_PREF.ENTER_SENDS_MESSAGE, newEnterBehavior)
      track({ link_name: `Chat:Change enter behavior to ${newEnterBehavior ? 'send a message' : 'start a new line'}` })
    } catch (err) {
      log({ msg: `setPreference (${CHAT_PREF.ENTER_SENDS_MESSAGE}) failed! - ${err}`, level: LOG_LEVEL.ERROR })
    }
  }

  return (
    <Row gutters="nano" guttersY="none">
      {!!displayEnterSettingText && (
        <ActionChip
          onClick={overlay.open}
          inline
          color="blue"
          emphasis="high"
          label={enterSettingText}
          description={t('chat.send-options', 'Send Options')}
        />
      )}

      <QuickGlanceOverlay {...overlay} placement="top" title={t('chat.send-options', 'Send Options')}>
        <RadioGroup orientation="vertical">
          <Radio
            checked={!!enterSendsMessage}
            label={
              <>
                <Paragraph size="sm">{t('chat.enter.sends-message', 'Enter Key Sends Message')}</Paragraph>
                <Separator size="hide" /> {/* workaround to remove margin-top from second Paragraph */}
                <Paragraph size="xs">{t('chat.enter-shift.new-line', 'Shift+Enter Key Creates New Line')}</Paragraph>
              </>
            }
            name="enterBehaviorChoice"
            value="sendMessage"
            onChange={(e) => {
              toggleEnterButtonAction({ target: e.target })
              overlay.close()
            }}
            wrapLabel
          />
          <Separator size="xxs" />
          <Radio
            checked={!enterSendsMessage}
            label={<Paragraph size="sm">{t('chat.enter.new-line', 'Enter Key Creates New Line')}</Paragraph>}
            name="enterBehaviorChoice"
            value="startNewLine"
            onChange={(e) => {
              toggleEnterButtonAction({ target: e.target })
              overlay.close()
            }}
            wrapLabel
          />
        </RadioGroup>
      </QuickGlanceOverlay>
    </Row>
  )
}
