import React, { useCallback, useEffect, useMemo } from 'react'
import { useSelection } from '@fs/zion-frontend-friends'
import { NoticeLoading } from '@fs/zion-icon'
import { PickerDialog, PickerDialogContent, PickerDialogImage } from '..'
import { usePickerDialog } from '../hooks'

const estimatedImageHeight = 283

const CoreSelector = ({
  headingText,
  photoData,
  as: TagName = PickerDialogImage,
  onClose,
  overlay,
  actionText,
  confirmationCallback,
  secondaryActionText,
  secondaryActionCallback,
  cancelOnClick,
  maxSelectable,
  loading,
  noOverlay,
  ...props
}) => {
  const { idSelectionStates, selectItem, deselectAll, changeItems } = useSelection({ items: photoData })
  const { isSelected, isSelectingEnabled } = usePickerDialog({ idSelectionStates, maxSelectable })

  const handleOnSelect = useCallback((id) => isSelectingEnabled(id) && selectItem(id), [isSelectingEnabled, selectItem])

  useEffect(() => {
    if (idSelectionStates.length && photoData.length) {
      changeItems(photoData)
    }
  }, [changeItems, idSelectionStates.length, photoData])

  const selectionInitialized = photoData.length
    ? Object.prototype.hasOwnProperty.call(idSelectionStates, photoData[0].id)
    : false

  useEffect(() => {
    if (!overlay.isOpen && overlay.transitioning) {
      onClose()
    }
  }, [onClose, overlay])

  const footerProps = useMemo(
    () => ({
      actionText,
      confirmationCallback,
      secondaryActionText,
      secondaryActionCallback,
      maxSelectable,
      idSelectionStates,
      cancelOnClick,
    }),
    [
      actionText,
      cancelOnClick,
      confirmationCallback,
      idSelectionStates,
      maxSelectable,
      secondaryActionCallback,
      secondaryActionText,
    ]
  )

  return (
    <PickerDialog
      headingText={headingText}
      clearSelected={deselectAll}
      overlay={overlay}
      footerProps={footerProps}
      noOverlay={noOverlay}
    >
      <PickerDialogContent itemHeightEstimate={estimatedImageHeight} idSelectionStates={idSelectionStates} {...props}>
        {(!selectionInitialized || loading) && <LoadingSpinner />}
        {selectionInitialized &&
          !loading &&
          photoData
            .filter(Boolean)
            .map((media) => (
              <TagName
                key={media.id}
                id={media.id}
                alt={media.alt}
                selectable={isSelectingEnabled(media.id)}
                src={media.src}
                selected={isSelected(media.id)}
                onSelect={handleOnSelect}
                media={media}
              />
            ))}
      </PickerDialogContent>
    </PickerDialog>
  )
}

function LoadingSpinner() {
  return (
    <div
      role="alert"
      data-testid="loading-spinner"
      aria-busy="true"
      style={{
        position: 'fixed',
        top: '50%',
        'inset-inline-start': '50%',
        transform: 'translate(-50%, -50%)',
      }}
    >
      <NoticeLoading size="lg" />
    </div>
  )
}

export default CoreSelector
