import React, { useEffect, useCallback, useState, useRef } from 'react'
import { useTranslation } from 'react-i18next'
import { useOverlay } from '@fs/zion-ui'
import { useEffectiveUser } from '@fs/zion-user'
import MemoryCard from '@fs/zion-memory-card'
import {
  getMemoriesForUserMPS,
  getAlbumsForUser,
  getAlbumMemoriesMPS,
  getFavoriteAlbums,
  getFavoriteMemoriesForUser,
} from '../services'
import EmptyStateMessageBlock from './shared/EmptyStateMessageBlock'
import BaseSelector from './BaseSelector'
import { useGallerySelector, useGallerySelectorApi } from './useGallerySelector'
import { memoryCollectionKeys } from './GallerySelectorContext'
import { galleryUtils } from '../utils'

const noOp = () => {}

const CardItem = ({ id, selected, onSelect, selectable = true, media }) => {
  return (
    <MemoryCard
      id={id}
      checked={selected}
      selectable={selectable}
      onClick={(e) => selectable && onSelect(id, e.shiftKey)}
      memory={media}
    />
  )
}

const memoryCallParams = {
  artifactArchivedState: 'NON_ARCHIVED',
  includePortraits: false,
  includeAssociatedArtifacts: true,
  includeContactName: true,
  includeCiscData: true,
  profile: 'skeleton',
  includeDatesPlaces: true,
}

const useDebounce = (value, delay) => {
  const [debouncedValue, setDebouncedValue] = useState(value)

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value)
    }, delay)

    return () => {
      clearTimeout(handler)
    }
  }, [delay, value])

  return debouncedValue
}

/*
 * --- Photo breakdown ---
 * currentPhotos: The photos from the current collection (could be an album)
 * displayedPhotos: The photos from the current collection that may be filtered
 */
const GallerySelectorCore = ({
  maxSelectable,
  confirmationCallback,
  secondaryActionCallback,
  onClose = noOp,
  emptyState,
  openerRef = null,
  acceptedTypes = [],
  excludedMemIds = [],
  noOverlay = false,
  publicOnly = false,
  ...props
}) => {
  const isCurrent = useRef(true)
  const { cisId } = useEffectiveUser()
  const pickerOverlay = useOverlay()
  const [t] = useTranslation()

  const {
    allowedMediaTypes,
    dialogNavFolders,
    currentPhotos,
    displayedPhotos,
    isFetching,
    memoryCollections,
    searchVal,
  } = useGallerySelector()
  const { setFiltered, init, reset, setSearchValue, setIsFetching, updateCurrentPhotos } = useGallerySelectorApi()

  const arrangeOptions = [
    { value: 'newest_added', label: t('picker-dialog.selector.gallery.arrange.newest', 'Newest Added') },
    { value: 'title_a-z', label: t('picker-dialog.selector.gallery.arrange.title-a-z', 'Title A-Z') },
    { value: 'no_title', label: t('picker-dialog.selector.gallery.arrange.no-title', 'No Title') },
    { value: 'not_tagged', label: t('picker-dialog.selector.gallery.arrange.not-tagged', 'Not Tagged') },
  ]

  const fetchGalleryData = useCallback(async () => {
    if (!pickerOverlay.isOpen && !pickerOverlay.transitioning) {
      try {
        setIsFetching(true)
        const queryParams = {
          ...memoryCallParams,
          _: Date.now(),
        }
        pickerOverlay.open()
        const [albumsResp, bookmarkedAlbumsResp, photosResp] = await Promise.allSettled([
          getAlbumsForUser({ cisId }),
          getFavoriteAlbums({ cisId }),
          getMemoriesForUserMPS({ cisId, queryParams }),
        ])
        init({
          albumsResp: albumsResp.value,
          bookmarkedAlbumsResp: bookmarkedAlbumsResp.value,
          photosResp: photosResp.value,
          acceptedTypes,
          excludedMemIds,
        })
      } catch (error) {
        console.error(error)
        pickerOverlay.close()
      } finally {
        setIsFetching(false)
      }
    }
  }, [pickerOverlay, setIsFetching, cisId, init, acceptedTypes, excludedMemIds])

  const handleConfirmationCallback = useCallback(
    (selectedIds) => {
      const selectedItems = selectedIds?.map((id) => currentPhotos?.find((photo) => photo?.id?.toString() === id))
      confirmationCallback(selectedItems)
    },
    [confirmationCallback, currentPhotos]
  )

  const handleSecondaryActionCallback = useCallback(
    (selectedIds) => {
      if (secondaryActionCallback) {
        const selectedItems = selectedIds?.map((id) => currentPhotos?.find((photo) => photo?.id?.toString() === id))
        secondaryActionCallback(selectedItems)
      }
    },
    [currentPhotos, secondaryActionCallback]
  )

  const searchOnChange = useCallback((value) => setSearchValue(value), [setSearchValue])

  const [arrangeValue, setArrangeValue] = useState('newest_added')

  const debouncedSearchVal = useDebounce(searchVal, 200)

  // Combined effect that applies both search and arrange filters
  useEffect(() => {
    let filtered = [...currentPhotos]

    if (publicOnly) {
      filtered = filtered.filter((photo) => photo?.visibility !== 'PRIVATE')
    }

    // Apply search filter
    if (debouncedSearchVal) {
      filtered = filtered.filter((photo) => {
        const { originalFilename, title, description } = photo
        const regEx = new RegExp(`${debouncedSearchVal}`, 'gi')
        const matchesSearch = regEx.test(`${originalFilename} ${title} ${description}`)
        return matchesSearch
      })
    }

    switch (arrangeValue) {
      case 'newest_added':
        filtered = filtered.sort((a, b) => b.uploadDatetime - a.uploadDatetime)
        break
      case 'title_a-z':
        filtered = filtered
          .filter((photo) => Boolean(photo.title))
          .sort((a, b) => (a.title.toLowerCase() < b.title.toLowerCase() ? -1 : 1))
        break
      case 'no_title':
        filtered = filtered.filter((photo) => !photo.title)
        break
      case 'not_tagged':
        filtered = filtered.filter((photo) => !photo.photoTagCount)
        break
      default:
        break
    }

    setFiltered(filtered)
  }, [currentPhotos, debouncedSearchVal, arrangeValue, publicOnly, setFiltered])

  const arrangeOnChange = useCallback((value) => {
    setArrangeValue(value)
  }, [])

  const handleFolderSelection = useCallback(
    async (folder) => {
      switch (folder.id) {
        case memoryCollectionKeys.myMemories:
          updateCurrentPhotos(memoryCollections?.[memoryCollectionKeys.myMemories], memoryCollectionKeys.myMemories)
          break
        case memoryCollectionKeys.myArchive: {
          const queryParams = {
            ...memoryCallParams,
            artifactArchivedState: 'ARCHIVED',
            _: Date.now(),
          }
          let structuredPhotos = []

          if (memoryCollections?.[memoryCollectionKeys.myArchive]?.length > 0) {
            structuredPhotos = memoryCollections?.[memoryCollectionKeys.myArchive]
          } else {
            const photosResp = await getMemoriesForUserMPS({ cisId, queryParams })
            structuredPhotos = galleryUtils.structurePhotoData(
              photosResp?.data?.artifact ?? [],
              allowedMediaTypes,
              excludedMemIds
            )
          }

          updateCurrentPhotos(structuredPhotos, memoryCollectionKeys.myArchive)
          break
        }
        case memoryCollectionKeys.bookmarkedMemories: {
          const queryParams = {
            ...memoryCallParams,
            _: Date.now(),
          }
          let structuredPhotos = []

          if (memoryCollections?.[memoryCollectionKeys?.bookmarkedMemories]?.length > 0) {
            structuredPhotos = memoryCollections?.[memoryCollectionKeys?.bookmarkedMemories]
          } else {
            const photosResp = await getFavoriteMemoriesForUser({ cisId, queryParams })
            structuredPhotos = galleryUtils.structurePhotoData(
              photosResp?.data?.artifact ?? [],
              allowedMediaTypes,
              excludedMemIds
            )
          }

          updateCurrentPhotos(structuredPhotos, memoryCollectionKeys.bookmarkedMemories)
          break
        }

        default:
          try {
            const queryParams = {
              ...memoryCallParams,
              _: Date.now(),
            }
            let structuredPhotos = []

            if (memoryCollections?.[folder.id]?.length > 0) {
              structuredPhotos = memoryCollections?.[folder.id]
            } else {
              const photosResp = await getAlbumMemoriesMPS({ albumId: folder.id, queryParams })
              structuredPhotos = galleryUtils.structurePhotoData(
                photosResp?.data?.artifactList?.artifact ?? [],
                allowedMediaTypes,
                excludedMemIds
              )
            }

            updateCurrentPhotos(structuredPhotos, folder.id)
          } catch (error) {
            console.error(error)
          }
          break
      }
    },
    [allowedMediaTypes, cisId, excludedMemIds, memoryCollections, updateCurrentPhotos]
  )

  const handleOnClose = useCallback(() => {
    reset()
    onClose()
  }, [onClose, reset])

  useEffect(() => {
    if (noOverlay) {
      cisId && fetchGalleryData()
    } else if (openerRef) {
      openerRef.current = () => {
        cisId && fetchGalleryData()
      }
    }
  }, [cisId, fetchGalleryData, noOverlay, openerRef])

  useEffect(() => {
    isCurrent.current = true
    return () => {
      isCurrent.current = false
    }
  }, [])

  return (
    <BaseSelector
      headingText={t('picker-dialog.selector.heading.gallery', 'Select memories to import from your Gallery')}
      overlay={pickerOverlay}
      photoData={displayedPhotos}
      maxSelectable={maxSelectable}
      isFetching={isFetching}
      showMainNavHeader={false}
      dialogNavStructure={dialogNavFolders}
      folderSelectionCallback={handleFolderSelection}
      confirmationCallback={handleConfirmationCallback}
      secondaryActionCallback={handleSecondaryActionCallback}
      as={CardItem}
      onClose={handleOnClose}
      emptyState={
        emptyState || {
          messageBlock: <EmptyStateMessageBlock />,
        }
      }
      preContentRowProps={{
        searchOnChange,
        arrangeOnChange,
        arrangeOptions,
      }}
      noOverlay={noOverlay}
      {...props}
    />
  )
}

export default GallerySelectorCore
