import { getSessionId } from '@fs/zion-session'
import { i18n } from '@fs/zion-locale'
import { uploadFiles, CHAT_SCREENING_STATE } from '../services/memories/artifactStoreService'
import { actionTypes } from '../providers/ChatAttachmentsProvider'

const formatAudioWidth = (seconds) => {
  // MM:SS
  const numSeconds = parseInt(seconds, 10)
  const minutes = Math.floor(numSeconds / 60)
  const secs = numSeconds % 60
  return `${minutes}:${secs}`
}

const tilePropCache = {}

export const CHAT_ATTACHMENT_SERVICE_TYPE = {
  ABOUT: 'ABOUT',
  MEMORY_ARTIFACT: 'MEMORY_ARTIFACT',
  ARTIFACT_STORE: 'ARTIFACT_STORE',
}

const categoryToType = {
  AUDIO: 'audio',
  PDF: 'document',
  IMAGE: 'photo',
  TEXT: 'story',
}

export const getCanShowImage = ({ screeningState, fromUser }) => {
  return (
    screeningState === CHAT_SCREENING_STATE.APPROVED || (screeningState !== CHAT_SCREENING_STATE.RESTRICTED && fromUser)
  )
}

export const getScreeningStateLabel = (screeningState) => {
  if (screeningState === CHAT_SCREENING_STATE.APPROVED) {
    return i18n.t('chat.chat-attachment-accepted', 'Accepted')
  }
  if (screeningState === CHAT_SCREENING_STATE.RESTRICTED) {
    return i18n.t('chat.chat-attachment-rejected.label', 'Rejected')
  }
  return i18n.t('chat.chat-attachment-reviewing.label', 'Reviewing...')
}
export const uploadToTileProps = (artifactObj) => {
  if (!artifactObj) {
    return null
  }
  if (artifactObj?.filename && tilePropCache[artifactObj.filename]) {
    return tilePropCache[artifactObj.filename]
  }
  const thumbnailImg = artifactObj.thumb200sUri
  if (!thumbnailImg) {
    return null
  }
  const tileProps = {
    type: 'photo',
    id: artifactObj.filename,
    title: artifactObj.title || i18n.t('chat.chat-image-attachment-caption', 'View Image'),
  }
  const sessionId = getSessionId()
  tileProps.image = thumbnailImg?.includes('?')
    ? `${thumbnailImg}&sessionId=${sessionId}`
    : `${thumbnailImg}?sessionId=${sessionId}`

  if (artifactObj?.artifactId) {
    tilePropCache[artifactObj.artifactId] = tileProps
  }
  return tileProps
}

export const uploadMemoryToTileProps = (artifactObj) => {
  if (!artifactObj) {
    return null
  }
  if (artifactObj?.id && tilePropCache[artifactObj.id]) {
    return tilePropCache[artifactObj.id]
  }
  const sessionId = getSessionId()
  const type = categoryToType[artifactObj.category] || categoryToType[artifactObj.contentCategory] || 'story'
  const tileProps = {
    type,
    id: artifactObj.id,
    title: artifactObj.title,
  }
  switch (type) {
    case 'photo':
    case 'document': {
      const thumbnailImg = artifactObj.thumbUrl
      tileProps.image = thumbnailImg.includes('?')
        ? `${thumbnailImg}&sessionId=${sessionId}`
        : `${thumbnailImg}?sessionId=${sessionId}`
      break
    }
    case 'audio': {
      tileProps.caption = artifactObj.description
      tileProps.duration = artifactObj.width ? formatAudioWidth(artifactObj.width) : ''
      break
    }
    case 'story':
    default:
      tileProps.description = artifactObj.description
      break
  }
  if (artifactObj?.id) tilePropCache[artifactObj.id] = tileProps
  return tileProps
}

export async function uploadFilesFromFileSelectorInput({
  fileInputRef,
  showStatusOverlay,
  pendingArtifactAttachments,
  chatAttachmentsDispatch,
  isReply,
}) {
  try {
    const files = Array.from(fileInputRef?.current?.files)
    const { validationErrorString, uploadedFiles } = await uploadFiles({ files })
    if (validationErrorString) {
      showStatusOverlay(validationErrorString)
    }
    if (uploadedFiles.length > 0) {
      const newAttachments = [...pendingArtifactAttachments]
      uploadedFiles.forEach(({ id, filename, mediaType }) => {
        if (id && !newAttachments.find((artifact) => artifact.id === id)) {
          newAttachments.push({
            id,
            serviceType: CHAT_ATTACHMENT_SERVICE_TYPE.ARTIFACT_STORE,
            filename,
            mediaType,
            isReply,
          })
        }
      })
      chatAttachmentsDispatch({
        type: actionTypes.SET_PENDING_ARTIFACT_ATTACHMENTS,
        pendingArtifactAttachments: newAttachments,
      })
    }
  } finally {
    fileInputRef.current.value = ''
  }
}

export async function updateOnGalleryConfirmation({
  selectedMemories,
  pendingArtifactAttachments,
  chatAttachmentsDispatch,
  overlay,
  targetRef,
  isReply,
}) {
  const newAttachments = [...pendingArtifactAttachments]

  selectedMemories.forEach((memory) => {
    if (
      memory?.id &&
      memory?.visibility !== 'PRIVATE' &&
      !newAttachments.find((artifact) => artifact.id === memory.id)
    ) {
      newAttachments.push({
        ...memory,
        serviceType: CHAT_ATTACHMENT_SERVICE_TYPE.MEMORY_ARTIFACT,
        isReply,
      })
    }
    if (memory?.visibility === 'PRIVATE') {
      overlay.open({ target: targetRef.current })
    }
  })
  chatAttachmentsDispatch({
    type: actionTypes.SET_PENDING_ARTIFACT_ATTACHMENTS,
    pendingArtifactAttachments: newAttachments,
  })
}
