const isNumber = (value) => typeof value === 'number'

const calculateWindowPosition = (window, width, height) => {
  const windowPosition = {}

  /** Calculate the top and left params to center the social media window within the
   * currently opened browser window. */
  const wLeft = window.screenLeft ? window.screenLeft : window.screenX
  const wTop = window.screenTop ? window.screenTop : window.screenY
  windowPosition.left = wLeft + window.innerWidth / 2 - width / 2
  windowPosition.top = wTop + window.innerHeight / 2 - height / 2

  return windowPosition
}

const calculateWindowWidth = (screen, width) => (width > screen.width ? screen.width : width)

export default { calculateWindowPosition, calculateWindowWidth, isNumber }
