import React from 'react'
import { css } from '@linaria/core'
import { useChatState } from '../providers/ChatStateProvider'
import ChatJoinEmbeddedChatButton from './ChatJoinEmbeddedChatButton'
import ChatActions from './ChatActions'
import { CHAT_MESSAGE_TYPE } from '../helpers/stream/streamChatHelper'

const chatActionsCss = css`
  min-height: 0;
  overflow-y: auto;
  max-width: 550px;
  margin: auto;
  width: 100%;
`

export default function ChatActionsHolder({
  isReply,
  messageRef,
  onSend,
  recipientLabel,
  typingLabel,
  isSending,
  showSpinner,
  isThread,
  thread,
}) {
  const { client, isEmbedded, restrictToManagedGroups, parentMessage } = useChatState()
  if (isEmbedded && restrictToManagedGroups) {
    return null
  }

  if (isEmbedded && client?.anonymous) {
    return (
      <div className={chatActionsCss}>
        <ChatJoinEmbeddedChatButton />
      </div>
    )
  }
  if (!isThread || parentMessage?.type !== CHAT_MESSAGE_TYPE.DELETED) {
    return (
      <div className={chatActionsCss}>
        <ChatActions
          isReply={isReply}
          messageRef={messageRef}
          onSend={onSend}
          recipientLabel={recipientLabel}
          typingLabel={typingLabel}
          isSending={isSending}
          showSpinner={showSpinner}
          thread={thread}
        />
      </div>
    )
  }

  return null
}
