import React, { forwardRef, useCallback, useRef } from 'react'
import PropTypes from 'prop-types'
import { ObserverRootContext, useObserver, Observable } from '@fs/zion-frontend-friends'

const PaginationTrigger = ({ paginationCallback, resizeCallback }) => {
  const paginationTriggerRef = useRef()
  const paginationCallbackMiddleMan = useCallback(
    (entry) => {
      if (entry.isIntersecting) paginationCallback()
    },
    [paginationCallback]
  )

  useObserver(paginationTriggerRef, paginationCallbackMiddleMan, resizeCallback)

  return <div ref={paginationTriggerRef} />
}

const ScrollPaginator = ({ rootMargin = '0px', paginationCallback, resizeCallback = () => {} }, ref) => {
  return (
    <ObserverRootContext.Provider value={ref}>
      <Observable rootMargin={rootMargin}>
        <PaginationTrigger paginationCallback={paginationCallback} resizeCallback={resizeCallback} />
      </Observable>
    </ObserverRootContext.Provider>
  )
}

export default forwardRef(ScrollPaginator)

ScrollPaginator.propTypes = {
  /** Content to show above the Content section (not scrolled with content) */
  paginationCallback: PropTypes.func.isRequired,
  /** Content to show above the Content section (not scrolled with content) */
  resizeCallback: PropTypes.func,
  /** Content to show above the Content section (not scrolled with content) */
  rootMargin: PropTypes.string,
}
