import React from 'react'
import { Divider, ListItem } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { format } from '@fs/zion-locale/date-fns'
import { useParams } from '@fs/zion-router'
import { useChatState } from '../providers/ChatStateProvider'
import { getChannelName } from '../helpers/stream/streamChatHelper'
import { isPubliclyViewableChannel, isVendorChannel } from '../services/fsChat/fsChatService'

export default function NoResultsText() {
  const [t] = useTranslation()
  const { cid } = useParams()
  const { client, channels } = useChatState()
  const channel = channels?.find((c) => c.cid === cid || `${c.type}:${c.cid}` === cid)
  let noResultsText = ''
  if (isVendorChannel(channel)) {
    noResultsText = t(
      'chat.vendor-chat-no-messages-yet.heading',
      'Hello! Welcome to this public chat with {vendorName}. Ask your question here, and we’ll be happy to assist you.',
      { vendorName: channel?.data?.name }
    )
  } else if (isPubliclyViewableChannel(channel)) {
    noResultsText = t(
      'chat.public-chat-no-messages-yet.heading',
      'Hello and welcome to this Public Chat! Join an existing conversation or start a new one.'
    )
  } else {
    noResultsText = t(
      'chat.no-messages-yet.heading',
      'Welcome to the "{channelName}" chat. No messages have been posted to this chat yet.',
      { channelName: getChannelName({ channel, excludeUserId: client?.userID }) }
    )
  }
  return (
    <>
      <Divider label={format(Date.now(), 'PPP')} />
      <ListItem
        primaryText={<i>{noResultsText}</i>}
        endElement={<ListItem.MetaText text={format(Date.now(), 'p')} />}
      />
    </>
  )
}
