import { actionTypes } from '../providers/ChatAttachmentsProvider'
import { useChatState } from '../providers/ChatStateProvider'
import { CHAT_ATTACHMENT_SERVICE_TYPE } from './chatAttachmentHelper'
import { LOG_LEVEL } from '../global/chatLog'

export function useOnKeyDown({ disabled, onSubmit: internalOnSubmit }) {
  const { enterSendsMessage } = useChatState()
  return (e) => {
    // NOTE: for languages with composing characters (Korean, Japanese, etc), wait until the character is fully composed.
    if (e.isComposing || e.keyCode === 229) return

    // Enter handling — Shift+Enter always creates a new line regardless of mode
    if (e.key === 'Enter' && !e.shiftKey && enterSendsMessage) {
      // Prevent default, so it doesn't add a newline to the input value
      e.preventDefault()
      if (!disabled) {
        internalOnSubmit(e)
      }
    }
  }
}

export async function onChatActionsSubmit({
  onSend,
  pendingArtifactAttachments,
  pendingAboutAttachment,
  chatAttachmentsDispatch,
  getFormValues,
  resetForm,
  deleteDraft,
  log,
}) {
  try {
    const attachments = pendingArtifactAttachments.map(({ id, filename, serviceType, mediaType, isReply }) => ({
      id: id.toString(),
      filename,
      serviceType,
      mediaType,
      // type property is needed to fix an issue with editing messages with attachments on iOS
      type: 'fs-attachment',
      isReply,
    }))
    if (pendingAboutAttachment?.link || pendingAboutAttachment?.text) {
      attachments.push({
        id: pendingAboutAttachment?.link,
        filename: pendingAboutAttachment?.link,
        serviceType: CHAT_ATTACHMENT_SERVICE_TYPE.ABOUT,
        data: pendingAboutAttachment?.text,
      })
    }
    chatAttachmentsDispatch({ type: actionTypes.CLEAR_ALL_PENDING_ATTACHMENTS })

    const messageToSend = getFormValues().message.trim()

    await onSend(messageToSend, attachments)

    resetForm()
    deleteDraft()
  } catch (err) {
    log({ msg: `Error sending message: ${err}`, level: LOG_LEVEL.ERROR })
  }
}
