import React from 'react'
import { useTranslation } from 'react-i18next'
import { ActionChip } from '@fs/zion-ui'

export default function Tombstone({ tombstone }) {
  const [t] = useTranslation()

  const label = t('memory-card.tombstone.label-plural', '{count, plural, one {# day} other {# days}}', {
    count: tombstone,
  })
  const description = t(
    'memory-card.tombstone.description-plural',
    '{count, plural, one {This memory will be permanently deleted in # day.} other {This memory will be permanently deleted in # days.}}',
    { count: tombstone }
  )

  return <ActionChip label={label} description={description} color="red" emphasis="high" />
}
