import axios from '@fs/zion-axios'
import { serviceUtils } from '../utils'

const baseUrl = '/service/memories/presentation'

/** */
const getAlbumMemoriesMPS = ({ albumId, queryParams }) =>
  axios.get(`${baseUrl}/albums/${albumId}/artifacts${serviceUtils.getQueryString(queryParams)}`)

// -------------------------------
// ---- MPS PATRONS API CALLS ----
// -------------------------------
const patronsUrl = `${baseUrl}/patrons`

/** */
const getMemoriesForUserMPS = ({ cisId, queryParams }) =>
  axios.get(`${patronsUrl}/${cisId}/artifacts${serviceUtils.getQueryString(queryParams)}`)

export { getAlbumMemoriesMPS, getMemoriesForUserMPS }
