import React from 'react'
import { Button, MarginBox, Row } from '@fs/zion-ui'
import { useParams } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import { useChatState, useChatDispatch } from '../providers/ChatStateProvider'
import { connectChat } from '../chat-reconnect/ChatReconnectPage'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import useChatLog from '../hooks/useChatLog'
import { LOG_LEVEL } from '../global/chatLog'
import { addOrRemoveChannelMembers } from '../hooks/channelHooks'
import useHandleChatErrors from '../hooks/useHandleChatErrors'

// placeholder for ChatActions when connected anonymously
// Should only be used with embeddedChat
export default function ChatJoinEmbeddedChatButton() {
  const { client } = useChatState()
  const chatDispatch = useChatDispatch()
  const { cid } = useParams()
  const [t] = useTranslation()
  const { log, track } = useChatLog({ component: '[ChatJoinEmbeddedChatButton]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  // reset the chat state and connect as a regular user
  const handleJoinChannel = async () => {
    try {
      // reset the chat state and connect as a regular user
      log({ msg: 'Chat Join Embedded Chat Button Clicked', level: LOG_LEVEL.LOG })
      track({ link_name: `CHAT:Join embedded chat button clicked` }, { chatChannelId: cid })
      chatDispatch({ type: CHAT_ACTIONS.LOGOUT, overrides: ['isEmbedded', 'currentCid', 'threadChannel'] })
      await client?.disconnectUser()
      await connectChat({ chatDispatch, isEmbedded: true, cid })
    } catch (err) {
      handleBasicError(err, {
        moreInfo: `Problem joining embedded chat. ChannelId ${cid}`,
      })
    }
    try {
      await addOrRemoveChannelMembers({ cid, cisIdsToAdd: [client?.user?.fs_cis_id], log })
    } catch (err) {
      log({ msg: `Error adding user to channel`, level: LOG_LEVEL.ERROR })
    }
  }
  return (
    <MarginBox marginY="xs" data-testid="chat-join-embedded-chat-button">
      <Row alignX="center">
        <Button emphasis="high" onClick={handleJoinChannel}>
          {t('chat.join', 'Join Chat')}
        </Button>
      </Row>
    </MarginBox>
  )
}
