import React from 'react'
import { format } from '@fs/zion-locale/date-fns'
import { Tag, Row, Separator } from '@fs/zion-ui'
import { i18n } from '@fs/zion-locale'

export default function ChatTimestamp({ date }) {
  const dateText = format(new Date(date), 'PPPP', { locale: i18n.language })
  return (
    <>
      <Row alignX="center">
        <Tag text={dateText} color="gray" />
      </Row>
      <Separator size="xxs" />
    </>
  )
}
