import React, { memo, useState, useRef, useCallback, useEffect } from 'react'
import { css } from '@linaria/core'
import PropTypes from 'prop-types'
import { Arrow, ArrowSwap, MenuSearch, NoticeLoading } from '@fs/zion-icon'
import { boolAttr } from '@fs/zion-frontend-friends'
import { colors, TextField, Select, useContainerWidth, FlowGrid, IconButton, Bleed } from '@fs/zion-ui'
import { ShadowScroller, ResponsiveProvider, GridStart } from '@fs/zion-ui/quarks-authorized-use-only'
import { useTranslation } from 'react-i18next'
import SideNav from './SideNav'
import ScrollPaginator from './ScrollPaginator'
import emptyStateGraphic from './emptyStateGraphic.svg'

const contentWrapperCss = css`
  /*Fixes a current known frontier style ordering */
  &[bleed-overwrite] {
    flex-direction: row;
  }
  display: flex;
  position: relative;
  overflow: hidden;
  max-width: inherit;
  max-height: 60vh;
  &[is-mobile] {
    flex-grow: 1;
    width: 100vw;
    max-height: 85vh;
  }
`
const contentCss = css`
  display: flex;
  flex-direction: column;
  flex-grow: 2;
  max-width: 100vw;
  background-color: ${colors.gray03};
  z-index: 0;
  min-height: 60vh;
`
const preContentCss = css`
  position: sticky;
  top: 0;
  inset-inline-start: 0;
  inset-inline-end: 0;
  backdrop-filter: blur(4px);
  z-index: 3;
  padding: 8px 12px;

  &::before {
    content: '';
    background-color: ${colors.gray03};
    opacity: 0.85;
    position: absolute;
    top: 0;
    inset-inline-start: 0;
    inset-inline-end: 0;
    bottom: 0;
  }

  &[adjust-height] {
    animation: grow 300ms ease-in-out forwards;
  }
  &:not([adjust-height]) {
    animation: shrink 400ms ease-in-out forwards;
  }
  @keyframes grow {
    0% {
      height: 60px;
    }
    100% {
      height: 104px;
    }
  }
  @keyframes shrink {
    0% {
      height: 104px;
    }
    100% {
      height: 60px;
    }
  }
`
const returnBtnCss = css`
  display: inline-flex;
  align-items: center;
  z-index: 1;
  & span {
    /* matching padding of IconButton to make text align properly*/
    padding: 8px 12px;
  }
`
const mobilePreContentCss = css`
  display: flex;
  flex-direction: row;
  justify-content: space-between;
`
const iconRowCss = css`
  display: inline-flex;
  z-index: 3;
  & > button:first-of-type {
    margin-inline-end: 8px;
  }
`
const RowCss = css`
  display: inline-flex;
  width: 100%;
  &:not([is-mobile]) > div:first-of-type {
    margin-inline-end: 12px;
  }
  & > div:last-of-type {
    flex-grow: 2;
    min-width: unset;
    max-width: unset;
  }
  &[is-mobile] {
    min-width: 258px;
    margin-top: 8px;
  }
  &[is-mobile][show-select],
  &[is-mobile][show-search] {
    animation: slideIn 400ms ease-in-out forwards;
  }
  &[is-mobile]:not([show-search]):not([show-select]) {
    animation: slideOut 300ms ease-in-out forwards;
  }
  @keyframes slideIn {
    0% {
      opacity: 0;
      transform: translateY(-50%);
    }
    30% {
      opacity: 0;
    }
    100% {
      opacity: 1;
      transform: translateY(0%);
    }
  }
  @keyframes slideOut {
    0% {
      opacity: 1;
      transform: translateY(0%);
    }
    100% {
      opacity: 0;
      transform: translateY(-50%);
    }
  }
`
const gridWrapperCss = css`
  & > div {
    margin: 0;
  }
`
const innerContentCss = css`
  max-width: 1325px;
  padding: 8px 12px;
`
const emptyContainerCss = css`
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  margin-top: 3rem;
`
const center = css`
  height: 75vh;
  display: flex;
  align-items: center;
  justify-content: center;
`

const MemoizedDialogContent = memo(function MemoizedDialogContent({ itemHeightEstimate, children }) {
  const atWidth = useContainerWidth()
  return (
    <div className={gridWrapperCss}>
      <FlowGrid
        itemHeightEstimate={itemHeightEstimate}
        columnCount={atWidth({ default: 1, xs: 2, md: 3, lg: 4, xxl: 6 })}
        gutters="xxs"
        keepVisible
      >
        {children}
      </FlowGrid>
    </div>
  )
})

const MemoizedSelect = memo(function MemoizedSelect({ arrangeOptions, arrangeOnChange, isMobile, selectedFolder }) {
  const [selectValue, setSelectValue] = useState('')
  const [t] = useTranslation()

  useEffect(() => {
    setSelectValue('')
  }, [selectedFolder])

  return (
    <Select
      options={arrangeOptions}
      onChange={(e) => {
        setSelectValue(e.target.value)
        arrangeOnChange(e.target.value)
      }}
      value={selectValue}
      placeholder={t('picker-dialog.arrange.label', 'Arrange')}
      autoWidth={!isMobile}
      dense
    />
  )
})

const MemoizedSearch = memo(function MemoizedSearch({ searchOnEnter, searchOnChange, selectedFolder }) {
  const [searchVal, setSearchVal] = useState()
  const [t] = useTranslation()

  useEffect(() => {
    setSearchVal('')
  }, [selectedFolder])

  return (
    <TextField
      onEnterKey={(e) => {
        searchOnEnter?.(e.target.value)
      }}
      Icon={MenuSearch}
      clearable
      onChange={(e) => {
        setSearchVal(e.target.value)
        searchOnChange(e.target.value)
      }}
      value={searchVal}
      autoComplete="on"
      placeholder={t('picker-dialog.search.label', 'Search')}
      onClear={() => {
        setSearchVal('')
        searchOnChange('')
      }}
      dense
    />
  )
})

const PickerDialogContent = ({
  // navProps
  dialogNavStructure = { key: [] },
  folderSelectionCallback = () => {},
  showMainNavHeader = true,
  isFetching,
  itemHeightEstimate = 250,
  paginationCallback = () => {},
  preContentRowProps: { searchOnChange, searchOnEnter, arrangeOnChange, arrangeOptions } = {},
  emptyState,
  children,
}) => {
  const [t] = useTranslation()
  const [collapsedNav, setCollapsedNav] = useState(false)
  const atWidth = useContainerWidth()

  const isMobile = atWidth({
    default: true,
    md: false,
  })
  const [selectedFolder, setSelectedFolder] = useState(Object.values(dialogNavStructure)[0][0]?.name)
  const [showSearch, setShowSearch] = useState(false)
  const [showSelect, setShowSelect] = useState(false)
  const [adjustHeight, setAdjustHeight] = useState(false)

  const middleManFolderCallback = useCallback(
    (folder) => {
      if (isMobile) setCollapsedNav(true)
      setSelectedFolder(folder.name)
      folderSelectionCallback(folder)
    },
    [isMobile, folderSelectionCallback, setCollapsedNav]
  )

  const handleSelectClick = useCallback(() => {
    if (showSearch) {
      setAdjustHeight(false)
      setTimeout(() => setShowSearch(false), 100)
      setTimeout(() => {
        setAdjustHeight(true)
        setShowSelect(true)
      }, 400)
    } else if (showSelect) {
      setAdjustHeight(false)
      setTimeout(() => setShowSelect(false), 200)
    } else {
      setAdjustHeight(true)
      setTimeout(() => setShowSelect(true), 200)
    }
  }, [showSearch, showSelect])

  const handleSearchClick = useCallback(() => {
    if (showSelect) {
      setAdjustHeight(false)
      setTimeout(() => setShowSelect(false), 100)
      setTimeout(() => {
        setAdjustHeight(true)
        setShowSearch(true)
      }, 300)
    } else if (showSearch) {
      setAdjustHeight(false)
      setTimeout(() => setShowSearch(false), 200)
    } else {
      setAdjustHeight(true)
      setTimeout(() => setShowSearch(true), 200)
    }
  }, [showSearch, showSelect])

  const scrollableRef = useRef()

  const hasSearchOrArrange = Boolean(arrangeOptions?.length || searchOnChange)
  const isEmpty = !children[1]

  if (isFetching) {
    return (
      <div className={center}>
        <NoticeLoading size="lg" />
      </div>
    )
  }

  return (
    <>
      {/* bleed-overwrite fixes a current known frontier style ordering bug. Without this, the MemoryCards don't display when not on mobile size */}
      <Bleed all className={contentWrapperCss} bleed-overwrite={boolAttr(!isMobile)} is-mobile={boolAttr(isMobile)}>
        {Object.values(dialogNavStructure)[0].length > 0 && (
          <SideNav
            folderSelectionCallback={middleManFolderCallback}
            dialogNavStructure={dialogNavStructure}
            showMainNavHeader={showMainNavHeader}
            collapsedNav={collapsedNav}
            isMobile={isMobile}
          />
        )}
        <ResponsiveProvider className={contentCss}>
          <GridStart as={ShadowScroller} ref={scrollableRef}>
            {(hasSearchOrArrange || isMobile) && (
              <div
                className={preContentCss}
                show-select={boolAttr(showSelect)}
                show-search={boolAttr(showSearch)}
                adjust-height={boolAttr(adjustHeight)}
              >
                {isMobile && (
                  <div className={mobilePreContentCss}>
                    {selectedFolder && (
                      <div className={returnBtnCss}>
                        <IconButton
                          title={selectedFolder}
                          Icon={Arrow}
                          iconDirection="backward"
                          onClick={() => setCollapsedNav(false)}
                        />
                        <span>{selectedFolder}</span>
                      </div>
                    )}
                    {hasSearchOrArrange && (
                      <div className={iconRowCss}>
                        {arrangeOptions?.length && (
                          <IconButton
                            title={t('picker-dialog.arrange.label', 'Arrange')}
                            Icon={ArrowSwap}
                            iconDirection="down"
                            onClick={handleSelectClick}
                          />
                        )}
                        {searchOnChange && (
                          <IconButton
                            title={t('picker-dialog.search.label', 'Search')}
                            Icon={MenuSearch}
                            onClick={handleSearchClick}
                          />
                        )}
                      </div>
                    )}
                  </div>
                )}
                {hasSearchOrArrange && (
                  <div
                    className={RowCss}
                    is-mobile={boolAttr(isMobile)}
                    show-select={boolAttr(showSelect)}
                    show-search={boolAttr(showSearch)}
                  >
                    {((isMobile && showSelect) || (!isMobile && arrangeOptions?.length)) && (
                      <MemoizedSelect
                        arrangeOptions={arrangeOptions}
                        arrangeOnChange={arrangeOnChange}
                        isMobile={isMobile}
                        selectedFolder={selectedFolder}
                      />
                    )}
                    {((isMobile && showSearch) || (!isMobile && searchOnChange)) && (
                      <MemoizedSearch
                        searchOnEnter={searchOnEnter}
                        searchOnChange={searchOnChange}
                        selectedFolder={selectedFolder}
                      />
                    )}
                  </div>
                )}
              </div>
            )}
            {isEmpty ? (
              <div style={{ minHeight: 'inherit' }}>
                <div className={emptyContainerCss}>
                  <img
                    src={emptyStateGraphic}
                    alt={t('picker-dialog.empty.image.alt', 'No content available')}
                    style={{ maxWidth: '90%', marginBottom: '2rem' }}
                  />
                  {emptyState.messageBlock}
                  {emptyState?.actionBlock}
                </div>
              </div>
            ) : (
              <>
                <div className={innerContentCss}>
                  <MemoizedDialogContent itemHeightEstimate={itemHeightEstimate}>{children}</MemoizedDialogContent>
                </div>
                <ScrollPaginator ref={scrollableRef} rootMargin="500px" paginationCallback={paginationCallback} />
              </>
            )}
          </GridStart>
        </ResponsiveProvider>
      </Bleed>
    </>
  )
}

export default PickerDialogContent

PickerDialogContent.propTypes = {
  /** An object used to represent the navigational folder structure of the import source (e.g. Gallery, Facebook, etc.). The key represents the header and the value contains an array of objects, shown as folders. The nested object should include a 'name' prop. This object will be returned when the folder button is clicked. Optionally, Icons can be passed in to override the folder Icon. If you wish to pass a custom Icon and it doesn't have an active state variation, use the same Icon for `leftIconActive`. */
  dialogNavStructure: PropTypes.objectOf(
    PropTypes.arrayOf(
      PropTypes.shape({
        name: PropTypes.string.isRequired,
        id: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
        leftIcon: PropTypes.func,
        leftIconActive: PropTypes.func,
      })
    ).isRequired
  ),

  /** Use the first 'Header' provided in the `dialogNavStructure` as a label for the entire nav list. */
  showMainNavHeader: PropTypes.bool,
  /** Whether memories are currently being fetched. */
  isFetching: PropTypes.bool,
  /** Estimated pixel height of the items shown in the PickerDialog. This will allow for a more performant experience. **NOTE:** Don't pass this prop in if you want ImageGrid to be used. */
  itemHeightEstimate: PropTypes.number,
  /** Invoked callback when a folder button in the side-nav is clicked. */
  folderSelectionCallback: PropTypes.oneOfType([PropTypes.func, PropTypes.object]),

  /** Function you want invoked when the user has scrolled near the bottom of the content section. */
  paginationCallback: PropTypes.func,
  /** JSX you want shown when no content is shown. */
  emptyState: PropTypes.shape({
    messageBlock: PropTypes.node.isRequired,
    action: PropTypes.node,
  }).isRequired,
  /** Item(s) you want shown in a static section above the content */
  preContentRow: PropTypes.shape({
    searchOnChange: PropTypes.func,
    searchOnEnter: PropTypes.func,
    arrangeOnChange: PropTypes.func,
    arrangeOptions: PropTypes.arrayOf(
      PropTypes.shape({
        value: PropTypes.string,
        label: PropTypes.string,
      })
    ),
  }),
}
