import React from 'react'
import { Paragraph } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'

export default function Comments({ commentCount }) {
  const [t] = useTranslation()

  return (
    commentCount > 0 && (
      <Paragraph secondary size="xs">
        {t('memory-card.comments.label', 'Comments:')} {commentCount > 99 ? '99+' : `${commentCount}`}
      </Paragraph>
    )
  )
}
