import { useCallback, useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import { isTranslationAvailable } from '@fs/zion-locale'
import { getSessionId } from '@fs/zion-session'
import { memoryUtils, restorationToolUrl, isLocalHost } from '../utils'

export default function useMemoryCard(memory, missing) {
  const [t] = useTranslation()
  const { thumbMobileUrl, thumbUrl, thumbSquareUrl } = memory

  const {
    getAriaLabel,
    getDateString,
    getPlaceString,
    isAudio,
    isError,
    isImage,
    isPdf,
    isPhaudio,
    isPhotoStory,
    isPrivate,
    isRestricted,
    isTextStory,
  } = memoryUtils

  // Memory Types
  const isAudioMemory = useMemo(() => isAudio(memory), [isAudio, memory])
  const isImageMemory = useMemo(() => isImage(memory), [isImage, memory])
  const isPdfMemory = useMemo(() => isPdf(memory), [isPdf, memory])
  const isPhaudioMemory = useMemo(() => isPhaudio(memory), [isPhaudio, memory])
  const isPhotoStoryMemory = useMemo(() => isPhotoStory(memory), [isPhotoStory, memory])
  const isPrivateMemory = useMemo(() => isPrivate(memory), [isPrivate, memory])
  const isTextStoryMemory = useMemo(() => isTextStory(memory), [isTextStory, memory])

  // Display States
  const isErrorMemory = useMemo(() => isError(memory), [isError, memory])
  const isRestrictedMemory = useMemo(() => isRestricted(memory), [isRestricted, memory])

  const ariaLabel = useMemo(() => getAriaLabel(memory, missing), [getAriaLabel, memory, missing])

  const date = useMemo(() => getDateString(memory) || t('memory-card.no-date', 'No Date'), [getDateString, memory, t])

  const place = useMemo(
    () =>
      getPlaceString(memory) ||
      (isTranslationAvailable('memory-card.no-place') ? t('memory-card.no-place', 'No Place') : null),
    [getPlaceString, memory, t]
  )

  const imageSrc = useMemo(() => {
    const url = thumbMobileUrl || thumbUrl || thumbSquareUrl
    return isLocalHost() ? `${url}&session=${getSessionId()}` : url
  }, [thumbMobileUrl, thumbUrl, thumbSquareUrl])

  const getCardTo = useCallback(
    (to, tombstone, selectable, disabled, reorder) => {
      if ((tombstone && !missing) || (missing && selectable) || disabled || reorder) {
        return null
      }
      if (missing) {
        return restorationToolUrl
      }
      return to
    },
    [missing]
  )

  return {
    ariaLabel,
    date,
    getCardTo,
    imageSrc,
    isAudioMemory,
    isErrorMemory,
    isImageMemory,
    isPdfMemory,
    isPhaudioMemory,
    isPhotoStoryMemory,
    isPrivateMemory,
    isRestrictedMemory,
    isTextStoryMemory,
    place,
  }
}
