import React, { memo, useState, useEffect } from 'react'
import { i18n } from '@fs/zion-locale'
import { css } from '@linaria/core'
import { boolAttr } from '@fs/zion-frontend-friends'
import { Paragraph, colors, Row, MarginBox, useOverlay } from '@fs/zion-ui'
import { format, formatDistanceStrict } from '@fs/zion-locale/date-fns'
import { useTranslation } from 'react-i18next'
import { useParams } from '@fs/zion-router'
import useInterval from '../hooks/utils/useInterval'
import ChatMessageBase from './ChatMessageBase'
import { getMessageText, getIsSystemMessage, getIsSystemUser } from '../helpers/stream/streamChatHelper'
import ChatMessageContactChip from './ChatMessageContactChip'
import { useChatState } from '../providers/ChatStateProvider'
import { isManagedChannel } from '../services/fsChat/fsChatService'
import useChatFlags from '../hooks/useChatFlags'

const ONE_MINUTE = 60 * 1000

const timestampCss = css`
  margin-inline: 8px;
`
const timestampIndentCss = css`
  padding-inline-start: 10px !important;
  padding-inline-end: 0 !important;
  &[from-user] {
    padding-inline-start: 0 !important;
  }
`
const messageIndentCss = css`
  padding-inline-start: 20px !important;
  padding-inline-end: 0 !important;
  &[from-user] {
    padding-inline-start: 0 !important;
  }
`
const containerCss = css`
  border-radius: 4px;
  &[emphasized] {
    &:not([from-user]) {
      background: ${colors.transparent.gray05};
    }
    &[from-user] {
      background: ${colors.blue05};
    }
  }
`

function getTimeDifference(timestamp) {
  if (new Date() - new Date(timestamp) < ONE_MINUTE) {
    return i18n.t('chat.just-now.label', 'Just now')
  }
  return formatDistanceStrict(new Date(timestamp), new Date(), {
    addSuffix: true,
    locale: i18n.language,
  })
}

function ChatMessage({
  message,
  condensePreviousMessage,
  condenseNextMessage,
  channel,
  parentChannel,
  fromUser,
  isUnread,
  hideReplyButtons,
  labelId,
}) {
  const { client, restrictToManagedGroups } = useChatState()
  const [t] = useTranslation()
  const displayName = message?.user?.name
  const { pid } = useParams()
  const reactionOverlay = useOverlay()
  const emphasize = isUnread
  const formattedTimestamp = message?.created_at ? format(new Date(message?.created_at), 'PPpp') : undefined
  const [formattedDistance, setFormattedDistance] = useState(getTimeDifference(message?.created_at))
  useInterval(() => {
    setFormattedDistance(getTimeDifference(message?.created_at))
  }, ONE_MINUTE)
  const isDeletedMessage = message?.fs_message_deleted
  const isSystemMessage = getIsSystemMessage(message)
  const isSystemUser = getIsSystemUser(message?.user)

  const isManagedGroup = isManagedChannel(channel)
  const showReactions =
    !isDeletedMessage &&
    !isSystemMessage &&
    !isSystemUser &&
    !client?.anonymous &&
    !(restrictToManagedGroups && !isManagedGroup)

  const { messagingChatOnDemandTranslationsIsOn } = useChatFlags()
  const isMessageInUsersLanguage = message?.i18n?.language === i18n.language
  const [isTranslated, setIsTranslated] = useState(
    isMessageInUsersLanguage ? false : !!message?.i18n?.[`${i18n.language}_text`]
  )
  const [text, setText] = useState('')
  const parentId = message?.parent_id

  useEffect(() => {
    const messageText = getMessageText({ message, t, isTranslated, fromUser, messagingChatOnDemandTranslationsIsOn })
    setText(messageText)
  }, [message, t, isTranslated, fromUser, messagingChatOnDemandTranslationsIsOn])

  return (
    <div
      className={containerCss}
      from-user={boolAttr(fromUser)}
      emphasized={boolAttr(emphasize)}
      data-messageid={message?.id}
    >
      {!fromUser && !condensePreviousMessage && !isSystemMessage && <ChatMessageContactChip user={message?.user} />}
      <Row
        alignX={fromUser ? 'end' : 'start'}
        from-user={boolAttr(fromUser)}
        className={messageIndentCss}
        id={labelId}
        alignY="middle"
      >
        <ChatMessageBase
          displayName={displayName}
          formattedDistance={formattedDistance}
          formattedTimestamp={formattedTimestamp}
          text={text}
          isDeleted={isDeletedMessage}
          emphasize={emphasize}
          fromUser={fromUser}
          edited={message?.message_text_updated_at}
          showReactions={showReactions}
          message={message}
          channel={channel}
          parentChannel={parentChannel}
          isSystemMessage={isSystemMessage}
          isSystemUser={isSystemUser}
          hideReplyButtons={hideReplyButtons}
          pid={pid}
          reactionOverlay={reactionOverlay}
          parentId={parentId}
          setIsTranslated={setIsTranslated}
          isTranslated={isTranslated}
          isMessageInUsersLanguage={isMessageInUsersLanguage}
        />
      </Row>
      {/* only display timestamp for last message from a user or if the message is on its own */}
      {((condensePreviousMessage && !condenseNextMessage) || (!condensePreviousMessage && !condenseNextMessage)) && (
        <MarginBox marginX="nano">
          <Row
            alignX="end"
            guttersX="none"
            guttersY="nano"
            from-user={boolAttr(fromUser)}
            className={timestampIndentCss}
            alignY="middle"
            wrap
          >
            <Paragraph aria-hidden="true" growX={!fromUser} noShrinkX secondary size="xs">
              <time dateTime={message?.created_at} title={formattedTimestamp} className={timestampCss}>
                {formattedDistance}
              </time>
            </Paragraph>
          </Row>
        </MarginBox>
      )}
    </div>
  )
}

const MemoizedChatMessage = memo(ChatMessage)
MemoizedChatMessage.displayName = 'ChatMessage'
export default MemoizedChatMessage
