import { NoticeLoading, SocialFaceHappy } from '@fs/zion-icon'
import { IconButton, QuickGlanceOverlay } from '@fs/zion-ui'
import React, { useState } from 'react'
import { useTranslation } from 'react-i18next'
import { toggleMessageReaction, emojiToStreamReactionType } from '../helpers/stream/streamChatHelper'
import useChatLog from '../hooks/useChatLog'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import ChatEmojiPicker from './ChatEmojiPicker'

export default function ChatMessageReactButton({ message, channel, overlay, ownReactions }) {
  const [t] = useTranslation()
  const label = t('chat.add-reaction.action', 'Add Reaction')
  const [saving, setSaving] = useState(false)
  const { log } = useChatLog({ component: '[ChatMessageReactButton]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  const handleEmojiClick = async (emoji) => {
    overlay.close()
    try {
      setSaving(true)
      await toggleMessageReaction({ channel, reactionType: emojiToStreamReactionType(emoji), message, ownReactions })
    } catch (error) {
      handleBasicError(error, {
        moreInfo: `Problem toggling emoji reaction. ChannelId: ${channel?.cid}, MessageId: ${message?.id}`,
      })
    }
    setSaving(false)
  }

  return (
    <div>
      <IconButton
        onClick={overlay.handleClick}
        size="xs"
        Icon={saving ? NoticeLoading : SocialFaceHappy}
        title={label}
      />
      {(overlay.isOpen || overlay.transitioning) && (
        <QuickGlanceOverlay {...overlay} aria-label={label}>
          <ChatEmojiPicker onEmojiClick={handleEmojiClick} />
        </QuickGlanceOverlay>
      )}
    </div>
  )
}
