import React from 'react'
import { css } from '@linaria/core'
import { Bleed, Row, Separator } from '@fs/zion-ui'
import { Comments, Visibility, Tombstone } from '.'
import useMemoryCard from '../useMemoryCard'

const renderAboveStoryGradient = css`
  z-index: 1;
`

function LeftContent({ commentCount, tombstone }) {
  return (
    <>
      {tombstone >= 0 ? <Tombstone tombstone={tombstone} /> : <Comments commentCount={commentCount} />}
      {/* When there is no content, this div pushes the visibility button to the right thanks to the growX below */}
      {/* Explicitly checking for undefined instead of < 1 or !tombstone because a tombstone can be zero days */}
      {tombstone === undefined && !commentCount && <div />}
    </>
  )
}

export default function Footer({ memory, tombstone }) {
  const { isPrivateMemory } = useMemoryCard(memory)
  const { commentCount } = memory

  return (
    <>
      <Separator size="nano" />
      <Bleed bottom>
        <div className={renderAboveStoryGradient} data-testid="memory-card-footer">
          <Row alignY="bottom">
            <LeftContent commentCount={commentCount} tombstone={tombstone} growX />
            <Visibility isPrivateMemory={isPrivateMemory} />
          </Row>
        </div>
        <Separator size="nano" />
      </Bleed>
    </>
  )
}
