import { ActionChip, Row } from '@fs/zion-ui'
import React, { useState } from 'react'
import { useTranslation } from 'react-i18next'
import { streamReactionTypeToEmoji, toggleMessageReaction } from '../helpers/stream/streamChatHelper'
import useChatLog from '../hooks/useChatLog'
import useHandleChatErrors from '../hooks/useHandleChatErrors'

export default function ChatMessageReactionChips({ message, channel, fromUser, ownReactions }) {
  if (JSON.stringify(message.reaction_counts) === '{}') return null
  return (
    <Row gutters="nano" wrap alignX={fromUser ? 'end' : 'start'}>
      {Object.keys(message.reaction_counts).map((reactionType) => (
        <ChatMessageReactionChip
          key={reactionType}
          message={message}
          channel={channel}
          reactionType={reactionType}
          ownReactions={ownReactions}
        />
      ))}
    </Row>
  )
}

function ChatMessageReactionChip({ message, channel, reactionType, ownReactions }) {
  const [t] = useTranslation()
  const [saving, setSaving] = useState(false)
  const { log } = useChatLog({ component: '[ChatMessageReactionChip]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  const count = message.reaction_counts[reactionType]
  if (!count) return null

  // Silently ignore invalid reaction types (FSCHAT-734)
  let emoji
  try {
    emoji = streamReactionTypeToEmoji(reactionType)
  } catch (error) {
    log({ msg: `Invalid reaction type ${reactionType} on message ${message.id}` })
    return null
  }

  const isOwnReaction = ownReactions?.some((ownReaction) => ownReaction.type === reactionType)
  const actionLabel = isOwnReaction
    ? t('chat.remove-reaction.action', 'Remove Reaction')
    : t('chat.add-reaction.action', 'Add Reaction')
  const emojiLabel = `${emoji} ${count}`

  const reactedUserNames = getReactedUserNames({ message, reactionType, t })
  const tooltip = `${emoji} ${reactedUserNames.join(', ')}`

  const handleReactionClick = async () => {
    try {
      setSaving(true)
      await toggleMessageReaction({ channel, reactionType, message, ownReactions })
    } catch (error) {
      handleBasicError(error, { moreInfo: `Problem toggling reaction. MessageId: ${message?.id}` })
    }
    setSaving(false)
  }

  return (
    <ActionChip
      key={reactionType}
      aria-label={`${emojiLabel} ${actionLabel}`}
      label={emojiLabel}
      description={tooltip}
      selected={isOwnReaction}
      onClick={handleReactionClick}
      disabled={saving}
    />
  )
}

export function getReactedUserNames({ message, reactionType, t }) {
  const count = message.reaction_counts[reactionType]
  const reactions = message.latest_reactions?.filter((reaction) => reaction?.type === reactionType) || []
  const names = reactions.map((reaction) => reaction.user?.name).filter((name) => !!name) || []

  // In the message, latest_reactions does not contain all reaction objects
  // Add a label to account for some/all people who reacted whose names we don’t have
  const unknownReactedUserCount = count - names.length
  if (unknownReactedUserCount === count) {
    names.push(
      t('chat.people-count.label', '{count, plural, =0 {no people} one {# person} other {# people}}', { count })
    )
  } else if (unknownReactedUserCount > 0) {
    names.push(
      t(
        'chat.other-people-count.label',
        '{count, plural, =0 {no other people} one {# other person} other {# other people}}',
        { count: unknownReactedUserCount }
      )
    )
  }
  return names
}
