import React from 'react'
import { css } from '@linaria/core'
import { Bleed, Image } from '@fs/zion-ui'
import { DocumentPdf, MediaHeadphones } from '@fs/zion-icon'
import { memoryUtils } from '../../utils'
import MemoryCollage from '../../MemoryCollage/MemoryCollage'
import { Audio, MediaFooter } from '.'
import useMemoryCard from '../useMemoryCard'

const mediaContainerCss = css`
  // Needed to absolutely position MediaFooter
  position: relative;
  // overriding default height of 'auto' to let growY (flex-grow) fill Media's container
  & > img {
    height: 0;
  }
  // Targets the image skeleton and makes it fill all vertical space
  & > [role='img'] {
    flex-grow: 1;
  }
`

export default function Media({ memory, noDetails, dense }) {
  const { imageSrc, isAudioMemory, isImageMemory, isPdfMemory, isPhaudioMemory, isPhotoStoryMemory } =
    useMemoryCard(memory)
  const { formatAudioDuration, getStoryImageUrls } = memoryUtils
  const showMediaFooter = isPhaudioMemory || isPdfMemory
  const audioDuration = (isAudioMemory || isPhaudioMemory) && formatAudioDuration(memory)
  const alt = memory?.title || ''

  return (
    <Bleed top sides bottom={noDetails} className={mediaContainerCss} data-testid="memory-card-media">
      {(isImageMemory || isPhaudioMemory || isPdfMemory) && (
        <Image src={imageSrc} alt={alt} draggable="false" data-testid="media-image" />
      )}
      {isPhotoStoryMemory && (
        <MemoryCollage
          images={getStoryImageUrls(memory)}
          minHeight={`${dense ? 130 : 200}px`}
          alt={alt}
          denseFooter={dense}
        />
      )}
      {isAudioMemory && <Audio audioDuration={audioDuration} dense={dense} />}
      {showMediaFooter && (
        <MediaFooter
          Icon={isPhaudioMemory ? MediaHeadphones : DocumentPdf}
          text={audioDuration || ''}
          dense={dense}
          alignX="start"
        />
      )}
    </Bleed>
  )
}
