import React, { useCallback, useEffect, useRef, useState } from 'react'
import { Virtuoso } from 'react-virtuoso'
import { useTranslation } from 'react-i18next'
import { Separator, Row, Divider, Paragraph } from '@fs/zion-ui'
import { useEvent } from '@fs/zion-frontend-friends'
import ChatTimestamp from './ChatTimestamp'
import ChatMessage from './ChatMessage'
import { useChatState, useChatDispatch } from '../providers/ChatStateProvider'
import VirtuosoScrollShadow from './VirtuosoScrollShadow'
import { CHANNEL_TYPE } from '../services/fsChat/fsChannelEnums'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import {
  isUserBlocked,
  getIsSystemMessage,
  isParentOfUnreadThread,
  getChannelUnreadCount,
} from '../helpers/stream/streamChatHelper'
import ChatMessageBlocked from './ChatMessageBlocked'
import {
  getArticleLabelId,
  getNextIndexOrElement,
  virtuosoComponents,
  focusOnMessageAfterScroll,
} from './feedPatternHelper'
import LoadingSpinner from '../chat-window/LoadingSpinner'
import useChatFlags from '../hooks/useChatFlags'

export function ChatContentMessageNode({
  message,
  condensePreviousMessage,
  condenseNextMessage,
  channel,
  showDateSeparator,
  isUnread,
  hideReplyButtons,
  labelId,
  isInThread,
}) {
  const [t] = useTranslation()
  const { client, channels } = useChatState()
  const fromUser = message?.user?.id === client?.userID
  const messageIsParentOfUnreadThread = isParentOfUnreadThread({ message, channels })
  const showParentMessageSeparator = isInThread && message?.reply_count > 0

  if (!fromUser && isUserBlocked({ userId: message?.user?.id, client })) {
    return <ChatMessageBlocked user={message.user} />
  }

  return (
    <>
      {showDateSeparator && message?.created_at && <ChatTimestamp date={message?.created_at} />}
      {message?.user && message?.id && (
        <>
          {showDateSeparator && fromUser && <Separator size="xxs" aria-hidden="true" />}
          <ChatMessage
            message={message}
            condensePreviousMessage={condensePreviousMessage}
            condenseNextMessage={condenseNextMessage}
            channel={channel}
            fromUser={fromUser}
            isUnread={isUnread || messageIsParentOfUnreadThread}
            hideReplyButtons={hideReplyButtons}
            labelId={labelId}
          />
          {showParentMessageSeparator && (
            <Row alignY="middle" gutters="sm">
              <Divider growX />
              <Paragraph size="sm" secondary>
                {t(
                  'chat.message-replies.action-plural',
                  '{count, plural, =0 {No Replies} one {# Reply} other {# Replies}}',
                  { count: message?.reply_count || 0 }
                )}
              </Paragraph>
              <Divider growX />
            </Row>
          )}
        </>
      )}
      <Separator size={condenseNextMessage ? 'nano' : 'xs'} aria-hidden="true" />
    </>
  )
}

function normalizeRange({ firstItemIndex, range }) {
  const { startIndex, endIndex } = range
  return { startIndex: startIndex - firstItemIndex, endIndex: endIndex - firstItemIndex }
}

function getUnreadThreadMessageIndexes(channel, channels, messages) {
  const { cid } = channel || {}
  const matchingThreadChannels = channels.filter(
    (c) =>
      c.type === CHANNEL_TYPE.FS_THREAD &&
      c.data.fs_parent_channel_cid === cid &&
      getChannelUnreadCount({ channel: c }) > 0
  )
  return matchingThreadChannels
    .filter((t) => {
      return messages.find((m) => {
        return m?.id === t.data.fs_parent_message_id
      })
    })
    .map((t) => {
      const parentMessage = messages.find((m) => {
        return m.id === t.data.fs_parent_message_id
      })
      return messages.indexOf(parentMessage)
    })
}

function getUnreadScrollInfoUp({ unreadMessageIndex, moreUnreadsUp, startIndex, closestUnreadIndexUp }) {
  const getClosestUnreadIndexUp = () => {
    if (
      unreadMessageIndex !== -1 &&
      unreadMessageIndex < startIndex &&
      (!closestUnreadIndexUp || unreadMessageIndex > closestUnreadIndexUp)
    ) {
      return unreadMessageIndex
    }
    return closestUnreadIndexUp
  }

  return {
    moreUnreadsUp: moreUnreadsUp || unreadMessageIndex < startIndex,
    closestUnreadIndexUp: getClosestUnreadIndexUp(),
  }
}

function getUnreadScrollInfoDown({ unreadMessageIndex, moreUnreadsDown, endIndex, closestUnreadIndexDown }) {
  const getClosestUnreadIndexDown = () => {
    if (
      unreadMessageIndex !== -1 &&
      unreadMessageIndex > endIndex &&
      (closestUnreadIndexDown === -1 || unreadMessageIndex < closestUnreadIndexDown)
    ) {
      return unreadMessageIndex
    }
    return closestUnreadIndexDown
  }

  return {
    moreUnreadsDown: moreUnreadsDown || unreadMessageIndex > endIndex,
    closestUnreadIndexDown: getClosestUnreadIndexDown(),
  }
}

function getUnreadScrollInfo({ channel, channels, firstItemIndex, range, messages }) {
  const { startIndex, endIndex } = normalizeRange({ firstItemIndex, range })
  const unreadThreadMessageIndexes = getUnreadThreadMessageIndexes(channel, channels, messages)

  return unreadThreadMessageIndexes.reduce(
    (unreadScrollInfo, unreadMessageIndex) => {
      const { moreUnreadsUp, closestUnreadIndexUp } = getUnreadScrollInfoUp({
        unreadMessageIndex,
        startIndex,
        ...unreadScrollInfo,
      })
      const { moreUnreadsDown, closestUnreadIndexDown } = getUnreadScrollInfoDown({
        unreadMessageIndex,
        endIndex,
        ...unreadScrollInfo,
      })
      return { moreUnreadsUp, closestUnreadIndexUp, moreUnreadsDown, closestUnreadIndexDown }
    },
    {
      moreUnreadsUp: false,
      moreUnreadsDown: false,
      closestUnreadIndexUp: undefined,
      closestUnreadIndexDown: -1,
    }
  )
}

function getReadMessageFromRange({ firstItemIndex, range, messages }) {
  const { startIndex } = normalizeRange({ firstItemIndex, range })
  return messages[startIndex]
}

function getTopVisibleMessageIdFromRange({ firstItemIndex, range, messages }) {
  const { startIndex, endIndex } = normalizeRange({ firstItemIndex, range })
  // If at the bottom, don’t store a specific ID, so that we return to the very bottom when reading messages again
  if (messages?.length > 0 && endIndex === messages.length - 1) {
    return ''
  }
  return messages[startIndex]?.id
}

export default function ChatContentMessages({
  channel,
  loading,
  messages = [],
  unreadMessages = [],
  firstItemIndex,
  prependItems,
  appendItems,
  virtuosoRef,
  hideReplyButtons = false,
  markChannelReadOnRangeChange,
  setTopVisibleMessageId,
  topVisibleMessageId,
  isThread = false,
}) {
  const { channels, scrollToBottom, scrollThreadToBottom, client } = useChatState()
  const chatDispatch = useChatDispatch()
  const scrollShadowRef = useRef()
  const [scrolledToBottom, setScrolledToBottom] = useState(false)
  const [scrolledToTop, setScrolledToTop] = useState()
  const [unreadScrollInfo, setUnreadScrollInfo] = useState()
  const { moreUnreadsUp, moreUnreadsDown, closestUnreadIndexUp, closestUnreadIndexDown } = unreadScrollInfo || {}
  const firstTimestamp = messages?.length > 0 ? messages[0]?.created_at : undefined
  let previousDate = firstTimestamp ? new Date(firstTimestamp) : new Date('Apr 6 1820')
  const [currentIndex, setCurrentIndex] = useState(0)
  const numberOfMessages = 2 // number of messages until the "Go to latest" button is displayed
  const { messagingChatNewAutoscrollingIsOn } = useChatFlags()

  const loadMoreUpTimeoutRef = useRef(null)
  useEffect(() => () => clearTimeout(loadMoreUpTimeoutRef.current), [])
  const loadMoreUp = useCallback(() => {
    clearTimeout(loadMoreUpTimeoutRef.current)
    loadMoreUpTimeoutRef.current = setTimeout(() => {
      prependItems()
    }, 200)
  }, [prependItems])

  const loadMoreDownTimeoutRef = useRef(null)
  useEffect(() => () => clearTimeout(loadMoreDownTimeoutRef.current), [])
  const loadMoreDown = useCallback(() => {
    clearTimeout(loadMoreDownTimeoutRef.current)
    loadMoreDownTimeoutRef.current = setTimeout(() => {
      appendItems()
    }, 200)
  }, [appendItems])

  // Help Virtuoso auto-scroll with the output when we have messages and are already scrolled to the bottom
  const followOutput = messagingChatNewAutoscrollingIsOn ? 'smooth' : messages?.length > 0 && !topVisibleMessageId
  const scrollingBehavior = messagingChatNewAutoscrollingIsOn ? 'smooth' : 'instant'

  useEffect(() => {
    if (!messages?.length) return

    const lastIsMine = messages.at(-1)?.user?.id === client?.userID

    if (isThread && scrollThreadToBottom && lastIsMine) {
      virtuosoRef.current?.scrollToIndex({ index: messages.length - 1, align: 'end', behavior: 'instant' })
      chatDispatch({ type: CHAT_ACTIONS.CLEAR_SCROLL_TO_BOTTOM })
    }
    if (!isThread && scrollToBottom && lastIsMine) {
      virtuosoRef.current?.scrollToIndex({ index: messages.length - 1, align: 'end', behavior: 'instant' })
      chatDispatch({ type: CHAT_ACTIONS.CLEAR_SCROLL_TO_BOTTOM })
    }
  }, [isThread, scrollToBottom, scrollThreadToBottom, messages, client, chatDispatch, virtuosoRef])

  const handleKeyDown = useEvent((event) => {
    const container = scrollShadowRef.current
    // The event bubbles through the component tree, so don’t trigger when a dialog or menu is open outside the message list DOM
    if (!container?.contains(document?.activeElement)) return

    const { index, element } = getNextIndexOrElement({ event, container, totalArticleCount: messages?.length || 0 })

    if (typeof index === 'number') {
      virtuosoRef.current.scrollToIndex({ index, align: 'start', offset: -32 })
      setTimeout(() => {
        // Important to query within the current scroller, since thread + main channel can be in the document together
        const nextElement = container?.querySelector(`[data-index="${index}"]`)
        nextElement?.focus()
      }, 10)
      event.preventDefault()
      event.stopPropagation()
    } else if (element) {
      element.focus()
    }
  })

  const onGoLatest = () => {
    virtuosoRef.current?.scrollToIndex({ index: messages.length - 1, align: 'end', behavior: scrollingBehavior })
    focusOnMessageAfterScroll({
      container: scrollShadowRef.current,
      querySelector: `[data-index="${messages.length - 1}"]`,
    })
  }

  return (
    <VirtuosoScrollShadow
      scrollShadowRef={scrollShadowRef}
      scrolledToBottom={scrolledToBottom}
      scrolledToTop={scrolledToTop}
      moreUnreadsUp={moreUnreadsUp}
      onScrollUpToUnread={() => {
        virtuosoRef.current?.scrollToIndex(closestUnreadIndexUp)
      }}
      moreUnreadsDown={moreUnreadsDown}
      onScrollDownToUnread={() => {
        virtuosoRef.current?.scrollToIndex(closestUnreadIndexDown)
      }}
      showLatest={messages.length - 1 - currentIndex >= numberOfMessages}
      onGoLatest={onGoLatest}
    >
      {loading && <LoadingSpinner />}
      <Virtuoso
        atBottomStateChange={setScrolledToBottom}
        atTopStateChange={setScrolledToTop}
        rangeChanged={(range) => {
          setUnreadScrollInfo(getUnreadScrollInfo({ channel, channels, firstItemIndex, range, messages }))
          setTopVisibleMessageId(getTopVisibleMessageIdFromRange({ firstItemIndex, range, messages }))
          markChannelReadOnRangeChange(getReadMessageFromRange({ firstItemIndex, range, messages }))
        }}
        ref={virtuosoRef}
        style={{ overflowX: 'hidden', overflowY: 'auto' }}
        context={{ channel, client, loading }}
        components={virtuosoComponents}
        onKeyDown={handleKeyDown}
        firstItemIndex={firstItemIndex}
        data={messages}
        startReached={loadMoreUp}
        endReached={loadMoreDown}
        followOutput={followOutput}
        tabIndex={-1}
        // eslint-disable-next-line react/no-unstable-nested-components -- this is how Virtuoso documents using itemContent
        itemContent={(index, message) => {
          const messageDate = new Date(message?.created_at)
          const showDateSeparator = messageDate.getDate() !== previousDate.getDate()
          if (showDateSeparator) previousDate = messageDate
          const isUnread = unreadMessages.some((mid) => mid === message.id)
          const isCurrentMessageSystem = getIsSystemMessage(message)
          setCurrentIndex(index - firstItemIndex)

          const previousMessage = messages[index - firstItemIndex - 1]
          const isPreviousMessageSameUser = previousMessage?.user?.id === message?.user?.id
          const isPreviousMessageWithinSameDay = isPreviousMessageSameUser
            ? messageDate.getUTCDate() === new Date(previousMessage?.created_at).getUTCDate()
            : false
          const isPreviousMessageSystem = getIsSystemMessage(previousMessage)
          const condensePreviousMessage =
            isPreviousMessageSameUser &&
            isPreviousMessageWithinSameDay &&
            !isPreviousMessageSystem &&
            !isCurrentMessageSystem

          const nextMessage = messages[index - firstItemIndex + 1]
          const isNextMessageSameUser = nextMessage?.user?.id === message?.user?.id
          const isNextMessageWithinSameDay = isNextMessageSameUser
            ? new Date(nextMessage?.created_at).getUTCDate() === messageDate.getUTCDate()
            : false
          const isNextMessageSystem = getIsSystemMessage(nextMessage)
          const condenseNextMessage =
            isNextMessageSameUser && isNextMessageWithinSameDay && !isNextMessageSystem && !isCurrentMessageSystem

          return (
            <ChatContentMessageNode
              key={`${message?.id}-${message?.created_at}`}
              channel={channel}
              message={message}
              condensePreviousMessage={condensePreviousMessage}
              condenseNextMessage={condenseNextMessage}
              showDateSeparator={showDateSeparator}
              isUnread={isUnread}
              hideReplyButtons={hideReplyButtons}
              labelId={getArticleLabelId(index)}
              isInThread={isThread}
            />
          )
        }}
      />
    </VirtuosoScrollShadow>
  )
}
