import { focusableSelectors } from '@fs/zion-frontend-friends'
import { Separator } from '@fs/zion-ui'
import React, { forwardRef } from 'react'
import { useTranslation } from 'react-i18next'
import { getChannelName } from '../helpers/stream/streamChatHelper'

// The list of messages (ChatContentMessages) implements the Feed Pattern from the ARIA Authoring Practices Guide
// See https://www.w3.org/WAI/ARIA/apg/patterns/feed/

export const getArticleLabelId = (dataItemIndex) => `article-label-${dataItemIndex}`

function getFocusDestination(container, direction) {
  const focusableElements = Array.from(document.querySelectorAll(focusableSelectors))
  const childElementIndices = []
  focusableElements.forEach((el, index) => {
    if (container.contains(el)) childElementIndices.push(index)
  })

  const beforeIndex = Math.min(...childElementIndices) - 1
  const afterIndex = Math.max(...childElementIndices) + 1
  return focusableElements[direction === 'before' ? beforeIndex : afterIndex]
}

// Arrow keys and page up/down move to next/previous message.
// Home/end move to first/last message.
// Control+home/end move to focusable element just before or after the message list.
// Command(Mac)/Control(Windows/Linux) + arrow up/down also move to first/last message
export function getNextIndexOrElement({ event, container, totalArticleCount }) {
  const activeArticle = document?.activeElement?.closest('article')
  const activeArticleIndex = activeArticle ? Number(activeArticle.getAttribute('data-index')) : null

  // Modern platform detection with fallback
  const isMac = navigator.userAgentData?.platform
    ? navigator.userAgentData.platform === 'macOS'
    : /macintosh|mac os x/i.test(navigator.userAgent)
  const modifierKey = isMac ? event.metaKey : event.ctrlKey

  // Common navigation targets
  const firstMessage = { index: 0 }
  const lastMessage = { index: totalArticleCount - 1 }
  const previousMessage = { index: Math.max(0, activeArticleIndex - 1) }
  const nextMessage = { index: Math.min(totalArticleCount - 1, activeArticleIndex + 1) }
  const beforeList = { element: getFocusDestination(container, 'before') }
  const afterList = { element: getFocusDestination(container, 'after') }

  switch (event.key) {
    case 'ArrowUp':
      return modifierKey ? firstMessage : previousMessage
    case 'ArrowDown':
      return modifierKey ? lastMessage : nextMessage
    case 'PageUp':
      return previousMessage
    case 'PageDown':
      return nextMessage
    case 'Home':
      return modifierKey ? beforeList : firstMessage
    case 'End':
      return modifierKey ? afterList : lastMessage
    default:
      return {}
  }
}

// Parent wrapper of the list of messages (role of feed)
const List = forwardRef(({ context, ...props }, ref) => {
  const { channel, client, loading } = context
  const [t] = useTranslation()
  const name = getChannelName({ channel, excludedUserId: client?.userID })
  const label = t('chat.messages-from.label', 'Messages from {name}', { name })

  return <div role="feed" aria-busy={loading} aria-label={label} {...props} ref={ref} />
})
List.displayName = 'ChatMessageList'

// Wrapper of each individual message (role of article)
const Item = forwardRef(({ context, ...props }, ref) => {
  const labeledById = getArticleLabelId(props['data-item-index'])
  return (
    <article
      tabIndex="-1"
      aria-posinset={props['data-index'] + 1}
      aria-setsize={props['data-known-size']}
      aria-labelledby={labeledById}
      ref={ref}
      {...props}
    />
  )
})
Item.displayName = 'ChatMessageItem'

// This is defined outside of the render function to avoid focus issues from remounts.
// The `context` prop is used to pass the channel and other state to `List`.
// See https://github.com/petyosi/react-virtuoso/issues/715#issuecomment-1189144213
export const virtuosoComponents = { Header: () => <Separator size="sm" />, List, Item }

export function focusOnMessageAfterScroll({ container, querySelector }) {
  let attempts = 0
  const maxAttempts = 30
  if (container) {
    // Move focus to the latest message after scrolling, otherwise it will be lost
    const interval = setInterval(() => {
      const element = container.querySelector(querySelector)
      if (element) {
        clearInterval(interval)
        // Add a small delay to ensure scrolling has completed
        setTimeout(() => {
          element.focus()
        }, 100)
      }
      attempts++
      if (attempts >= maxAttempts) {
        clearInterval(interval)
      }
    }, 100)
  }
}
