import React, { useCallback, useRef } from 'react'
import { GallerySelector } from '@fs/zion-picker-dialog'
import { IconButton, Paragraph, QuickGlanceOverlay, useOverlay, QuickGlanceActions, Button } from '@fs/zion-ui'
import { LogoFamilysearch } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { useChatAttachmentsState, useChatAttachmentsDispatch } from '../providers/ChatAttachmentsProvider'
import { updateOnGalleryConfirmation } from '../helpers/chatAttachmentHelper'

export const maxAttachmentsReached = (pendingAttachments) => pendingAttachments.length >= 3

export default function ChatShareMemoryButton({ isReply }) {
  const { t } = useTranslation()
  const { pendingArtifactAttachments } = useChatAttachmentsState()
  const chatAttachmentsDispatch = useChatAttachmentsDispatch()
  const galleryRef = useRef()
  const overlay = useOverlay()
  const targetRef = useRef()

  const galleryConfirmationCallback = useCallback(
    (selectedMemories) => {
      updateOnGalleryConfirmation({
        selectedMemories,
        pendingArtifactAttachments,
        chatAttachmentsDispatch,
        overlay,
        targetRef,
        isReply,
      })
    },
    [pendingArtifactAttachments, chatAttachmentsDispatch, overlay, isReply]
  )
  const maxReached = maxAttachmentsReached(pendingArtifactAttachments)
  const tooltip = maxReached
    ? t('chat.share-memory.limit', 'Max Uploads Reached')
    : t('chat.share-memory.action', 'Share Memory')

  return (
    <>
      <IconButton
        title={tooltip}
        data-testid="add-link"
        Icon={LogoFamilysearch}
        onClick={() => galleryRef.current()}
        disabled={maxReached}
        ref={targetRef}
      />
      <GallerySelector
        confirmationCallback={galleryConfirmationCallback}
        onClose={() => {}} // needed for component
        maxSelectable={Number(3 - pendingArtifactAttachments.length)}
        emptyState={{ messageBlock: <div /> }}
        openerRef={galleryRef}
      />
      <QuickGlanceOverlay
        aria-label={t('chat.share-memory.private.error.title', 'Error sharing private memory')}
        {...overlay}
      >
        <Paragraph size="sm">
          {t(
            'chat.share-memory.private.error',
            'You are trying to share a Private memory. To continue, please visit your Memories Gallery, and change this setting to Public. Then come back to Chat, and try this action again.'
          )}
        </Paragraph>
        <QuickGlanceActions>
          <Button
            onClick={() => {
              window.open('/photos/gallery', '_blank')
              overlay.close()
            }}
          >
            {t('chat.share-memory.memories-gallery', 'Memories Gallery')}
          </Button>
          <Button onClick={overlay.close}>{t('common-ui:dismiss.action', 'Dismiss')}</Button>
        </QuickGlanceActions>
      </QuickGlanceOverlay>
    </>
  )
}
