const ChatAttachments = React.lazy(() => import('../chat-attachments/ChatAttachments'))
const ChatMessageTreePersonLink = lazy(() => import('./ChatMessageTreePersonLink'))
const ChatMessageReplyButtons = React.lazy(() => import('../chat-buttons/ChatMessageReplyButtons'))
const ChatMessageOverlay = React.lazy(() => import('./ChatMessageOverlay'))

ChatAttachments.displayName = 'ChatAttachments'
ChatMessageTreePersonLink.displayName = 'ChatMessageTreePersonLink'
ChatMessageReplyButtons.displayName = 'ChatMessageReplyButtons'
ChatMessageOverlay.displayName = 'ChatMessageOverlay'

const messageCss = css`
  padding: 6px 8px;
  border-radius: 4px;
  background: ${colors.gray03};
  font-size: 14px;
  line-height: 20px;
  width: auto;
  white-space: pre-wrap;
  /* Allow long words to break in the middle, but keep breaking on words too. */
  overflow-wrap: anywhere;
  /* Safari fix for overflow-wrap since it fails without this one. */
  word-break: break-word;

  *[from-user] & {
    width: auto;
  }
  // Match hover and selected colors of ListItem
  :hover {
    background: ${colors.blue05};
    :not([from-user]) {
      background: ${colors.transparent.gray05};
    }
  }
`

const fromUserBackgroundCss = css`
  background: ${colors.blue03};
`

const emphasisCss = css`
  background-color: ${colors.gray05};
`

const emphasisFromUserCss = css`
  background-color: ${colors.blue05};
`

const NUMBERS_ONLY_REGEX = /^\d+$/

// Try to interpret a string as a numeric PID-like value in the form of two numbers separated by a hyphen
// Returns { start, end } as numbers when it matches that shape, otherwise null.
const parseNumericPidLike = (value) => {
  const parts = value.split('-')
  if (parts.length !== 2) return null

  const [startText, endText] = parts

  if (!NUMBERS_ONLY_REGEX.test(startText) || !NUMBERS_ONLY_REGEX.test(endText)) return null

  const start = Number(startText)
  const end = Number(endText)

  return { start, end }
}

// Identify numeric PID-shaped strings that look like plausible year-year ranges between 1000 and 2100
const isLikelyYearRange = (value) => {
  const numericRange = parseNumericPidLike(value)
  if (!numericRange) return false
  const { start, end } = numericRange
  const inYearRange = (year) => year >= 1000 && year <= 2100
  return inYearRange(start) && inYearRange(end) && start <= end
}

function getPidMatches({ text, linkMatches }) {
  if (!text) return []
  const pidRegex = new RegExp(pidRegexStr, 'gi')
  // Ignore PIDs that are part of an already-recognized link
  const isPidNotInLink = (pidMatch) =>
    !linkMatches.some((linkMatch) => linkMatch.start <= pidMatch.index && linkMatch.end >= pidMatch.index)
  const regexMatches = Array.from(text.matchAll(pidRegex))
    .filter(isPidNotInLink)
    // Filter out numeric date ranges like "1887-1972" while preserving true PIDs
    .filter((regexMatch) => !isLikelyYearRange(regexMatch[0]))
  // Generate match objects with the same shape as those from anchorme, with a custom isPid property
  return regexMatches.map((regexMatch) => {
    const pid = regexMatch[0].toUpperCase()
    return {
      start: regexMatch.index,
      end: regexMatch.index + pid.length,
      string: pid,
      isPid: true,
    }
  })
}

function parseRawMessageText(text, domainWhitelist) {
  const linkMatches = anchorme.list(text)
  const pidMatches = getPidMatches({ text, linkMatches })
  // Manually sort, since PIDs were matched after, but can be interspersed with links
  const matches = linkMatches.concat(pidMatches).sort((a, b) => a.start - b.start)

  if (matches.length === 0) return <span aria-hidden>{text}</span>
  const elements = []
  let lastIndex = 0
  matches
    .filter((match) => {
      if (match.isPid) return true
      if (match.isEmail) return false
      const url = match.string
      return isLinkApproved(url, domainWhitelist)
    })
    .forEach((match, index) => {
      const key = `${index}link`
      // Push text located before matched string
      if (match.start > lastIndex) {
        const prefixKey = `${index}prefix`
        elements.push(
          <span key={prefixKey} aria-hidden>
            {text.substring(lastIndex, match.start)}
          </span>
        )
      }

      if (match.isPid) {
        elements.push(
          <Suspense fallback={match.string} key={key}>
            <ChatMessageTreePersonLink pid={match.string} />
          </Suspense>
        )
      }

      if (match.isURL) {
        const url = new URL(
          match.string.startsWith('https://') || match.string.startsWith('http://')
            ? match.string
            : `https://${match.string}`
        ).toString()

        elements.push(
          <Link
            key={key}
            data-testid="chat-message-link"
            target="_blank"
            linkName={`Chat:Click External Link ${match.string}`}
            to={url}
            external
          >
            {match.string}
          </Link>
        )
      }

      lastIndex = match.end
    })

  // Push remaining text
  if (text.length > lastIndex) {
    elements.push(<span key="suffix">{text.substring(lastIndex)}</span>)
  }

  return elements.length === 1 ? elements[0] : elements
}

const getOwnReactions = (latestReactions, myId) => {
  return (latestReactions ?? []).filter((r) => r.user_id === myId)
}

export default function ChatMessageBase({
  text,
  displayName,
  formattedDistance,
  formattedTimestamp,
  emphasize = false,
  fromUser,
  edited = false,
  isDeleted = false,
  showReactions,
  message,
  channel,
  parentChannel,
  isSystemMessage,
  isSystemUser,
  hideReplyButtons,
  pid,
  reactionOverlay,
  parentId,
  setIsTranslated,
  isTranslated,
  isMessageInUsersLanguage,
}) {
  const [t] = useTranslation()
  const { client, restrictToManagedGroups } = useChatState()
  const { domainWhitelist } = useChatProviderContext()
  const parsedText = useMemo(() => parseRawMessageText(text, domainWhitelist), [text, domainWhitelist])
  const [attachmentsWithData, setAttachmentWithData] = useState([])
  const isManagedGroup = isManagedChannel(channel)
  const showReplyButtons =
    !isSystemMessage &&
    !isSystemUser &&
    !parentId &&
    !hideReplyButtons &&
    !client?.anonymous &&
    !(restrictToManagedGroups && !isManagedGroup)

  const { messagingChatOnDemandTranslationsIsOn } = useChatFlags()
  const isUserLanguageSupported = !!useSupportedLanguageName(i18n.language)
  const hasText = text?.length > 0

  const messageAria = i18n.t('chat.someone-said.aria-label', `{name} said {message} {timeAgo}`, {
    name: displayName,
    message: text,
    timeAgo: formattedDistance,
  })
  const unreadText = t('chat.unread.label', 'Unread')
  const ariaLabel = emphasize ? `${messageAria} (${unreadText})` : messageAria

  const ownReactions = useMemo(
    () => getOwnReactions(message?.latest_reactions, client.userID),
    [message?.latest_reactions, client.userID]
  )

  return (
    <article
      className={cx(
        messageCss,
        emphasize && !fromUser && emphasisCss,
        emphasize && fromUser && emphasisFromUserCss,
        fromUser && fromUserBackgroundCss
      )}
      aria-label={ariaLabel}
      from-user={boolAttr(fromUser)}
    >
      {isDeleted && (
        <Row alignY="middle" gutters="nano">
          {isDeleted && <ContentDelete noShrinkX color={colors.transparent.gray40} />}
          {parsedText}
        </Row>
      )}
      {!isDeleted && text && (
        <Row alignX={fromUser ? 'end' : 'start'}>
          <MoreLess collapsedLineCount={10}>{parsedText}</MoreLess>
        </Row>
      )}
      {!isDeleted && message?.attachments?.length > 0 && (
        <Row alignX={fromUser ? 'end' : 'start'} gutters="nano" guttersY="xxs">
          <Suspense fallback={<div>{t('common-ui:loading.ellipsis.label', 'Loading...')}</div>}>
            <ChatAttachments
              attachments={message?.attachments}
              fromUser={fromUser}
              setAttachmentWithData={setAttachmentWithData}
              isSystemUser={isSystemUser}
            />
          </Suspense>
        </Row>
      )}
      {(edited || isTranslated) && (
        <>
          <Separator size="hide" />
          <Row alignX={fromUser ? 'end' : 'start'} gutters="nano" guttersY="xxs">
            {!!edited && (
              <Paragraph as="span" secondary size="xs">
                {t('chat.message-edited.caption', '(edited)')}
              </Paragraph>
            )}
            {messagingChatOnDemandTranslationsIsOn && !fromUser && isTranslated && !isMessageInUsersLanguage && (
              <Paragraph as="span" secondary size="xs">
                {t('chat.message-translated.caption', '(translated)')}
              </Paragraph>
            )}
          </Row>
        </>
      )}
      {/* removes Row margin-top */}
      <Separator size="hide" />
      {showReactions && (
        <>
          <Row alignX={fromUser ? 'end' : 'start'} data-testid="chat-reaction-buttons">
            <ChatMessageReactionChips
              message={message}
              channel={parentChannel || channel}
              fromUser={fromUser}
              ownReactions={ownReactions}
            />
          </Row>
          <Separator size="hide" />
        </>
      )}
      <Row gutters="nano" alignY="bottom" alignX={fromUser ? 'end' : 'start'}>
        {hasText &&
          isUserLanguageSupported &&
          !fromUser &&
          !isSystemMessage &&
          !isDeleted &&
          !client?.anonymous &&
          messagingChatOnDemandTranslationsIsOn && (
            <Suspense fallback={<Skeleton.IconButton size="xs" />}>
              <ChatTranslateMessageToggle
                message={message}
                channelId={channel?.cid}
                setIsTranslated={setIsTranslated}
                isTranslated={isTranslated}
                isMessageInUsersLanguage={isMessageInUsersLanguage}
              />
            </Suspense>
          )}
        {showReactions && (
          <ChatMessageReactButton
            message={message}
            channel={parentChannel || channel}
            noShrinkX
            overlay={reactionOverlay}
            ownReactions={ownReactions}
          />
        )}
        {showReplyButtons && (
          <Suspense fallback={<Skeleton.IconButton size="xs" />} noShrinkX>
            <ChatMessageReplyButtons message={message} channel={channel} />
          </Suspense>
        )}

        {showReactions && (
          <Suspense fallback={<Skeleton.IconButton size="xs" />} noShrinkX>
            <ChatMessageOverlay
              message={message}
              fromUser={fromUser}
              pid={pid}
              attachmentsWithData={attachmentsWithData}
              formattedDistance={formattedDistance}
              formattedTimestamp={formattedTimestamp}
            />
          </Suspense>
        )}
      </Row>
    </article>
  )
}
