import React, { useRef, useEffect, useCallback } from 'react'
import { useParams, useHistory } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'
import ZionForm, { useZionForm, FormMultilineTextField } from '@fs/zion-form'
import { Row, Ellipsis, MarginBox, Separator } from '@fs/zion-ui'
import AddPersonButton from '../chat-buttons/AddPersonButton'
import ChatShareMemoryButton from '../chat-buttons/ChatShareMemoryButton'
import ChatUploadMemoryButton from '../chat-buttons/ChatUploadMemoryButton'
import ChatEmojiButton from '../chat-buttons/ChatEmojiButton'
import ChatPendingAttachments from '../chat-attachments/ChatPendingAttachments'
import { useChatAttachmentsState, useChatAttachmentsDispatch, actionTypes } from '../providers/ChatAttachmentsProvider'
import useChatFlags from '../hooks/useChatFlags'
import { useOnKeyDown, onChatActionsSubmit } from '../helpers/chatActionsHelper'
import ChatActionsSendButton from './ChatActionsSendButton'
import { useChatState } from '../providers/ChatStateProvider'
import { MAX_LENGTH_MESSAGE, CHANNEL_TYPE } from '../services/fsChat/fsChannelEnums'
import { showJoinLeaveTypingForChannel } from '../services/fsChat/fsChatService'
import { useChatProviderContext } from '../providers/useChatProviderContext'
import ChatActionsChangeEnterButton from './ChatActionsChangeEnterButton'
import useChatLog from '../hooks/useChatLog'
import { useChatDraft } from '../hooks/useChatDraft'

const messageTextFieldCss = css`
  overflow: scroll;
  /* Offset the extra margin from InputBase */
  margin-bottom: -16px;
  /* Prevent scrollbars from showing when user has "show scrollbars always" on */
  scrollbar-width: none;
  -ms-overflow-style: none;

  &::-webkit-scrollbar {
    display: none;
  }

  /* Prevent long channel names from causing the placeholder to wrap */

  textarea:placeholder-shown,
  textarea::placeholder {
    text-overflow: ellipsis;
    white-space: nowrap;
    overflow: hidden;
  }
`

const chatActionWrapperCss = css`
  padding: 0 12px;
  position: relative;
`

const typingLabelCss = css`
  position: absolute;
  bottom: 36px;
  inset-inline: 12px;
  font-size: 10px;
`

const skipLinkCss = css`
  position: absolute;
  inset-inline: -10000px;
  top: auto;
  width: 1px;
  height: 1px;
  overflow: hidden;
`

export default function ChatActions({
  onSend,
  messageRef,
  isReply = false,
  typingLabel,
  recipientLabel,
  isSending,
  showSpinner,
  thread,
}) {
  const chatFlags = useChatFlags()
  const { channels, isEmbedded } = useChatState()
  const { log } = useChatLog({ component: '[ChatActions]' })
  const { supportInformation } = useChatProviderContext()
  const [t] = useTranslation()
  const { cid, pid } = useParams()
  const channel = channels?.find((c) => c.cid === cid)
  const { pendingArtifactAttachments, pendingAboutAttachment, pendingMessageText } = useChatAttachmentsState()
  const chatAttachmentsDispatch = useChatAttachmentsDispatch()
  const fieldName = `message`
  const history = useHistory()

  const methods = useZionForm({
    mode: 'all',
    defaultValues: {
      message: pendingMessageText || supportInformation?.messageText || '',
    },
  })
  const { reset: resetForm, getValues: getFormValues, watch } = methods
  const messageText = watch(fieldName)

  useEffect(() => {
    chatAttachmentsDispatch({
      type: actionTypes.SET_PENDING_MESSAGE_TEXT,
      pendingMessageText: messageText || '',
    })
  }, [chatAttachmentsDispatch, messageText])

  // Cleanup function as the user navigates away from the conversation
  useEffect(() => {
    return () => {
      resetForm({ message: '' })
      chatAttachmentsDispatch({ type: actionTypes.CLEAR_ALL_PENDING_ATTACHMENTS })
    }
  }, [chatAttachmentsDispatch, cid, resetForm])

  const { deleteDraft, saveDraft } = useChatDraft({
    channel,
    thread,
    isReply,
    pid,
    getFormValues,
    resetForm,
    log,
    fieldName,
  })

  // Used if messageRef was not passed in
  const messageFallbackRef = useRef()
  const onSubmit = useCallback(() => {
    onChatActionsSubmit({
      onSend,
      pendingArtifactAttachments,
      pendingAboutAttachment,
      chatAttachmentsDispatch,
      getFormValues,
      resetForm,
      deleteDraft,
      log,
    })
  }, [
    onSend,
    pendingArtifactAttachments,
    pendingAboutAttachment,
    chatAttachmentsDispatch,
    getFormValues,
    resetForm,
    deleteDraft,
    log,
  ])

  const showAddPersonToChat =
    !isReply &&
    !isEmbedded &&
    (channel?.type === CHANNEL_TYPE.FS_SUPPORT ||
      channel?.type === CHANNEL_TYPE.FS_VENDOR ||
      channel?.type === CHANNEL_TYPE.FS_SESSION ||
      channel?.type === CHANNEL_TYPE.FS_PUBLIC ||
      channel?.type === CHANNEL_TYPE.FS_ROOTSTECH)

  const hasPendingAttachmentsInContext = pendingArtifactAttachments.some((attachment) => attachment.isReply === isReply)
  const disabled = !recipientLabel || !(messageText || hasPendingAttachmentsInContext) || isSending
  const fieldLabel = isReply
    ? t('chat.reply.placeholder', 'Reply in thread…')
    : t('chat.message.placeholder', 'Message {recipient}', { recipient: recipientLabel })

  return (
    <ZionForm
      methods={methods}
      onSubmit={onSubmit}
      aria-label={t('chat.compose.aria-label', 'Compose Message')}
      data-testid="chat-actions"
    >
      <ChatPendingAttachments
        pendingArtifactAttachments={pendingArtifactAttachments}
        pendingAboutAttachment={pendingAboutAttachment}
        isReply={isReply}
        artifactRemoveHandler={(id) => {
          const newAttachments = pendingArtifactAttachments.filter((artifact) => artifact.id !== id)
          chatAttachmentsDispatch({
            type: actionTypes.SET_PENDING_ARTIFACT_ATTACHMENTS,
            pendingArtifactAttachments: newAttachments,
          })
        }}
        aboutRemoveHandler={() => chatAttachmentsDispatch({ type: actionTypes.CLEAR_PENDING_ABOUT_ATTACHMENT })}
      />
      <div className={chatActionWrapperCss}>
        {showAddPersonToChat && (
          <Row guttersY="nano">
            <div growX />
            <AddPersonButton channel={channel} />
          </Row>
        )}
        <Separator size="nano" />
        <Row gutters="xxs" alignY="middle">
          <div className={messageTextFieldCss} growX>
            <button
              type="button"
              className={skipLinkCss}
              onClick={(e) => {
                e.preventDefault()
                const el = document.getElementById('active-chat-listitem')
                if (!el) {
                  history.push('/chats')
                } else {
                  el.focus()
                  el.scrollIntoView({ behavior: 'smooth', block: 'center' })
                }
              }}
            >
              {t('chat.back-to-chat-list.link', 'Back to chat list')}
            </button>
            <FormMultilineTextField
              data-testid="message-textfield"
              ref={messageRef || messageFallbackRef}
              name={fieldName}
              aria-label={fieldLabel}
              placeholder={fieldLabel}
              maxLength={MAX_LENGTH_MESSAGE}
              maxHeight={100}
              onKeyDown={useOnKeyDown({
                disabled,
                onSubmit,
              })}
              onChange={() => {
                if (showJoinLeaveTypingForChannel({ channel, chatFlags })) {
                  if (isReply) {
                    const threadChannel = pid ? channels.find((c) => c.id === pid) : undefined
                    threadChannel?.keystroke()
                  } else {
                    channel?.keystroke()
                  }
                }
                saveDraft()
              }}
            />
          </div>
          <ChatActionsSendButton disabled={disabled} showSpinner={showSpinner} />
        </Row>
        <MarginBox marginX="nano" marginY="pico">
          <Row gutters="xs" guttersY="nano" alignY="middle">
            <ChatShareMemoryButton isReply={isReply} />
            <ChatUploadMemoryButton isReply={isReply} />
            <ChatEmojiButton textFieldRef={messageRef || messageFallbackRef} growX />
            <ChatActionsChangeEnterButton isReply={isReply} />
          </Row>
        </MarginBox>
        <Ellipsis className={typingLabelCss}>{typingLabel}</Ellipsis>
      </div>
    </ZionForm>
  )
}
