import { useEffect, useReducer, useCallback, useRef } from 'react'
import { getMemoriesArtifact } from '../services/memories/memoriesService'
import {
  getArtifactFromStore,
  CHAT_SCREENING_STATE,
  CHAT_PROCESSING_STATE,
} from '../services/memories/artifactStoreService'
import chatLog, { LOG_LEVEL } from '../global/chatLog'
import { CHAT_ATTACHMENT_SERVICE_TYPE } from '../helpers/chatAttachmentHelper'
import { useChatState } from '../providers/ChatStateProvider'

const timeout = (ms) =>
  new Promise((resolve) => {
    setTimeout(resolve, ms)
  })

export const actionTypes = {
  FETCHING: 'FETCHING',
  FETCHED: 'FETCHED',
  FETCH_ERROR: 'FETCH_ERROR',
}

const MAX_RETRIES = 15

/**
 * Get the exponential back-off retry time useful for polling the artifact API
 * The backend screening for images is estimated to be 5s.
 * We start at 5s and increase the delay exponentially until it reaches up to 60 seconds.
 * Formula => wait_interval * (base * 2^n) +/- (random_interval)
 */
function getWaitTime(retryCount) {
  const SECOND = 1000
  const WAIT_INTERVAL = 5 * SECOND
  const MAX_WAIT_TIME = 60 * SECOND
  const plusOrMinus = Math.random() < 0.5 ? -1 : 1
  const RANDOM_INTERVAL = Number.parseInt(Math.random() * WAIT_INTERVAL, 10) * plusOrMinus
  return Math.min(WAIT_INTERVAL * 2 ** retryCount + RANDOM_INTERVAL, MAX_WAIT_TIME)
}

function canShowArtifact({ pending, artifact }) {
  return (
    (pending && artifact?.processingState === CHAT_PROCESSING_STATE.PROCESSED) ||
    artifact?.screeningState === CHAT_SCREENING_STATE.APPROVED ||
    artifact?.screeningState === CHAT_SCREENING_STATE.RESTRICTED
  )
}

function shouldRetryGetArtifactFromStore({ pending, artifact, retryCount }) {
  return !canShowArtifact({ pending, artifact }) && retryCount < MAX_RETRIES
}

export const useChatAttachment = ({ pending, id, serviceType }) => {
  const { user } = useChatState() || {}
  const isCurrentRef = useRef()

  const initialState = {
    status: 'fetching',
    error: null,
    memory: null,
  }
  const [s, dispatch] = useReducer((state, action) => {
    switch (action.type) {
      case actionTypes.FETCHING:
        return { ...state, status: 'fetching', memory: null }
      case actionTypes.FETCHED:
        return { ...state, status: 'fetched', memory: action.artifact }
      case actionTypes.FETCH_ERROR:
        return { ...state, status: 'error', error: action.error }
      default:
        return state
    }
  }, initialState)

  const fetchArtifactFromStore = useCallback(
    async (retryCount = 0) => {
      if (!isCurrentRef?.current) return
      dispatch({ type: actionTypes.FETCHING })

      if (id && serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.MEMORY_ARTIFACT) {
        try {
          const artifact = await getMemoriesArtifact(id)
          if (!isCurrentRef?.current) return
          dispatch({ type: actionTypes.FETCHED, artifact })
        } catch (error) {
          chatLog({
            msg: error,
            level: LOG_LEVEL.ERROR,
            component: '[useChatAttachment]',
            user: { id: user?.cisId },
          })
          dispatch({ type: actionTypes.FETCH_ERROR, error })
        }
      } else if (serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.ARTIFACT_STORE) {
        try {
          if (pending || retryCount > 0) {
            await timeout(getWaitTime(retryCount))
          }
          const artifact = await getArtifactFromStore(id)
          if (!isCurrentRef?.current) return
          dispatch({ type: actionTypes.FETCHED, artifact })
          if (shouldRetryGetArtifactFromStore({ pending, artifact, retryCount })) {
            fetchArtifactFromStore(++retryCount)
          }
        } catch (error) {
          chatLog({
            msg: error,
            level: LOG_LEVEL.ERROR,
            component: '[useChatAttachment]',
            user: { id: user?.cisId },
          })
          dispatch({ type: actionTypes.FETCH_ERROR, error })
        }
      }
    },
    [pending, id, serviceType, user?.cisId]
  )

  useEffect(() => {
    isCurrentRef.current = true
    fetchArtifactFromStore()
    return () => {
      isCurrentRef.current = false
    }
  }, [fetchArtifactFromStore])
  return s
}
