import React, { useRef, useCallback, useEffect } from 'react'
import { IconButton, useStatusOverlay } from '@fs/zion-ui'
import { DocumentPhoto } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { useChatAttachmentsState, useChatAttachmentsDispatch } from '../providers/ChatAttachmentsProvider'
import { uploadFilesFromFileSelectorInput } from '../helpers/chatAttachmentHelper'
import { maxAttachmentsReached } from './ChatShareMemoryButton'

export default function ChatUploadMemoryButton({ isReply }) {
  const { t } = useTranslation()
  const fileInputRef = useRef()
  const showStatusOverlay = useStatusOverlay()
  const { pendingArtifactAttachments } = useChatAttachmentsState()
  const chatAttachmentsDispatch = useChatAttachmentsDispatch()
  const maxReached = maxAttachmentsReached(pendingArtifactAttachments)

  const fileSelectorOnChange = useCallback(() => {
    uploadFilesFromFileSelectorInput({
      fileInputRef,
      showStatusOverlay,
      pendingArtifactAttachments,
      chatAttachmentsDispatch,
      isReply,
    })
  }, [fileInputRef, showStatusOverlay, pendingArtifactAttachments, chatAttachmentsDispatch, isReply])

  const handleImagePaste = useCallback(
    (event) => {
      const text = event.clipboardData.getData('text')
      if (text) {
        // If there's text, allow the default behavior (i.e., pasting text)
        return // Early return to bypass file handling
      }
      const files = event.clipboardData?.files
      if (files?.length > 0) {
        event.preventDefault()
        if (maxReached) {
          showStatusOverlay({ message: t('chat.share-memory.limit', 'Max Uploads Reached'), type: 'warning' })
        } else {
          uploadFilesFromFileSelectorInput({
            fileInputRef: { current: { files } },
            showStatusOverlay,
            pendingArtifactAttachments,
            chatAttachmentsDispatch,
            isReply,
          })
        }
      }
    },
    [chatAttachmentsDispatch, maxReached, pendingArtifactAttachments, showStatusOverlay, t, isReply]
  )

  useEffect(() => {
    document.addEventListener('paste', handleImagePaste)
    return () => document.removeEventListener('paste', handleImagePaste)
  }, [handleImagePaste])

  const title = maxReached
    ? t('chat.share-memory.limit', 'Max Uploads Reached')
    : t('chat.upload-memory.action', 'Upload Image to Chat')

  const buttonClick = () => fileInputRef.current.click()

  return (
    <>
      <IconButton
        title={title}
        data-testid="add-document"
        Icon={DocumentPhoto}
        description={t(
          'chat.upload-file-types.message',
          'We support .jpg, .png, and .gif, up to 5MB. Reviewing can take up to 15 minutes.'
        )}
        disabled={maxAttachmentsReached(pendingArtifactAttachments)}
        onClick={buttonClick}
      />
      <input
        data-testid="file-selector-input"
        style={{ display: 'none' }}
        name="file-selector"
        type="file"
        accept=".jpeg, .jpg, .gif, .png"
        ref={fileInputRef}
        onChange={fileSelectorOnChange}
        hidden
        aria-hidden
      />
    </>
  )
}
