import { Bleedable, Button } from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'
import { getChannelName } from '../helpers/stream/streamChatHelper'
import { useChatState } from '../providers/ChatStateProvider'
import { useChannelActions } from '../hooks/channelHooks'

export default function ChatContentMuted({ channel }) {
  const [t] = useTranslation()
  const { client, isEmbedded } = useChatState()
  const { displayUnmuteChannel, unmuteChannel } = useChannelActions({ channel })

  if (isEmbedded) return null

  const name = channel ? getChannelName({ channel, excludeUserId: client?.userID }) : 'Chat'
  const bodyMessage = t('chat.name-is-muted.message', `{name} is muted.`, { name })

  return (
    <Bleedable sides={22} top={8} bottom={0}>
      {bodyMessage}{' '}
      {displayUnmuteChannel && (
        <Button data-testid={`chat-content-blocked-${channel?.type}`} onClick={unmuteChannel}>
          {t('chat.unmute-chat.action', 'Unmute Chat')}
        </Button>
      )}
    </Bleedable>
  )
}
