import { getSessionId } from '@fs/zion-session'

const getMemoryType = (memory) => {
  let type = 'IMAGE'
  switch (memory.category) {
    case 'IMAGE':
      if (memory.contentCategory === 'DOCUMENT') type = 'DOCUMENT'
      break
    case 'AUDIO':
      type = 'AUDIO'
      break
    case 'TEXT':
      type = 'STORY'
      break
    case 'PDF':
      type = 'PDF'
      break
    default:
      break
  }
  return type
}

const structurePhotoData = (mediaItems, acceptedTypes, excludedMemIds) => {
  const data = []
  const hasItems = Boolean(mediaItems?.length)

  if (hasItems) {
    mediaItems.forEach((photo) => {
      const type = getMemoryType(photo)
      if (
        acceptedTypes?.includes(type.toLocaleLowerCase()) &&
        photo.artifactDisplayState !== 'RESTRICTED' &&
        !excludedMemIds?.includes(photo.id)
      ) {
        data.push({
          ...photo,
          id: photo.id,
          src: `${photo.thumbMobileUrl || photo.thumbUrl}&session=${getSessionId()}`,
          alt: photo.title,
        })
      }
    })
  }

  return data
}

const structureAlbumData = (mediaItems) => {
  const hasItems = Boolean(mediaItems?.length)

  return hasItems
    ? mediaItems.map(({ id, name }) => ({
        id,
        name,
      }))
    : []
}

export default { getMemoryType, structureAlbumData, structurePhotoData }
