import { useMemo } from 'react'
import { langText } from '@fs/zion-locale'
import streamSupportedLanguages from './streamSupportedLanguages'

const getInclusionList = () => {
  const familySearchSupportedLanguages = [...langText.core, ...langText.additional].flat()
  const inclusionList = {}

  familySearchSupportedLanguages.forEach(({ code, text }) => {
    // We need to filter out Simplified Chinese (zh)
    // https://familysearch.slack.com/archives/C7MN000RG/p1732569764804169
    if (streamSupportedLanguages.includes(code)) inclusionList[code] = text
  })

  return inclusionList
}

export default function useSupportedLanguageName(userLanguageCode) {
  // inclusionList will always be the same, so we can memoize it
  const inclusionList = useMemo(() => getInclusionList(), [])

  return inclusionList[userLanguageCode]
}
