import React from 'react'
import { Ellipsis, H1, H2, H3, H4, H5, H6, Paragraph, Separator } from '@fs/zion-ui'
import useMemoryCard from '../useMemoryCard'

const TextTag = ({ isHeading, children }) => {
  return isHeading ? children : <strong>{children}</strong>
}

export default function Title({ memory, dense, titleAs }) {
  const { isTextStoryMemory } = useMemoryCard(memory)

  const normalizedTitleAs = titleAs?.toLowerCase()
  let isHeading
  let TitleTag

  switch (normalizedTitleAs) {
    case 'h1':
      TitleTag = H1
      isHeading = true
      break
    case 'h2':
      TitleTag = H2
      isHeading = true
      break
    case 'h3':
      TitleTag = H3
      isHeading = true
      break
    case 'h4':
      TitleTag = H4
      isHeading = true
      break
    case 'h5':
      TitleTag = H5
      isHeading = true
      break
    case 'h6':
      TitleTag = H6
      isHeading = true
      break
    default:
      TitleTag = Paragraph
      isHeading = false
  }

  const titleProps = isHeading ? { size: dense ? 'H6' : 'H5' } : { size: dense ? 'sm' : 'md', dense: true }

  return (
    <>
      {!isTextStoryMemory && <Separator size="nano" />}
      <Ellipsis lineClamp={2} noTooltip>
        <TitleTag {...titleProps}>
          <TextTag isHeading={isHeading}>{memory.title}</TextTag>
        </TitleTag>
      </Ellipsis>
    </>
  )
}
