import React from 'react'
import { css } from '@linaria/core'
import { boolAttr } from '@fs/zion-frontend-friends'
import { Arrow } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { ActionChip, colors } from '@fs/zion-ui'

const shadowCss = css`
  height: 100%;
  width: 100%;
  position: absolute;
  top: 0;
  bottom: 0;
  left: 0;
  pointer-events: none;
  &::before,
  &::after {
    content: '';
    position: absolute;
    z-index: 2; /* needed so that if there is a table in the dialog the shadow will be above the table header */
    height: 11px;
    width: 100%;
    box-shadow: inset 0 11px 10px -10px rgba(0, 0, 0, 0.2);
    top: 0;
    opacity: 0;
    transition: opacity 0.3s;
  }
  &::after {
    top: unset;
    bottom: 0;
    box-shadow: inset 0px -11px 10px -10px rgba(0, 0, 0, 0.2);
  }
  &[scroll-top]::before {
    opacity: 1;
  }
  &[scroll-bottom]::after {
    opacity: 1;
  }
`
const containerCss = css`
  display: flex;
  flex-grow: 1;
  flex-shrink: 1;
  position: relative;
  overflow: hidden;
`

const contentCss = css`
  display: flex;
  flex-direction: column;
  flex: 1;
  -ms-overflow-style: -ms-autohiding-scrollbar; /* Makes the scrollbar auto-hide/show on edge */
  /* better mobile scrolling */
  overflow-scrolling: touch;
  -webkit-overflow-scrolling: touch;
  overflow-y: auto;
  overflow-x: hidden;
  min-height: 0;
  [data-viewport-type='element'] {
    left: 50%;
    transform: translate(-50%, 0%);
    max-width: 550px;
    padding-inline: 12px;
  }
`

const unreadChipCss = css`
  position: absolute;
  background: ${colors.gray00};
  height: 32px;
  border-radius: 16px;
  left: 50%;
  transform: translateX(-50%);
`

function UpArrow() {
  return <Arrow direction="up" />
}
function DownArrow() {
  return <Arrow direction="down" />
}

export default function VirtuosoScrollShadow({
  children,
  scrolledToBottom,
  scrolledToTop,
  moreUnreadsUp,
  moreUnreadsDown,
  onScrollDownToUnread,
  onScrollUpToUnread,
  scrollShadowRef,
  showLatest,
  onGoLatest,
}) {
  const topArrow = UpArrow
  const bottomArrow = DownArrow
  const [t] = useTranslation()
  const moreLabel = t('chat.more-unreads.label', 'More unreads')
  const latestLabel = t('chat.go-latest.label', 'Go to latest')

  return (
    <div className={containerCss} ref={scrollShadowRef}>
      <div className={contentCss}>{children}</div>
      <div className={shadowCss} scroll-top={boolAttr(!scrolledToTop)} scroll-bottom={boolAttr(!scrolledToBottom)} />
      {moreUnreadsUp && (
        <div className={unreadChipCss} style={{ top: 12 }}>
          <ActionChip selected Icon={topArrow} label={moreLabel} onClick={onScrollUpToUnread} />
        </div>
      )}
      {moreUnreadsDown && (
        <div className={unreadChipCss} style={{ bottom: 12 }}>
          <ActionChip selected Icon={bottomArrow} label={moreLabel} onClick={onScrollDownToUnread} />
        </div>
      )}
      {!moreUnreadsDown && showLatest && (
        <div className={unreadChipCss} style={{ bottom: 12 }}>
          <ActionChip selected Icon={bottomArrow} label={latestLabel} onClick={onGoLatest} aria-hidden />
        </div>
      )}
    </div>
  )
}
