import { Bleedable, Paragraph, InlineButton } from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'
import useChatBlockUser from '../hooks/useChatBlockUser'

export default function ChatMessageBlocked({ user }) {
  const [t] = useTranslation()
  const { unblockUser } = useChatBlockUser({ targetUserId: user?.id, targetUserName: user?.name })

  return (
    <Bleedable sides={32} top={8}>
      <Paragraph size="xs">{user?.name}</Paragraph>
      {t('chat.use-blocked.message', 'This user is blocked.')}{' '}
      <InlineButton data-testid={`chat-content-blocked-${user?.id}`} onClick={unblockUser}>
        {t('chat.unblock.action', 'Unblock')}
      </InlineButton>
    </Bleedable>
  )
}
