import React, { useMemo } from 'react'
import { css } from '@linaria/core'
import PropTypes from 'prop-types'
import { Card, SelectableCard, colors } from '@fs/zion-ui'
import { useDraggable } from '@dnd-kit/core'
import useMemoryCard from './useMemoryCard'
import { Media, Title, Description, Footer, Status, StoryGradient, Details } from './components'

const cardContainerCss = css`
  display: flex;
  flex-direction: column;
  // Match the height of cards in the same row of the FlowGrid
  flex: 1 1;
`

export default function MemoryCard({
  memory,
  to,
  onClick,
  onContextMenu,
  selectable = false,
  checked = false,
  draggable = false,
  dragIndex = null,
  reorder = false,
  nativeDragApi = undefined,
  showDate, // DEPRECATED: Use showDatePlace instead. Leaving for backwards compatibility, but will be removed in a future release.
  showDatePlace,
  tombstone = undefined,
  missing = false,
  dense = false,
  disabled = false,
  linkName,
  a11y = {},
}) {
  const { ariaLabel, getCardTo, isPhotoStoryMemory, isPrivateMemory, isTextStoryMemory } = useMemoryCard(
    memory,
    missing
  )
  const { commentCount, description, id, title } = memory
  const { listeners, setNodeRef: draggableRef } = useDraggable({ id, disabled })
  const draggableProps = draggable ? { ref: draggableRef, ...listeners } : null
  const reorderProps = reorder && !draggable ? { ...nativeDragApi, draggable: true, 'drag-index': dragIndex } : null
  const { ariaLabel: providedAriaLabel, titleAs } = a11y

  const CardTag = useMemo(() => (selectable ? SelectableCard : Card), [selectable])

  const displayDetail = useMemo(() => {
    if (showDatePlace) return showDatePlace
    if (showDate) return 'date'
    return null
  }, [showDate, showDatePlace])

  const showDescription = useMemo(
    () => description && (dense ? isTextStoryMemory : isTextStoryMemory || isPhotoStoryMemory),
    [dense, description, isPhotoStoryMemory, isTextStoryMemory]
  )

  const showFooter = useMemo(
    () => (commentCount > 0 || isPrivateMemory || tombstone > 0) && !dense,
    [commentCount, dense, isPrivateMemory, tombstone]
  )

  const noDetails = useMemo(
    () => !title && !showDescription && !displayDetail && !showFooter,
    [showDescription, showFooter, title, displayDetail]
  )

  const disableCard = useMemo(
    () => (tombstone !== undefined && !selectable) || disabled,
    [disabled, selectable, tombstone]
  )

  return (
    <div className={cardContainerCss} {...draggableProps} {...reorderProps}>
      <CardTag
        backgroundColor={isTextStoryMemory ? colors.gray02 : colors.gray00}
        to={getCardTo(to, tombstone, selectable, disabled, reorder)}
        onClick={reorder ? null : onClick}
        onContextMenu={onContextMenu ? (e) => onContextMenu(e, id) : undefined}
        checked={checked}
        linkName={linkName}
        minHeight={dense ? 170 : 300}
        margins={dense ? 'nano' : 'xs'}
        disabled={disableCard}
        aria-label={providedAriaLabel || ariaLabel}
      >
        <Status memory={memory} missing={missing} dense={dense} />
        {!isTextStoryMemory && <Media memory={memory} noDetails={noDetails} dense={dense} growY />}
        {title && <Title memory={memory} dense={dense} titleAs={titleAs} />}
        {displayDetail && <Details memory={memory} showDatePlace={displayDetail} dense={dense} />}
        {showDescription && <Description memory={memory} dense={dense} />}
        {showFooter && <Footer memory={memory} tombstone={tombstone} />}
        {isTextStoryMemory && <StoryGradient />}
      </CardTag>
    </div>
  )
}

MemoryCard.propTypes = {
  /** Memory object to display. This will most likely come from a service. */
  memory: PropTypes.shape({
    id: PropTypes.number.isRequired,
    artifactDisplayState: PropTypes.string,
    associatedArtifacts: PropTypes.shape({
      artifact: PropTypes.arrayOf(
        PropTypes.shape({
          id: PropTypes.number,
        })
      ),
    }),
    category: PropTypes.string.isRequired,
    commentCount: PropTypes.number.isRequired,
    description: PropTypes.string,
    title: PropTypes.string,
    thumbMobileUrl: PropTypes.string,
    thumbUrl: PropTypes.string,
    width: PropTypes.number,
  }).isRequired,

  /** Url to use the card like a link. Overrides onClick. */
  to: PropTypes.string,

  /** Event when the card is clicked. */
  onClick: PropTypes.func,

  /** Show the selectable state of the card. */
  selectable: PropTypes.bool,

  /** Show card as checked when selectable. */
  checked: PropTypes.bool,

  /** When true, enables dnd-kit dragging functionality. */
  draggable: PropTypes.bool,

  /** Use `showDatePlace` instead. When true, displays the date below the title. Maintained for backwards compatibility. */
  showDate: PropTypes.bool,

  /** Controls which detail to display below the title. Pass `"date"` to show date of memory, or `"place"` to show place. */
  showDatePlace: PropTypes.oneOf(['date', 'place']),

  /** Days until a recently deleted memory is permanently deleted. Replaces comment count and disables `to` and `onClick`. */
  tombstone: PropTypes.number,

  /** Shrink card height, fonts, margins, and details for use in compact spaces. */
  dense: PropTypes.bool,

  /** Disables `to`, `onClick`, and dragging interactions if you only want to display the card. */
  disabled: PropTypes.bool,

  /** A11y affordances. Providing an `ariaLabel` will override our default ariaLabels we provide for you. Providing `titleAs` such as `"H3"` will change the semantic heading level of the card's title. */
  a11y: PropTypes.shape({
    ariaLabel: PropTypes.string,
    titleAs: PropTypes.string,
  }),
}
