import React from 'react'
import { css } from '@linaria/core'
import { boolAttr, sanitizeProps } from '@fs/zion-frontend-friends'
import { ContentCheck } from '@fs/zion-icon'
import { colors } from '../theme'
import BaseCard from './BaseCard'
import type { CardProps } from './Card'

const selectableCardCss = css`
  user-select: none;
  cursor: pointer;

  &::after {
    content: '';
    position: absolute;
    bottom: 0;
    inset-inline-start: 0;
    height: 100%;
    width: 100%;
    pointer-events: none;
    border-radius: inherit;
    z-index: 1;
    border: 2px solid rgba(32, 171, 215, 0);
    background: rgba(32, 171, 215, 0);
    transition:
      border-color 0.2s,
      background 0.2s;
  }

  &:focus-visible {
    outline: 4px solid ${colors.blue60};
    outline-offset: -1px;
  }

  &[is-checked]::after,
  &:hover::after {
    // TODO: when we get transparent colors, use the transparent colors.help.accent version
    background: rgba(32, 171, 215, 0.2);
  }

  &:not(:focus-visible):hover::after {
    border-color: ${colors.blue30};
  }
`

const checkMarkCss = css`
  position: absolute;
  top: 12px;
  inset-inline-end: 12px;
  height: 24px;
  width: 24px;
  border-radius: 24px;
  padding: 1px;
  z-index: 2;
  color: ${colors.gray40};
  background-color: ${colors.gray00};
  border: 1px solid ${colors.gray40};
  opacity: 0.8;
  display: flex;
  justify-content: center;
  align-items: center;

  &[is-checked] {
    color: ${colors.gray00};
    background-color: ${colors.blue50};
    border: 1px solid ${colors.gray00};
    opacity: 1;
  }
`

type SelectableCardProps = CardProps & {
  /** Puts the card is a `checked` state if `true`. */
  checked?: boolean

  /** Function that gets called on user interactions. Can wither be a React setState function or useSelection function if an `id` prop is provided. */
  setChecked?: (prevChecked?: unknown) => unknown
}

// eslint-disable-next-line @typescript-eslint/no-empty-function
function noOp(): void {}

const SelectableCard = ({
  checked,
  setChecked = noOp,
  onClick = noOp,
  children,
  ...props
}: SelectableCardProps): JSX.Element => {
  return (
    <BaseCard
      {...sanitizeProps(props)}
      className={selectableCardCss}
      onClickCapture={(e) => {
        // @ts-expect-error -- TODO fix strict issue: This was grandfathered from before we adopted strict mode in typescript.
        e.preventDefault()
        // @ts-expect-error -- TODO fix strict issue: This was grandfathered from before we adopted strict mode in typescript.
        e.stopPropagation()
        // @ts-expect-error -- TODO fix strict issue: This was grandfathered from before we adopted strict mode in typescript.
        onClick(e)
        setChecked((prevChecked) => !prevChecked)
      }}
      // allows toggling of checked state with the enter/return key
      // when navigating with the keyboard
      onKeyDown={(e) => {
        // @ts-expect-error -- TODO fix strict issue: This was grandfathered from before we adopted strict mode in typescript.
        if (e.key === 'Enter' || e.key === ' ') {
          // @ts-expect-error -- TODO fix strict issue: This was grandfathered from before we adopted strict mode in typescript.
          const target = e.target as HTMLElement
          target.click()
        }
      }}
      role="checkbox"
      // required to make the card accessible with the TAB key
      tabIndex={0}
      is-checked={boolAttr(checked)}
      aria-checked={checked ? 'true' : 'false'}
      overLayer={
        <div className={checkMarkCss} is-checked={boolAttr(checked)}>
          <ContentCheck size="xs" />
        </div>
      }
    >
      {children}
    </BaseCard>
  )
}

export default SelectableCard
