import { i18n } from '@fs/zion-locale'
import zionDebug from '@fs/zion-debug'
import axios from '@fs/zion-axios'

const MEMORIES_SERVICE_BASE = '/service/memories'

const debug = zionDebug('zion:chat:memories')

export async function getMemoriesArtifact(id) {
  if (!id) return null
  const url = `${MEMORIES_SERVICE_BASE}/presentation/artifacts/${id}`
  const params = {
    _: new Date().getTime(),
  }
  try {
    const { data } = await axios.get(url, { params })
    return data || null
  } catch (err) {
    debug(`[CHAT][MEMORIES] ${err}`)
    throw new Error(i18n.t('chat.error-memory-load.message', 'Unable to load memory'))
  }
}

export async function uploadToMemories(file) {
  const url = `${MEMORIES_SERVICE_BASE}/manager/artifacts/files`
  const body = file
  const headers = {
    'Content-Type': file.type,
  }
  const params = {
    filename: i18n.t('chat.download-image-filename.label', 'FamilySearch-Chat-image'),
  }
  const { data } = await axios.post(url, body, { params, headers })
  return data || null
}
