import React, { memo, useState, useCallback } from 'react'
import { css } from '@linaria/core'
import { boolAttr, sanitizeProps } from '@fs/zion-frontend-friends'
import PropTypes from 'prop-types'
import { DocumentFolder, DocumentFolderOpen, ArrowCaret } from '@fs/zion-icon'
import { useContainerWidth, List, ListItem, colors, H5 } from '@fs/zion-ui'
import { ShadowScroller } from '@fs/zion-ui/quarks-authorized-use-only'

const navCss = css`
  display: flex;
  flex-direction: column;
  width: 220px;
  min-width: 220px;
  background: ${colors.gray00};
  z-index: 1;

  &[is-mobile] {
    width: 100%;
    height: 100%;
    transition: all 400ms cubic-bezier(0.25, 0.75, 0.5, 1);
    position: absolute;
    transform: translateX(0%);

    &[collapsed] {
      transform: translateX(-100%);
    }
  }

  & * {
    user-select: none;
  }
`
const headingCss = css`
  margin: 12px 0 12px 16px;
`

const StatefulListItem = memo(({ folder, folderSelectionCallback, selected, setSelected }) => {
  const atWidth = useContainerWidth()
  const extraProps = atWidth({
    default: {
      endElement: <ListItem.Icon Icon={ArrowCaret} color={colors.gray40} />,
    },
    md: {},
  })

  const handleItemClick = useCallback(() => {
    setSelected(folder.id || folder.name)
    folderSelectionCallback(folder)
  }, [folderSelectionCallback, folder, setSelected])

  const LeftIcon = folder.leftIcon ?? DocumentFolder
  const DefaultActive = folder.leftIcon ? LeftIcon : DocumentFolderOpen
  const ActiveIcon = folder.leftIconActive ?? DefaultActive

  return (
    <ListItem
      key={`xs${folder.id || folder.name}`}
      primaryText={`${folder.name}`}
      startElement={<ListItem.Icon Icon={selected ? ActiveIcon : LeftIcon} />}
      onClick={handleItemClick}
      selected={selected}
      {...extraProps}
    />
  )
})

// export default function SideNav({
const SideNav = memo(function SideNav({
  children,
  dialogNavStructure = {},
  showMainNavHeader = true,
  folderSelectionCallback,
  /* HIDDEN PROPS */
  collapsedNav,
  isMobile,
  ...props
}) {
  const [selected, setSelected] = useState()
  const [navLabel, setNavLabel] = useState()
  return (
    <aside
      {...sanitizeProps(props)}
      className={navCss}
      is-mobile={isMobile ? '' : undefined}
      collapsed={boolAttr(collapsedNav)}
    >
      {Object.keys(dialogNavStructure)?.length > 0 && (
        <ShadowScroller>
          <nav aria-labelledby={navLabel} style={{ padding: '16px' }}>
            {Object.entries(dialogNavStructure).map(([key, value], index) => {
              if (!navLabel && index === 0 && showMainNavHeader) setNavLabel(key)
              return (
                <div key={key}>
                  {((index === 0 && showMainNavHeader) || index > 0) && (
                    <div className={headingCss}>
                      <H5 size={index === 0 ? 'H5' : 'H6'} id={key}>
                        {key}
                      </H5>
                    </div>
                  )}
                  <List aria-labelledby={index === 0 && navLabel ? undefined : key}>
                    {value.map((folder) => (
                      <StatefulListItem
                        key={`${folder.id || folder.name}`}
                        folder={folder}
                        folderSelectionCallback={folderSelectionCallback}
                        setSelected={setSelected}
                        selected={selected === (folder.id || folder.name)}
                      />
                    ))}
                  </List>
                </div>
              )
            })}
          </nav>
        </ShadowScroller>
      )}
    </aside>
  )
})

export default SideNav

SideNav.propTypes = {
  /** An object used to represent the navigational folder structure of the import source. The key represents the header and the value contains an array of objects, shown as folders. The nested object should include a 'name' prop. This object will be returned when the folder button is clicked. */
  dialogNavStructure: PropTypes.objectOf(
    PropTypes.arrayOf(
      PropTypes.shape({
        name: PropTypes.string,
      })
    ).isRequired
  ),
  /** Items displayed in the Picker Dialog that the user can select. */
  showMainNavHeader: PropTypes.bool,
  /** Items displayed in the Picker Dialog that the user can select. */
  folderSelectionCallback: PropTypes.func,

  // HIDDEN PROPS
  /** Items displayed in the Picker Dialog that the user can select. */
  isMobile: PropTypes.bool,
  /** If true mobile attr is added to element for css */
  // fullscreen: PropTypes.bool,
  /** label id used for aria-labelledby */
  // describedById: PropTypes.string,
}
