import { useEffect, useCallback, useMemo } from 'react'
import debounce from 'lodash.debounce'
import { isPubliclyViewableChannel } from '../services/fsChat/fsChatService'

/**
 * Hook to manage loading, saving, and deleting chat message drafts.
 */
export function useChatDraft({ channel, thread, isReply, pid, getFormValues, resetForm, log, fieldName }) {
  const composer = isReply ? thread?.messageComposer : channel?.messageComposer

  useEffect(() => {
    if (!channel || isPubliclyViewableChannel(channel)) return

    const draftText = composer?.textComposer?.text
    resetForm({ message: draftText ?? '' })
  }, [channel, composer, resetForm])

  // callback to delete draft after sending the message
  const deleteDraft = useCallback(() => {
    if (!channel) return
    if (isPubliclyViewableChannel(channel)) {
      resetForm({ message: '' })
      return
    }
    try {
      composer?.textComposer?.setText('')
      const opts = isReply && pid ? { parent_id: pid } : {}
      channel.deleteDraft(opts)
    } catch (err) {
      log({ msg: `Error deleting draft: ${err}`, level: 'error' })
    } finally {
      resetForm({ message: '' })
    }
  }, [composer, channel, isReply, pid, log, resetForm])

  // handler to save the draft when the message changes
  const saveDraft = useMemo(
    () =>
      debounce(async () => {
        if (!channel || isPubliclyViewableChannel(channel)) return
        const text = getFormValues(fieldName).trim()
        try {
          const opts = { text }
          if (isReply && pid) opts.parent_id = pid
          composer?.textComposer?.setText(text)
          await channel.createDraft(opts)
        } catch (err) {
          log({ msg: `Error saving draft: ${err}`, level: 'error' })
        }
      }, 1000),
    [channel, composer, isReply, pid, getFormValues, log, fieldName]
  )

  // cleanup debounce on unmount
  useEffect(() => {
    return () => {
      saveDraft.flush()
      saveDraft.cancel()
    }
  }, [saveDraft])

  return { deleteDraft, saveDraft }
}
