import { SocialFaceHappy } from '@fs/zion-icon'
import { IconButton, QuickGlanceOverlay, useOverlay } from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'
import ChatEmojiPicker from './ChatEmojiPicker'

export default function ChatEmojiButton({ textFieldRef }) {
  const overlay = useOverlay({ focusBackRef: textFieldRef })
  const [t] = useTranslation()
  const handleEmojiClick = (emoji) => {
    const field = textFieldRef.current
    field.setRangeText(emoji, field.selectionStart, field.selectionEnd, 'end')
    // Firing an input event lets React know we changed the value
    field.dispatchEvent(new Event('input', { bubbles: true }))
    overlay.close()
    field.focus()
  }

  return (
    <>
      <IconButton
        data-testid="insert-emoji"
        onClick={overlay.handleClick}
        title={t('chat.insert-emoji.action', 'Emoji')}
        Icon={SocialFaceHappy}
      />
      <QuickGlanceOverlay {...overlay} placement={['top', 'end', 'bottom', 'start']}>
        <ChatEmojiPicker onEmojiClick={handleEmojiClick} />
      </QuickGlanceOverlay>
    </>
  )
}
