import React, { createContext, useMemo, useReducer } from 'react'
import { i18n } from '@fs/zion-locale'
import { MenuHome, DocumentBox, DocumentFolderLove } from '@fs/zion-icon'
import { galleryUtils } from '../utils'

const GallerySelectorContext = createContext()
const GallerySelectorContextApi = createContext()

const gallerySelectorActions = {
  filtered: 'filtered',
  init: 'init',
  isFetching: 'isFetching',
  newSearchVal: 'newSearchVal',
  reset: 'reset',
  updateCurrentPhotos: 'updateCurrentPhotos',
}

const initialState = {
  allowedMediaTypes: ['image', 'document', 'audio', 'story', 'pdf'],
  currentPhotos: [],
  dialogNavFolders: { '': [] },
  displayedPhotos: [],
  isFetching: false,
  memoryCollections: { myMemories: [], archive: [], bookmarked: [] },
  searchVal: '',
}

const memoryCollectionKeys = {
  bookmarkedMemories: 'bookmarkedMemories',
  myArchive: 'myArchive',
  myMemories: 'myMemories',
}

const reducer = (state, action) => {
  const bookmarksLabel = i18n.t('picker-dialog.selector.nav.gallery.bookmarks', 'Bookmarks')
  const albumsLabel = i18n.t('picker-dialog.selector.nav.gallery.albums', 'Albums')
  const myMemoriesLabel = i18n.t('picker-dialog.selector.nav.gallery.my-memories', 'My Memories')
  const myArchiveLabel = i18n.t('picker-dialog.selector.nav.gallery.my-archive', 'My Archive')
  const memoriesLabel = i18n.t('picker-dialog.selector.nav.gallery.bookmarked-memories', 'Memories')

  switch (action.type) {
    case gallerySelectorActions.isFetching:
      return { ...state, isFetching: action.isFetching }
    case gallerySelectorActions.init: {
      const { albumsResp, photosResp, bookmarkedAlbumsResp, acceptedTypes, excludedMemIds } = action
      const typeFilter = acceptedTypes.length ? acceptedTypes : state.allowedMediaTypes

      const structuredPhotos = galleryUtils.structurePhotoData(photosResp?.data.artifact, typeFilter, excludedMemIds)
      const structuredAlbums = galleryUtils.structureAlbumData(albumsResp?.data.album)
      const structuredBookmarkedAlbums = galleryUtils.structureAlbumData(bookmarkedAlbumsResp?.data.album)

      const albumKeys = [...structuredAlbums, ...structuredBookmarkedAlbums]?.reduce(
        (albums, album) => ({ ...albums, [`${album?.id}`]: [] }),
        {}
      )

      return {
        ...state,
        allowedMediaTypes: typeFilter,
        currentPhotos: structuredPhotos,
        displayedPhotos: structuredPhotos,
        memoryCollections: {
          ...albumKeys,
          [`${memoryCollectionKeys.bookmarkedMemories}`]: [],
          [`${memoryCollectionKeys.myArchive}`]: [],
          [`${memoryCollectionKeys.myMemories}`]: structuredPhotos,
        },
        dialogNavFolders: {
          systemAlbumsWithoutHeading: [
            {
              name: myMemoriesLabel,
              id: memoryCollectionKeys.myMemories,
              leftIcon: MenuHome,
            },
            {
              name: myArchiveLabel,
              id: memoryCollectionKeys.myArchive,
              leftIcon: DocumentBox,
            },
          ],
          [bookmarksLabel]: [
            {
              name: memoriesLabel,
              id: memoryCollectionKeys.bookmarkedMemories,
              leftIcon: DocumentFolderLove,
            },
            ...structuredBookmarkedAlbums,
          ],
          [albumsLabel]: structuredAlbums,
        },
      }
    }
    case gallerySelectorActions.newSearchVal:
      return {
        ...state,
        searchVal: action.newSearchVal,
      }
    case gallerySelectorActions.filtered:
      return {
        ...state,
        displayedPhotos: action.filtered,
      }
    case gallerySelectorActions.reset:
      return initialState
    case gallerySelectorActions.updateCurrentPhotos:
      return {
        ...state,
        currentPhotos: action.currentPhotos,
        displayedPhotos: action.currentPhotos,
        memoryCollections: { ...state.memoryCollections, [action.collectionKey]: action.currentPhotos },
      }
    default:
      return state
  }
}

export default function GallerySelectorProvider({ children }) {
  const [state, dispatch] = useReducer(reducer, initialState)

  const api = useMemo(
    () => ({
      init: ({ albumsResp, bookmarkedAlbumsResp, photosResp, acceptedTypes, excludedMemIds }) =>
        dispatch({
          type: gallerySelectorActions.init,
          albumsResp,
          bookmarkedAlbumsResp,
          photosResp,
          acceptedTypes,
          excludedMemIds,
        }),
      reset: () => dispatch({ type: gallerySelectorActions.reset }),
      setFiltered: (filtered) => dispatch({ type: gallerySelectorActions.filtered, filtered }),
      setIsFetching: (isFetching) => dispatch({ type: gallerySelectorActions.isFetching, isFetching }),
      setSearchValue: (newSearchVal) => dispatch({ type: gallerySelectorActions.newSearchVal, newSearchVal }),
      updateCurrentPhotos: (currentPhotos, collectionKey) =>
        dispatch({ type: gallerySelectorActions.updateCurrentPhotos, collectionKey, currentPhotos }),
    }),
    []
  )

  const {
    allowedMediaTypes,
    currentPhotos,
    dialogNavFolders,
    displayedPhotos,
    isFetching,
    memoryCollections,
    searchVal,
  } = state

  const data = useMemo(
    () => ({
      allowedMediaTypes,
      currentPhotos,
      dialogNavFolders,
      displayedPhotos,
      isFetching,
      memoryCollections,
      searchVal,
    }),
    [allowedMediaTypes, currentPhotos, dialogNavFolders, displayedPhotos, isFetching, memoryCollections, searchVal]
  )

  return (
    <GallerySelectorContext.Provider value={data}>
      <GallerySelectorContextApi.Provider value={api}>{children}</GallerySelectorContextApi.Provider>
    </GallerySelectorContext.Provider>
  )
}

export { GallerySelectorContext, GallerySelectorContextApi, GallerySelectorProvider, memoryCollectionKeys }
