import { i18n } from '@fs/zion-locale'
import { getChannelMembers } from './stream/streamChatHelper'
import { CHANNEL_TYPE } from '../services/fsChat/fsChannelEnums'

const AUAMessageDelay = 1000 * 60 * 5 // 5 minutes

export function getHelpeeInfo({ channel, client }) {
  if (channel?.type === CHANNEL_TYPE.FS_SUPPORT) {
    const isHelpee =
      Boolean(channel?.data?.fs_created_by_cis_id) && channel?.data?.fs_created_by_cis_id === client?.user?.fs_cis_id
    const channelOwner = getChannelMembers({ channel }).find((m) => {
      return m?.user?.fs_cis_id === channel?.data?.fs_created_by_cis_id
    })
    const helpeeName = channelOwner?.user?.name || i18n.t('chat.unknown-name.label', 'Unknown Name')
    return { isHelpee, helpeeName }
  }
  return { isHelpee: false, helpeeName: undefined }
}

export function lastMessageWithinAUADelay(messages) {
  const lastMessageUpdate = messages?.length && messages[messages.length - 1].updated_at
  return Boolean(lastMessageUpdate) && Date.now() - new Date(lastMessageUpdate) >= AUAMessageDelay
}
