import { ContactOverlay } from '@fs/zion-contact-overlay'
import { ActionChip, Separator, useOverlay } from '@fs/zion-ui'
import React from 'react'
import { getAvatarPropsForStreamUser } from '../chat-avatar/chatAvatar'
import { useChatState } from '../providers/ChatStateProvider'
import { cisIdFromChatUserId, getIsSystemUser } from '../helpers/stream/streamChatHelper'

export default function ChatMessageContactChip({ user }) {
  const { client, restrictToManagedGroups } = useChatState()
  const overlay = useOverlay()
  if (!user?.id) return null
  const cisId = cisIdFromChatUserId(user?.id)
  const avatarProps = getAvatarPropsForStreamUser(user)

  return (
    <>
      <ActionChip label={user?.name} avatarProps={avatarProps} onClick={overlay.handleClick} emphasis="high" />
      <Separator size="nano" />
      {!client?.anonymous &&
        !restrictToManagedGroups &&
        !getIsSystemUser(user) &&
        (overlay.isOpen || overlay.transitioning) && (
          <ContactOverlay contact={{ cisId }} overlay={overlay} disableAbout />
        )}
    </>
  )
}
